-- Poems batch 273
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3bb0ce15-a654-482d-b839-dca1807a81a4','哭德和伯氏六首  其一','林景熙','宋','宋诗','song-poetry','','[]','棣隕雙葩洒淚紅，百年已短更匆匆。',32,'全唐诗/poet.song.242000.json','["棣隕雙葩洒淚紅，百年已短更匆匆。", "祇今風雪栖栖影，地老天荒一箇鴻。"]'),
('42e76984-1228-416a-8e20-b83102ba7e35','哭德和伯氏六首  其二','林景熙','宋','宋诗','song-poetry','','[]','風塵何處託清魂，家世梅花水月村。',32,'全唐诗/poet.song.242000.json','["風塵何處託清魂，家世梅花水月村。", "舊篋已無封禪稿，獨憐渴病似文園。"]'),
('f31e637d-2f71-421b-8df8-4bb28795d32b','哭德和伯氏六首  其三','林景熙','宋','宋诗','song-poetry','','[]','空遺破硯孤心苦，只博生綃兩鬢華。',32,'全唐诗/poet.song.242000.json','["空遺破硯孤心苦，只博生綃兩鬢華。", "小婢燈前泣秋雨，竹房不見夜呼茶。"]'),
('7d9619ae-94b4-4af1-8d50-9022236ca583','哭德和伯氏六首  其四','林景熙','宋','宋诗','song-poetry','','[]','溪冷浣花宗武哭，池荒夢草惠連愁。',32,'全唐诗/poet.song.242000.json','["溪冷浣花宗武哭，池荒夢草惠連愁。", "行人猶說春風夜，燈影書聲共水樓。"]'),
('dd1c8112-e306-4800-bc3f-29c618997088','哭德和伯氏六首  其五','林景熙','宋','宋诗','song-poetry','','[]','伯兮癯似松間鶴，季也孤於雲水僧。',32,'全唐诗/poet.song.242000.json','["伯兮癯似松間鶴，季也孤於雲水僧。", "昨夜夢中聞笑語，覺來秋在影堂燈。"]'),
('264f676e-2fef-46ce-9116-e6d72a5e6b49','哭德和伯氏六首  其六','林景熙','宋','宋诗','song-poetry','','[]','草枯霜白泣原鴒，五十三年老弟兄。',32,'全唐诗/poet.song.242000.json','["草枯霜白泣原鴒，五十三年老弟兄。", "風雨對床緣未了，荆花重合在來生。"]'),
('2178c2db-2156-4dc4-9aee-bda4d71650d4','山窗新糊有故朝封事稿閲之有感','林景熙','宋','宋诗','song-poetry','','[]','偶伴孤雲宿嶺東，四山欲雪地爐紅。',32,'全唐诗/poet.song.242000.json','["偶伴孤雲宿嶺東，四山欲雪地爐紅。", "何人一紙防秋疏，却與山窗障北風。"]'),
('ba381c6b-57e3-46ac-9dc9-5551a142787f','僧門','林景熙','宋','宋诗','song-poetry','','[]','一閒每笑不如僧，及到僧門閒未能。',32,'全唐诗/poet.song.242000.json','["一閒每笑不如僧，及到僧門閒未能。", "昨夜褐袍風雪裏，隔溪犬吠入林燈。"]'),
('387bb8b7-3229-4f79-bff2-1ebb19209532','雜詠十首酬汪鎮卿  其一','林景熙','宋','宋诗','song-poetry','','[]','踆烏不停飛，歛景下蒙谷。',60,'全唐诗/poet.song.242000.json','["踆烏不停飛，歛景下蒙谷。", "征途險在前，而况車折軸。", "夸父追羲和，欲挽丹砂轂。", "意遠力不任，化作鄧林木。", "漫漫夜何如，長歌飯觳觫。"]'),
('1dec94ad-d900-4a05-b13e-62dbbb9ef145','雜詠十首酬汪鎮卿  其二','林景熙','宋','宋诗','song-poetry','','[]','百感湊孤夜，江樓起呼月。',60,'全唐诗/poet.song.242000.json','["百感湊孤夜，江樓起呼月。", "秋蟲聲轉悲，念此衆芳歇。", "人生非金石，青鬢忽已雪。", "踰淮橘心移，出山泉性汩。", "猗蘭抱孤芳，不受宿莽沒。"]'),
('f1ff8b4f-b53f-47dd-982b-748937dfaf68','雜詠十首酬汪鎮卿  其三','林景熙','宋','宋诗','song-poetry','','[]','老來屏人事，北窗寄高眠。',192,'全唐诗/poet.song.242000.json','["老來屏人事，北窗寄高眠。", "飄颻御風遠，銀闕開九天。", "虎豹不見嗔，豈予有仙緣。", "玉座覆紅雲，香爐霏紫烟。", "黄冠立小兆，冉冉導我前。", "下土蟣虱臣，微衷懷欲宣。", "兵戈幸休息，饑饉方連綿。", "洪惟大生德，寔制水旱權。", "願言回哀眷，與世蘇倒懸。", "皇靈閔臣請，曰其啟豐年。", "再拜謝闕下，回飈墮林泉。", "夜雷聲殷殷，甘澤朝盈田。", "沈思喜且驚，魂交非偶然。", "士抱當世憂，天猶爲之憐。", "况此咎證臻，庸非燮理愆。", "貞觀有房杜，斗米曾三錢。"]'),
('50ecbe7b-0abf-4955-9fb6-cc5be37c8f31','雜詠十首酬汪鎮卿  其四','林景熙','宋','宋诗','song-poetry','','[]','鳳德嗟已衰，宣尼欲浮海。',72,'全唐诗/poet.song.242000.json','["鳳德嗟已衰，宣尼欲浮海。", "頼有載道經，神功補元宰。", "刪詩挽風變，繫易憂世駭。", "春秋筆削嚴，西秦書乃采。", "微義將警周，逆悲大運改。", "悠悠千古心，後死文乃在。"]'),
('c0439616-351f-422a-8d57-de153d62512b','雜詠十首酬汪鎮卿  其五','林景熙','宋','宋诗','song-poetry','','[]','子有憂世心，蒿然見眉睫。',60,'全唐诗/poet.song.242000.json','["子有憂世心，蒿然見眉睫。", "崇交擬昔人，西風寄三疊。", "作詩匪雕鎪，要與六義涉。", "臣甫再拜鵑，高風或可躡。", "肯作蟋蟀鳴，悲凉和秋葉。"]'),
('d0a6c243-c12f-4f19-a755-8a1a78482afe','雜詠十首酬汪鎮卿  其六','林景熙','宋','宋诗','song-poetry','','[]','青蓮不墮劫，金鼎能回枯。',60,'全唐诗/poet.song.242000.json','["青蓮不墮劫，金鼎能回枯。", "吾道寄流水，此外何所須。", "豈不念百年，奄忽歸丘墟。", "生死同晝夜，逆天詎敢居。", "異端紛溺人，微此吾其魚。"]'),
('dacef1c4-8056-4c0b-93a4-d83c7724ccd6','雜詠十首酬汪鎮卿  其七','林景熙','宋','宋诗','song-poetry','','[]','淪惡易如墜，進善難如登。',60,'全唐诗/poet.song.242000.json','["淪惡易如墜，進善難如登。", "危哉方寸地，風雨吹冥冥。", "尺水增丈波，鰍鱔亦爲鯨。", "海桑空變易，天地終清寧。", "感此坐中夕，疏林動秋聲。"]'),
('a3c0f386-fade-44f5-abdb-85823d66ee46','雜詠十首酬汪鎮卿  其八','林景熙','宋','宋诗','song-poetry','','[]','漢日落西崦，孤彗明中州。',60,'全唐诗/poet.song.242000.json','["漢日落西崦，孤彗明中州。", "玄德負英猛，欲挽無萬牛。", "龍鳳一已逝，斯人復安求。", "區區守江左，老此以菟裘。", "大義固不識，卑哉孫仲謀。"]'),
('be801b1d-ef90-4dd9-9ba5-c0cd422d3f67','雜詠十首酬汪鎮卿  其九','林景熙','宋','宋诗','song-poetry','','[]','垂垂大厦顛，一木支無力。',60,'全唐诗/poet.song.242000.json','["垂垂大厦顛，一木支無力。", "精衛悲滄溟，銅駝化荆棘。", "英風傲几砧，濱死猶鐵脊。", "血染沙場秋，寒日亦爲碧。", "惟留吟嘯編，千載光奕奕。"]'),
('7c326e1b-1161-45a4-96d9-92b352f49981','雜詠十首酬汪鎮卿  其一○','林景熙','宋','宋诗','song-poetry','','[]','權臣坐偃月，棄官如飄蓬。',60,'全唐诗/poet.song.242000.json','["權臣坐偃月，棄官如飄蓬。", "及茲顛沛秋，翻然挺孤忠。", "一死未得所，網羅挂秋鴻。", "渡淮已不食，蛻槁夷齊風。", "何人續遷史，表爲節義雄。"]'),
('ab537898-d98a-4b36-bdc3-29fde72365c6','趙奧別業','林景熙','宋','宋诗','song-poetry','','[]','已無湖海夢，漸老足閒情。',48,'全唐诗/poet.song.242000.json','["已無湖海夢，漸老足閒情。", "野杖日尋壑，家書時到城。", "開池納天影，種竹引秋聲。", "亦愛簞瓢樂，年來世味輕。"]'),
('f54d326e-2ce3-4153-ae38-810a98d927a7','草花','林景熙','宋','宋诗','song-poetry','','[]','不入群芳譜，生機屑化工。',48,'全唐诗/poet.song.242000.json','["不入群芳譜，生機屑化工。", "十年多曠土，一種自春風。", "蛙吠殘陽影，螢明細雨叢。", "令人懷洛艷，錦幄照簾櫳。"]'),
('5ef53570-cde1-4e0d-b73d-f2079143aaac','夜意','林景熙','宋','宋诗','song-poetry','','[]','澹然無一事，至樂在書床。',48,'全唐诗/poet.song.242000.json','["澹然無一事，至樂在書床。", "老石棲雲定，疏松過雨香。", "砧清秋巷迥，燈白夜堂凉。", "此意無人會，重城醉夢鄉。"]'),
('05eb97d4-509c-4b21-ab58-11497f5bcd0d','老松舊隠爲曹許山賦','林景熙','宋','宋诗','song-poetry','','[]','七十五松在，當年手植翁。',48,'全唐诗/poet.song.242000.json','["七十五松在，當年手植翁。", "龍髯雲滿壑，鶴唳月當空。", "三品非秦爵，諸郎有晉風。", "夜深清籟發，歸珮玉丁東。"]'),
('243b14fa-da43-4c38-8458-ee7942f39cd7','中和節','林景熙','宋','宋诗','song-poetry','','[]','柳下一瓢酒，湖風散積陰。',48,'全唐诗/poet.song.242000.json','["柳下一瓢酒，湖風散積陰。", "晴舒生物命，春酌化工心。", "鶑語調寒燠，花粧定淺深。", "悠然情性會，宇宙入孤吟。"]'),
('9cb4193e-d1ce-4fae-a85c-38063937258c','天台隠者','林景熙','宋','宋诗','song-poetry','','[]','俗駕不曾到，瘦筇時復携。',48,'全唐诗/poet.song.242000.json','["俗駕不曾到，瘦筇時復携。", "肺肝清澗飲，鬢髮老巖棲。", "野巷猶雞犬，春城自鼓鞞。", "未應人世外，別有武陵溪。"]'),
('39bf2fb7-100a-4654-b58a-bba6a135a323','新昌道上','林景熙','宋','宋诗','song-poetry','','[]','江湖猶是客，歲月已成翁。',48,'全唐诗/poet.song.242000.json','["江湖猶是客，歲月已成翁。", "仙路重雲外，人家落木中。", "山痕經燒黑，土脈入泉紅。", "又得春風信，孤花照驛東。"]'),
('a9129f60-50e2-49e4-b465-35e29b7161d8','寄懷','林景熙','宋','宋诗','song-poetry','','[]','風雨知何夕，干戈寄此身。',48,'全唐诗/poet.song.242000.json','["風雨知何夕，干戈寄此身。", "青燈少年夢，白髮異鄉春。", "水驛逢花使，丹田守谷神。", "行窩隨處樂，聊自得吾真。"]'),
('48c8bd76-f1f5-4dfa-bf05-22fd2009c149','贈吳秀林東歸','林景熙','宋','宋诗','song-poetry','','[]','幾夜高堂夢，不知山水長。',48,'全唐诗/poet.song.242000.json','["幾夜高堂夢，不知山水長。", "西風歸雁蕩，落日過烏傷。", "斷影雲空白，孤心草欲黄。", "終憐負甘旨，淚灑蓼莪章。"]'),
('a7d208fe-69e1-4522-84a8-11e49e67b96e','越中送徐君寅歸閩','林景熙','宋','宋诗','song-poetry','','[]','此地同爲客，當秋獨送君。',48,'全唐诗/poet.song.242000.json','["此地同爲客，當秋獨送君。", "斜陽留薄醉，遠道惜輕分。", "老泪遺陵木，鄉山出海雲。", "天南有回雁，音信倘相聞。"]'),
('b660eecf-1b12-4f37-9607-f6983e312abb','餞盛景則教授','林景熙','宋','宋诗','song-poetry','','[]','空明仙人朝帝所，跨鶴凌虛墮霜羽。',160,'全唐诗/poet.song.242000.json','["空明仙人朝帝所，跨鶴凌虛墮霜羽。", "洞中石髓流不乾，聖泉寫入君肺腑。", "潘江陸海一目盡，自提脩綆汲千古。", "碧芹水冷涵夜燈，丹鳳山空鳴曉鼓。", "有時白戰風騷場，小巫見之縮雙股。", "飯雖不足仁義腴，牆陰老薺羹春苦。", "丈夫出處各有道，天地綱常要撐拄。", "俗吏惟知騁刀筆，腐儒亦或拘訓詁。", "雲霧窗寒森寶書，廣文袖有修月斧。", "離亭酒短秋帆開，雁蕩峰前桂花雨。"]'),
('fb8ce05b-d023-40fe-9ee0-ad43194a94f3','送橫舟真士遊茅山','林景熙','宋','宋诗','song-poetry','','["\u897f\u6e56"]','海鯢吹腥浪千尺，野渡橫舟人不識。',128,'全唐诗/poet.song.242000.json','["海鯢吹腥浪千尺，野渡橫舟人不識。", "春風未暖六經灰，閑抱黄庭煮白石。", "綠章夜徹九虎關，坐使業海生青蓮。", "蟾蜍窟冷手自探，西湖一鶴梅花仙。", "四時茫茫行大塊，君向何山飛羽佩。", "雙袖携雲發天台，孤竹騎龍窮地肺。", "瓣香持謁三茅君，上清祕笈開瓊文。", "十月嬰兒誰抱送，飛出泥丸跨丹鳳。"]'),
('f7fd2001-a586-4b39-a9e9-e745939feff6','讀秦紀','林景熙','宋','宋诗','song-poetry','','[]','琅邪臺上晚雲平，虎視眈眈隘八紘。',64,'全唐诗/poet.song.242000.json','["琅邪臺上晚雲平，虎視眈眈隘八紘。", "萬里不知人半死，三山空覓草長生。", "兆來鬼璧沙丘近，威動神鞭海石驚。", "書外有書焚不盡，一編圯上漢功名。"]'),
('8c0cb422-bcb0-4fb0-bb93-ef33944505f1','項羽里','林景熙','宋','宋诗','song-poetry','','[]','英雄蓋世竟何爲，故里凄凉越水涯。',64,'全唐诗/poet.song.242000.json','["英雄蓋世竟何爲，故里凄凉越水涯。", "百二勢傾爭逐鹿，八千兵散獨乘騅。", "計疏白璧孤臣去，淚落烏江後騎追。", "遺廟荒林人酹酒，至今春草舞虞姬。"]'),
('a4e182fd-404d-4742-bc47-64f4fce3a140','元日即事','林景熙','宋','宋诗','song-poetry','','[]','宿霧沈城海日遲，十年冉冉鏡中絲。',64,'全唐诗/poet.song.242000.json','["宿霧沈城海日遲，十年冉冉鏡中絲。", "江湖舊夢衣冠在，天地春風鼓角知。", "杜曲桑麻歸已晚，尚平婚嫁畢何時。", "野人問我行藏事，自向庭前采柏枝。"]'),
('ef2c6341-28c0-4f4e-8b3a-490f0bcc9e08','燈市感舊','林景熙','宋','宋诗','song-poetry','','[]','舊夢仙山駕海鼇，飛梅如剪柳如繅。',64,'全唐诗/poet.song.242000.json','["舊夢仙山駕海鼇，飛梅如剪柳如繅。", "千門疑是繁星落，九陌不知明月高。", "零亂遺鈿空宿草，昇平疊鼓散春濤。", "寒燈寥落殘書在，獨抱荒愁寄濁醪。"]'),
('45e5c133-6ece-4868-a00d-f762576649de','栝城','林景熙','宋','宋诗','song-poetry','','[]','寒芒曾動少微星，一水溶溶疊嶂橫。',64,'全唐诗/poet.song.242000.json','["寒芒曾動少微星，一水溶溶疊嶂橫。", "落日漁舟吹遠笛，斷烟戍屋带荒城。", "沙鷗欲近如招隠，關樹無多亦厭兵。", "却憶鶑花亭外路，太平簫鼓沸春聲。"]'),
('ede8a405-6dc7-42a8-89e8-1c685701f972','答唐玉潜','林景熙','宋','宋诗','song-poetry','','[]','畎畝孤心老未衰，一籬瘦菊一瓢詩。',64,'全唐诗/poet.song.242000.json','["畎畝孤心老未衰，一籬瘦菊一瓢詩。", "黄埃赤日謾多事，蒼狗白雲能幾時。", "山酒柏香春壽母，桉書芸冷夜呼兒。", "橫琴妙在無弦處，何必知音有子期。"]'),
('2a9f1f7e-ff7c-44ad-98c8-6ad8cfd534e1','陪王監簿宴廣寒游次韻','林景熙','宋','宋诗','song-poetry','','[]','銀橋疑駕海天長，丹粟離離照翠觴。',64,'全唐诗/poet.song.242000.json','["銀橋疑駕海天長，丹粟離離照翠觴。", "影浸山河瓊殿冷，舞深風露羽衣香。", "亦知廣莫元無野，却笑溫柔別有鄉。", "手折一枝驚昨夢，素娥憐老授玄霜。"]'),
('beeb4275-acde-4bf3-a8a5-f11df5aa5044','楊妃菊','林景熙','宋','宋诗','song-poetry','','[]','昭陽舊恨逐風飄，歲晚山中霜露饒。',64,'全唐诗/poet.song.242000.json','["昭陽舊恨逐風飄，歲晚山中霜露饒。", "彭澤歸來空自老，中原舞破爲誰嬌。", "返魂碧海熏初炷，宿酒沈香暈不消。", "亦是前身曾捧硯，品題因得入詩瓢。"]'),
('3028244a-332e-4268-866c-5ca813b5dad1','漁舍觀梅','林景熙','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冷雲漠漠護籬陰，瀟洒苔枝出竹林。',64,'全唐诗/poet.song.242000.json','["冷雲漠漠護籬陰，瀟洒苔枝出竹林。", "影落寒磯和雪釣，香浮老瓦带春斟。", "幾憑水驛傳芳信，祇許沙鷗識素心。", "回首西湖千樹遠，扁舟寂寞夢中尋。"]'),
('e997f357-47f9-443a-a6b9-ed72b553abfc','陶山十詠和鄧牧心 若耶溪','林景熙','宋','宋诗','song-poetry','','[]','晴峰無數蘸清流，窈窕寒生六月秋。',32,'全唐诗/poet.song.242000.json','["晴峰無數蘸清流，窈窕寒生六月秋。", "百鍊不須歐冶劍，沼吳人在采蓮舟。"]'),
('096111b4-3fd4-4109-b762-8b513d720aa8','陶山十詠和鄧牧心 任公子釣石','林景熙','宋','宋诗','song-poetry','','[]','巨犗長竿釣海波，空遺磯石卧荒坡。',32,'全唐诗/poet.song.242000.json','["巨犗長竿釣海波，空遺磯石卧荒坡。", "千年無此垂綸手，多少饑民向浙河。"]'),
('83a9b80c-a4d7-45a8-b8d9-a542443296c2','陶山十詠和鄧牧心 集仙橋','林景熙','宋','宋诗','song-poetry','','[]','流來一水截人寰，虹背秋寒十二闌。',32,'全唐诗/poet.song.242000.json','["流來一水截人寰，虹背秋寒十二闌。", "白鶴飛邊人影絕，天風吹珮玉珊珊。"]'),
('15063390-e0e6-475b-8ef2-d227cb3827e1','陶山十詠和鄧牧心 陶宴嶺','林景熙','宋','宋诗','song-poetry','','[]','笑拂青蘿問隠君，千巖秋色此平分。',32,'全唐诗/poet.song.242000.json','["笑拂青蘿問隠君，千巖秋色此平分。", "當時宴坐無人識，唯有松風共白雲。"]'),
('bc87c06e-2b52-4778-9629-c2643483ffc4','陶山十詠和鄧牧心 石广','林景熙','宋','宋诗','song-poetry','','[]','一室元無斧鑿痕，閑雲四壁守孤猿。',32,'全唐诗/poet.song.242000.json','["一室元無斧鑿痕，閑雲四壁守孤猿。", "空山靜閲古今過，不老乾坤是此門。"]'),
('08ed5d14-2e61-492e-a9d4-eccc28e53422','陶山十詠和鄧牧心 石船','林景熙','宋','宋诗','song-poetry','','[]','玉笥孤帆喚不來，長風破浪憶江淮。',32,'全唐诗/poet.song.242000.json','["玉笥孤帆喚不來，長風破浪憶江淮。", "不知海水何年陸，萬斛龍驤寄斷崖。"]'),
('d45f1ebf-3a11-48ba-b9d2-2f77efae46f9','陶山十詠和鄧牧心 舜田','林景熙','宋','宋诗','song-poetry','','[]','聞說東夷有聖人，歷山何處此耕雲。',32,'全唐诗/poet.song.242000.json','["聞說東夷有聖人，歷山何處此耕雲。", "露苗猶洒當年泣，寂寞春風鳥自耘。"]'),
('24789833-bf6c-4278-8745-945efc13dbf7','陶山十詠和鄧牧心 葛仙翁石床','林景熙','宋','宋诗','song-poetry','','[]','鈞天夢破珊瑚枕，巖壑春供翡翠屏。',32,'全唐诗/poet.song.242000.json','["鈞天夢破珊瑚枕，巖壑春供翡翠屏。", "一卷黄庭雲半席，夜深讀與嶺猿聽。"]'),
('84573e85-626c-4fdc-bbc0-c81187b0b4a1','陶山十詠和鄧牧心 上下二鑊','林景熙','宋','宋诗','song-poetry','','[]','元非鑄冶自成灣，烏兔烹煎那得閑。',32,'全唐诗/poet.song.242000.json','["元非鑄冶自成灣，烏兔烹煎那得閑。", "却問黄糧幾番熟，不知沸鼎在人間。"]'),
('faddc3b8-b9a3-4cf3-802e-90a8ff49500f','陶山十詠和鄧牧心 附子岡','林景熙','宋','宋诗','song-poetry','','[]','洞霞疑接台峰近，石棧空歌蜀道難。',32,'全唐诗/poet.song.242000.json','["洞霞疑接台峰近，石棧空歌蜀道難。", "一種靈苗人不識，半山霜露夜痕乾。"]'),
('79ea9b1f-c365-4d4b-b3f8-12c8614066ac','酬謝皋父見寄','林景熙','宋','宋诗','song-poetry','','[]','入山采芝薇，豺虎據我丘。',108,'全唐诗/poet.song.242000.json','["入山采芝薇，豺虎據我丘。", "入海尋蓬萊，鯨鯢掀我舟。", "山海兩有礙，獨立凝遠愁。", "美人渺天西，瑶音寄青羽。", "自言招客星，寒川釣烟雨。", "風雅一手提，學子屨滿戶。", "行行古臺上，仰天哭所思。", "餘哀散林木，此意誰能知。", "夜夢繞勾越，落日冬青枝。"]'),
('a865d548-a08c-425a-9c34-50f0a63a4d61','送喻舜舉歸壽乃翁七十','林景熙','宋','宋诗','song-poetry','','[]','聞君有奇氣，千巖在胸中。',96,'全唐诗/poet.song.242000.json','["聞君有奇氣，千巖在胸中。", "歲晚携甘旨，歸以獻乃翁。", "乃翁松柏姿，深村侶樵農。", "風塵了不識，七十顔如童。", "舉桉各華髮，抱孫戲花叢。", "境閑意易足，食淡神常豐。", "乃知世網外，宇宙皆空同。", "仰山千歲酒，綵袖圍春風。"]'),
('8ff32cd9-3a12-4657-90cb-5236afa81721','過徐禮郎狀元坊','林景熙','宋','宋诗','song-poetry','','[]','名坊臨野渡，曾此産魁豪。',48,'全唐诗/poet.song.242000.json','["名坊臨野渡，曾此産魁豪。", "湖带詩書潤，山增科第高。", "劫灰遺斷礎，鬼火出深蒿。", "東海揚塵久，無人釣六鼇。"]'),
('3b7d054e-fc90-47e1-9271-2494223805b5','古松','林景熙','宋','宋诗','song-poetry','','[]','雷電空山夜，髯蛟起石泉。',48,'全唐诗/poet.song.242000.json','["雷電空山夜，髯蛟起石泉。", "喬陰無六月，老氣欲千年。", "斸藥人能壽，巢枝鳥亦仙。", "天風靈籟發，彷彿奏虞絃。"]'),
('ce34fb7f-56f4-4293-8f4a-153680e5f68f','訪朱月峰不值','林景熙','宋','宋诗','song-poetry','','[]','見說携琴去，西風半日程。',48,'全唐诗/poet.song.242000.json','["見說携琴去，西風半日程。", "雲留秋渡冷，月過別峰明。", "落葉驚疏鬢，黄花照澹情。", "思君不能寐，一雁叫深更。"]'),
('dd452436-60f9-47fc-96e2-7317dcab2270','題長春子自畫','林景熙','宋','宋诗','song-poetry','','[]','辟穀曾吞日月華，春風不老聚三花。',64,'全唐诗/poet.song.242000.json','["辟穀曾吞日月華，春風不老聚三花。", "玄關一竅通無極，白髮餘生笑有涯。", "野鶴相看盟秀竹，洞雲何處食靈瓜。", "披圖彷彿榴皮迹，珍重還如東老家。"]'),
('8c03c08c-d11f-4147-9ca1-2f905be1393c','輓浙西提舉李公','林景熙','宋','宋诗','song-poetry','','[]','文獻凋零半壟雲，荆花舊宅冷溪濱。',64,'全唐诗/poet.song.242000.json','["文獻凋零半壟雲，荆花舊宅冷溪濱。", "欲知禮樂千年事，曾寄行藏八袠身。", "旌節自天驚隔世，衣冠入地見全人。", "鵠袍猶憶談經處，風雨宮槐暗落薪。"]'),
('e1d4d246-cafd-4188-839b-23df92757a17','輓徐若翁','林景熙','宋','宋诗','song-poetry','','[]','化鵬有便風初積，棲鵩無端日已斜。',64,'全唐诗/poet.song.242000.json','["化鵬有便風初積，棲鵩無端日已斜。", "絕漠亦傳垂死偈，故朝曾是勸忠家。", "層霄夢斷關山笛，深雪魂歸院落花。", "公論蓋棺應自定，猶言遺德在東嘉。"]'),
('0832447a-e694-43e8-bf8d-ff70325cbb09','重過虎林','林景熙','宋','宋诗','song-poetry','','[]','漠漠江湖夢，蕭蕭禾黍秋。',48,'全唐诗/poet.song.242000.json','["漠漠江湖夢，蕭蕭禾黍秋。", "清笳吹落日，白髮過西州。", "池涸神龍逝，山空老鳳愁。", "惟餘關外水，寂寞自東流。"]'),
('7bdd70e3-6a01-4c02-8e58-f3ec9cbe8343','故宮','林景熙','宋','宋诗','song-poetry','','[]','驚風吹雨過，歷歷大槐蹤。',48,'全唐诗/poet.song.242000.json','["驚風吹雨過，歷歷大槐蹤。", "王氣銷南渡，僧坊聚北宗。", "烟深凝碧樹，草沒景陽鐘。", "愁見花甎月，荒秋咽亂蛩。"]'),
('0847f220-f5ea-4604-aee8-e043e219222f','辟雍','林景熙','宋','宋诗','song-poetry','','[]','冠带百年夢，昔游今重嗟。',48,'全唐诗/poet.song.242000.json','["冠带百年夢，昔游今重嗟。", "璧池春飲馬，槐市暝藏鴉。", "堂鼓晨昏寂，廊碑風雨斜。", "石經雖不火，歲歲長苔花。"]'),
('b45449ac-7d8c-406d-8101-32bf3bc801fd','禮闈','林景熙','宋','宋诗','song-poetry','','[]','楓陛將親策，蘭宮此並馳。',48,'全唐诗/poet.song.242000.json','["楓陛將親策，蘭宮此並馳。", "凡鱗風雨化，澹墨鬼神司。", "染柳春衣凈，看花曉馬遲。", "偶來追昨夢，戍屋草離離。"]'),
('3c1c2eda-e732-455d-94ea-0830621614b6','西湖','林景熙','宋','宋诗','song-poetry','','["\u897f\u6e56"]','繁華已如夢，登覽忽成塵。',48,'全唐诗/poet.song.242000.json','["繁華已如夢，登覽忽成塵。", "風物矉西子，笙歌醉北人。", "斷猿三竺曉，殘柳六橋春。", "太一今誰問，斜陽自水濱。"]'),
('3fc614cb-37bb-4159-9299-ad19327fdc12','拜岳王墓','林景熙','宋','宋诗','song-poetry','','[]','寥落一抔在，英雄萬古冤。',48,'全唐诗/poet.song.242000.json','["寥落一抔在，英雄萬古冤。", "孤忠懸白日，遺恨寄中原。", "樹老殘霞澹，塵深斷碣昏。", "東南天半壁，往事泣寒猿。"]'),
('3ae9e169-9565-461c-a626-4ee91f7341e8','孤山','林景熙','宋','宋诗','song-poetry','','[]','回首咸平夢，清風自滿湖。',48,'全唐诗/poet.song.242000.json','["回首咸平夢，清風自滿湖。", "乾坤一士隠，身世此山孤。", "鶴去空秋影，梅開尚舊株。", "耳孫今白髮，持酒酹寒蕪。"]'),
('460d83cd-171e-46df-9256-56e9a48d3da3','葛嶺','林景熙','宋','宋诗','song-poetry','','[]','不讀霍光傳，炫然桃李門。',48,'全唐诗/poet.song.242000.json','["不讀霍光傳，炫然桃李門。", "湖山變朝市，烽火滿乾坤。", "膽落冰天騎，魂飛瘴雨村。", "春風吹秀麥，誤國竟何言。"]'),
('be1ea141-5ace-42e0-850d-099d70e77b95','飛來峰','林景熙','宋','宋诗','song-poetry','','[]','何年移竺國，秀色發稜層。',48,'全唐诗/poet.song.242000.json','["何年移竺國，秀色發稜層。", "清極不知夏，虛中欲悟僧。", "樹幽嵐氣重，泉落乳花凝。", "猶憶烹茶處，閒來話葛藤。"]'),
('97b92c97-d166-4e92-8a0a-53832b1c77d9','寄別諸公','林景熙','宋','宋诗','song-poetry','','[]','盍簪譚舊夢，持酒送餘春。',48,'全唐诗/poet.song.242000.json','["盍簪譚舊夢，持酒送餘春。", "天地綠陰雨，江湖白髮人。", "時平銷劍氣，客久積衣塵。", "又出重關北，斜陽獨問津。"]'),
('5ec7324f-5f28-4d37-ad40-911bf7ae43df','五月五日寓嘉禾學宮顧東浦載酒相過二博士偕來飲就醉翌日留詩爲別','林景熙','宋','宋诗','song-poetry','','[]','嘉禾古三輔，積水何蒼茫。',144,'全唐诗/poet.song.242000.json','["嘉禾古三輔，積水何蒼茫。", "舊游夢歷歷，况此逢端陽。", "束艾肖人形，傾葵抱天常。", "蕭蕭老逢掖，得依夫子牆。", "鵷湖無五月，宿雨生微凉。", "客從東浦來，手持紫霞觴。", "采蒲汎纖玉，沃我書傳香。", "殷勤兩博士，雜出肴與漿。", "書囊談未了，一醉齊彭殤。", "酒醒忽不樂，起看北斗芒。", "歲月感疏鬢，風烟渺殊方。", "明當理征棹，斜日鱸魚鄉。"]'),
('c48f34c2-af65-4699-9627-5a2b2fd08ebe','訪二陸故居','林景熙','宋','宋诗','song-poetry','','[]','風流懷二陸，才名動三吳。',144,'全唐诗/poet.song.242000.json','["風流懷二陸，才名動三吳。", "斯人不可作，千載空烟蕪。", "當時騁俊筆，萬象爭先驅。", "有如明月璧，美價傾鴻都。", "世運有翻覆，韞匵真良圖。", "惜哉去就乖，毀此千金軀。", "人生皆有死，百年同須臾。", "獨遺文字芳，乃與天壤俱。", "凄凄崑山寒，冉冉谷水枯。", "白鶴久已寂，黄犬誰復呼。", "荒祠掛殘陽，扁舟入菰蒲。", "采蓴薦秋水，庶以明區區。"]'),
('52dfb24b-e3c0-4d38-bd4a-b43c910a0e1d','簡衛山齋','林景熙','宋','宋诗','song-poetry','','[]','虎林一傾蓋，草窗雪初殘。',96,'全唐诗/poet.song.242000.json','["虎林一傾蓋，草窗雪初殘。", "酒酣夜剪燭，妙語鏗琅玕。", "回首隔吳越，清風渺難攀。", "焉知白首餘，遠訪滄波間。", "大鵬九萬里，神駿十二閑。", "天風非不高，乃樂烟水寬。", "乾坤寄一齋，江湖浮九山。", "何當躡飛珮，跨鶴青雲端。"]'),
('df730408-c296-4209-9393-6bb84088862d','會嚴陵邵德芳同舍邀宿玄同齋道舊有作','林景熙','宋','宋诗','song-poetry','','[]','市槐夢忽醒，喬柯落風雨。',168,'全唐诗/poet.song.242000.json','["市槐夢忽醒，喬柯落風雨。", "何人斧爲薪，遺根尚依土。", "緬懷赤煒初，鬰若翠蛟舞。", "其下有橋門，雍雍冠带聚。", "萬物遞衰盛，千載一仰俯。", "射策君先登，氣勇不再鼓。", "邅迴三舍間，我亦躋寸武。", "雲雷膏尚屯，有志良獨苦。", "空山少芝薇，大澤多網罟。", "爾來涉長途，征衣拂天姥。", "遥汎松江舟，薰風采芳杜。", "故人隠雲間，九山青照戶。", "相逢各華顛，舊事不敢吐。", "悠哉抱玄同，高卧標枝古。"]'),
('8a61b694-d5df-42a7-ab97-5dbf5623a342','謁陸宣公祠','林景熙','宋','宋诗','song-poetry','','[]','冰玉爲骨秋爲神，堂堂內相真天人。',128,'全唐诗/poet.song.242000.json','["冰玉爲骨秋爲神，堂堂內相真天人。", "諫草數百垂清芬，仁義一洗功利塵。", "刳肝瀝血空排雲，白日不鑒吾忠勤。", "奉天詔下哀痛新，將士感泣天亦聞。", "皇威雷動清九垠，一紙可敵百萬軍。", "草茅學古期致君，以額扣閽九虎嗔。", "玉堂雲霧當華津，耿耿何不批龍鱗。", "一尊酹古凄夕曛，鵷湖之水春復春。"]'),
('92e3196d-53b3-4a3d-a363-9237156ebe67','雲間懷古','林景熙','宋','宋诗','song-poetry','','[]','薰風短棹水粼粼，老鶴疏林寂不聞。',64,'全唐诗/poet.song.242000.json','["薰風短棹水粼粼，老鶴疏林寂不聞。", "內史祠荒殘碣雨，黄門書冷半堆雲。", "獵場斜日分桑塢，馳道秋深走鹿群。", "寥落一觴誰吊古，漁鄉烟景客平分。"]'),
('c3299771-162e-489f-ae6b-c174c55aa0c1','劉伶墓','林景熙','宋','宋诗','song-poetry','','[]','碧落當年墮酒星，醉中萬事一浮萍。',32,'全唐诗/poet.song.242000.json','["碧落當年墮酒星，醉中萬事一浮萍。", "亦知人世無窮事，一醉松根不肯醒。"]'),
('6c45c987-a7d5-44f1-abaf-567feda734a4','黄耳塚','林景熙','宋','宋诗','song-poetry','','[]','筠筒音斷水雲村，吠入空林枸杞根。',32,'全唐诗/poet.song.242000.json','["筠筒音斷水雲村，吠入空林枸杞根。", "我亦天涯音信杳，盧令詩在爲招魂。"]'),
('3d0a9c6a-f95b-49be-8cdf-31626dbbea86','蘇小小墓','林景熙','宋','宋诗','song-poetry','','[]','歌扇風流憶舊家，一丘落月幾啼鴉。',32,'全唐诗/poet.song.242000.json','["歌扇風流憶舊家，一丘落月幾啼鴉。", "芳魂不肯爲黄土，猶幻燕支半樹花。"]'),
('e377a94c-61a1-402f-a455-274364aa72dc','過淀山湖','林景熙','宋','宋诗','song-poetry','','[]','泖口乘寒浪，湖心散積愁。',48,'全唐诗/poet.song.242000.json','["泖口乘寒浪，湖心散積愁。", "菰蒲疑海接，鳬雁與天浮。", "澤國無三伏，風颿又一州。", "平生謾爲客，奇絕在茲游。"]'),
('44fdddaa-94a8-4255-9c48-4d155b515ea3','舟次吳門','林景熙','宋','宋诗','song-poetry','','[]','懷古心猶壯，臨流影自孤。',48,'全唐诗/poet.song.242000.json','["懷古心猶壯，臨流影自孤。", "湖烟迷檇李，城木出姑蘇。", "草暗春驚鹿，菰香秋試鱸。", "青樓舊時月，無復聽吳歈。"]'),
('83098a25-2d1b-4636-bb02-456cdc62f42a','虎丘寺','林景熙','宋','宋诗','song-poetry','','[]','突兀僧房倚翠微，金精幻虎霸圖非。',64,'全唐诗/poet.song.242000.json','["突兀僧房倚翠微，金精幻虎霸圖非。", "瓊田萬頃山如湧，鐵壁千尋泉自飛。", "堂在經聲通老石，樓開塔影落秋衣。", "千年幽獨嗟誰氏，斷刻苔深带夕暉。"]'),
('574ff908-9bbe-482a-9d54-d6dbb307c786','劍池','林景熙','宋','宋诗','song-poetry','','[]','鑿開神斧是何年，珠雁金鳬鎖冷烟。',64,'全唐诗/poet.song.242000.json','["鑿開神斧是何年，珠雁金鳬鎖冷烟。", "薜荔带雲懸古木，轆轤卷月出秋泉。", "巖前洗劍精疑伏，林下烹茶味亦禪。", "高倚石闌清嘯發，恐驚池底老龍眠。"]'),
('aa34649a-25ef-4932-a8b8-fde432779509','垂虹橋','林景熙','宋','宋诗','song-poetry','','[]','地坼東吳海脈連，畫橋兩道跨晴川。',64,'全唐诗/poet.song.242000.json','["地坼東吳海脈連，畫橋兩道跨晴川。", "影翻河漢蛟龍國，勢壓江湖螮蝀天。", "幾處征帆浮日月，四洲譙角隔風烟。", "三高遠矣荒祠在，一笛闌干夕照邊。"]'),
('fb1c6945-d864-451c-acef-9d055097dc18','館娃宮','林景熙','宋','宋诗','song-poetry','','[]','苧羅山女入宮新，四壁黄金一笑春。',32,'全唐诗/poet.song.242000.json','["苧羅山女入宮新，四壁黄金一笑春。", "步輦醉歸香逕月，隔江還有卧薪人。"]'),
('64cdf317-425d-46a5-bae9-3d8c6e879c60','真娘墓','林景熙','宋','宋诗','song-poetry','','[]','歌聲舞影散春霞，月殉香魂幾落花。',32,'全唐诗/poet.song.242000.json','["歌聲舞影散春霞，月殉香魂幾落花。", "休恨天家無分到，漢妃青塚落胡沙。"]'),
('f93f49e4-5acf-4017-9df5-760701a32b7e','羞墓','林景熙','宋','宋诗','song-poetry','','[]','遠望車塵汗雨流，自知覆水已難收。',32,'全唐诗/poet.song.242000.json','["遠望車塵汗雨流，自知覆水已難收。", "爲君富貴妾羞死，富貴如君不自羞。"]'),
('5d8aacd4-906c-4f76-a1a9-90489c03fe96','京口月夕書懷','林景熙','宋','宋诗','song-poetry','','[]','山風吹酒醒，秋入夜燈凉。',48,'全唐诗/poet.song.242000.json','["山風吹酒醒，秋入夜燈凉。", "萬事已華髮，百年多異鄉。", "遠城江氣白，高樹月痕蒼。", "忽憶凭樓處，淮天雁叫霜。"]'),
('b84af3dd-b4d6-47b8-b534-c27411b36752','許郢州故宅','林景熙','宋','宋诗','song-poetry','','[]','讀君丁卯集，想此建橋時。',48,'全唐诗/poet.song.242000.json','["讀君丁卯集，想此建橋時。", "荒草一區宅，清風七字詩。", "吳雲含靜態，郢樹寄餘悲。", "落日空懷古，長歌知不知。"]'),
('04625e39-6b40-4cd4-9b5e-76c45bd05951','多景樓故址','林景熙','宋','宋诗','song-poetry','','[]','灰飛百尺景愁人，斷礎殘蕪但鹿群。',64,'全唐诗/poet.song.242000.json','["灰飛百尺景愁人，斷礎殘蕪但鹿群。", "對峙金焦兩拳石，平分淮浙半江雲。", "乾坤幾沸蕭公鑊，風浪空藏郭氏墳。", "野衲不知興廢事，梵宮金碧自紛紛。"]'),
('930cd598-4d09-4485-a707-e7192c6e441a','鶴林寺','林景熙','宋','宋诗','song-poetry','','[]','流水蒼松石逕斜，甕城城外梵王家。',64,'全唐诗/poet.song.242000.json','["流水蒼松石逕斜，甕城城外梵王家。", "仙林不返雲巢鶴，僧鉢曾移海國花。", "剝落苔碑秋卧草，荒凉竹院午敲茶。", "當時一擲乾坤手，曾向山窻倚暮霞。"]'),
('16ed75ac-a704-4837-9a3c-76885af6e597','金山寺','林景熙','宋','宋诗','song-poetry','','[]','吳楚風烟畫裏看，中流樹色擁禪關。',64,'全唐诗/poet.song.242000.json','["吳楚風烟畫裏看，中流樹色擁禪關。", "一星化石江成陸，雙塔摩空寺裹山。", "衲寄雲林清海怪，泉移蛟窟照僧閒。", "千年天塹今如掌，寂寞寒潮自往還。"]'),
('c2181d5e-0285-4bf9-92ce-c7ae502b24e1','焦山寺','林景熙','宋','宋诗','song-poetry','','[]','山裹中流小梵林，寶蓮鼇背翠沈沈。',64,'全唐诗/poet.song.242000.json','["山裹中流小梵林，寶蓮鼇背翠沈沈。", "半空但覺烟嵐合，三面不知風浪深。", "仙井浴丹開曉日，海門浮玉澹秋陰。", "洞深瑶草無人采，瘞鶴殘碑浸碧潯。"]'),
('6fa6cf74-cfb0-4c89-b5e7-0a66527edc4b','宋武帝居今爲壽丘寺','林景熙','宋','宋诗','song-poetry','','[]','青衣夢破滿林烟，一擲乾坤亦偶然。',32,'全唐诗/poet.song.242000.json','["青衣夢破滿林烟，一擲乾坤亦偶然。", "僧屋翠微看月上，江山猶似永初年。"]'),
('0ea0ab5b-5306-4a89-ba50-4fd839239047','中𤃩泉舊在揚子江心今題金山寺井曰第一名泉余疑而問僧僧謂神龍所移嘗示夢方丈亦愚世也然江心風濤茫渺縱有泉不復可取  其一','林景熙','宋','宋诗','song-poetry','','[]','蜀波萬里與淮連，揚子江心浪拍天。',32,'全唐诗/poet.song.242000.json','["蜀波萬里與淮連，揚子江心浪拍天。", "陸羽當年亦奇士，驪龍蟄處識名泉。"]'),
('d9ca61f9-58b7-4fda-8203-572d5b1fd4d5','中𤃩泉舊在揚子江心今題金山寺井曰第一名泉余疑而問僧僧謂神龍所移嘗示夢方丈亦愚世也然江心風濤茫渺縱有泉不復可取  其二','林景熙','宋','宋诗','song-poetry','','[]','金鼇背上汲清泠，僧說龍移遠脈靈。',32,'全唐诗/poet.song.242000.json','["金鼇背上汲清泠，僧說龍移遠脈靈。", "若定此泉爲第一，惠山未必服中𤃩。"]'),
('04b4d5a9-a75e-45b8-b751-dbfc794b04f7','惠山泉','林景熙','宋','宋诗','song-poetry','','[]','第二名泉在，深雲護石闌。',48,'全唐诗/poet.song.242000.json','["第二名泉在，深雲護石闌。", "九峰靈氣洩，三伏細流寒。", "遠脈松長潤，餘香茗欲殘。", "荒祠懷陸羽，一掬酹空壇。"]'),
('5495e44c-f99f-441c-bdc0-ba7d3246ede8','丹陽泉','林景熙','宋','宋诗','song-poetry','','[]','揚子江中𣂏夜月，慧山亭上漱朝烟。',32,'全唐诗/poet.song.242000.json','["揚子江中𣂏夜月，慧山亭上漱朝烟。", "遥看丹氣霏微裏，二十泉中第四泉。"]'),
('095cf01b-336f-427c-a2d7-eba5b4373c12','新豐道中','林景熙','宋','宋诗','song-poetry','','[]','長飈卷炎埃，澄空出秋素。',72,'全唐诗/poet.song.242000.json','["長飈卷炎埃，澄空出秋素。", "迢迢鐵甕城，回首隔蒼霧。", "酒帘颺荒市，笳鼓發深戍。", "倚篷問舟人，云是新豐路。", "籬落雞欲棲，野水牛半渡。", "不見抱琴人，斜陽在高樹。"]'),
('d12f36d8-4285-47e9-893f-6776c4d7b0a9','石翁嫗','林景熙','宋','宋诗','song-poetry','','[]','束艾楚俗愚，鑄金秦民怖。',132,'全唐诗/poet.song.242000.json','["束艾楚俗愚，鑄金秦民怖。", "何年斲雲根，偶立此翁嫗。", "千春衣莓苔，偕老食風露。", "世人輕結髮，覆水或旦暮。", "乃習無情緣，永與天壤固。", "停舟一訪古，久欲祛此錮。", "父老向我言，曾是梁朝墓。", "衣冠化黄土，古丘亦成路。", "當年殉金棺，茲物獨如故。", "閲世如過客，興亡了不悟。", "時借牛礪角，敲火戲童豎。"]'),
('c2c03d9c-bb8f-483c-becd-94b5373040ef','毗陵太平院壁間畫山水熟視之有飛動勢殆仙筆也因題','林景熙','宋','宋诗','song-poetry','','[]','山風不動雲四寂，萬頃波濤生素壁。',128,'全唐诗/poet.song.242000.json','["山風不動雲四寂，萬頃波濤生素壁。", "三峽夜怒摇星河，九溟晝沸卷霹靂。", "誰將江海一筆吞，華陽入硯玄波翻。", "靈鼇東轉坤軸動，驚浪出沒蛟與黿。", "毫端分寸千萬里，人心之險亦如此。", "老僧閲世如閲畫，面壁凝然悟玄理。", "嗟余老作汗漫遊，寒光飛動六月秋。", "乃知瞿塘在平陸，安得竹葉吹成舟。"]'),
('df358214-5d06-4168-aca4-e40c7599cffd','舟中書事','林景熙','宋','宋诗','song-poetry','','[]','村酒沽來濁可斟，扁舟過雨繫楓林。',64,'全唐诗/poet.song.242000.json','["村酒沽來濁可斟，扁舟過雨繫楓林。", "午香吹稻海田熟，秋蔓引苽茅屋深。", "天地暗塵歸客鬢，江湖斜日動鄉心。", "衰年自笑爲形役，空羨閒鷗卧水陰。"]'),
('2e3e0e05-4cc0-4d38-9ced-3854002c582e','蜀頭陀客吳歲久持行精勤有道者也','林景熙','宋','宋诗','song-poetry','','[]','三峽無歸夢，閒雲澹石床。',48,'全唐诗/poet.song.242000.json','["三峽無歸夢，閒雲澹石床。", "半生修白社，孤影寄朱方。", "覺路心如月，高年頂不霜。", "翻憐來往者，終日爲誰忙。"]'),
('950b6908-9717-433d-b842-8c13ea14ba10','練川道中次胡汲古韻','林景熙','宋','宋诗','song-poetry','','[]','客中還又客，回首憶并州。',48,'全唐诗/poet.song.242000.json','["客中還又客，回首憶并州。", "一枕江湖夢，五更風雨舟。", "水寒荷葉老，蟲響豆花秋。", "幾度看雲坐，吾生亦覺浮。"]'),
('ef1b1d97-046f-4e40-94df-7c4539893c0e','劉龍洲墓','林景熙','宋','宋诗','song-poetry','','[]','一抔寂寞幾秋風，雲斷洲空憶老龍。',32,'全唐诗/poet.song.242000.json','["一抔寂寞幾秋風，雲斷洲空憶老龍。", "湖海劉郎詩骨冷，乾淳餘響寄孤松。"]'),
('ecc54ea6-8dc6-4cc6-b710-63ea4206061e','過吳門感前游','林景熙','宋','宋诗','song-poetry','','[]','回首前游夢未忘，江雲漠漠樹蒼蒼。',64,'全唐诗/poet.song.242000.json','["回首前游夢未忘，江雲漠漠樹蒼蒼。", "客心空老鶑花月，詩貌不肥魚稻鄉。", "白虎氣銷遺瘦石，綵虹影冷卧斜陽。", "當時已嘆來麋鹿，後二千年更斷腸。"]'),
('c95618cb-c104-432f-a403-f5ef0d494533','舟次吳興二首  其一','林景熙','宋','宋诗','song-poetry','','[]','釣舟遠隔菰蒲雨，酒幔輕飄菡萏風。',32,'全唐诗/poet.song.242000.json','["釣舟遠隔菰蒲雨，酒幔輕飄菡萏風。", "彷彿層城鼇背上，萬家簾幕水晶宮。"]'),
('8701927d-7e53-4464-bb57-89e41ab17463','舟次吳興二首  其二','林景熙','宋','宋诗','song-poetry','','[]','蒼烟淡淡水濛濛，漁笛吹殘夕照紅。',32,'全唐诗/poet.song.242000.json','["蒼烟淡淡水濛濛，漁笛吹殘夕照紅。", "六客風流今已遠，堂名空入酒名中。"]'),
('139b139b-80c4-4b37-ad7a-111a62ccacd5','釣臺','林景熙','宋','宋诗','song-poetry','','[]','曾來天上宿，夢不離寒磯。',48,'全唐诗/poet.song.242000.json','["曾來天上宿，夢不離寒磯。", "宇宙雙臺迥，烟波一客歸。", "姓增江郡重，墓隔越山微。", "千古登臨意，凄凉带夕暉。"]'),
('08ca55fb-80ee-4ed7-a153-aa5fb3698c44','宿七里灘','林景熙','宋','宋诗','song-poetry','','[]','寥落空江上，買魚開酒尊。',48,'全唐诗/poet.song.242000.json','["寥落空江上，買魚開酒尊。", "亂山含雪意，孤艇寄楓根。", "灘近不成夢，鴻飛欲斷魂。", "偶呼黄帽語，一犬吠前村。"]'),
('65edfaa4-fa49-442f-88ff-f4b72ea9e1b1','方玄英故居','林景熙','宋','宋诗','song-poetry','','[]','艤舟鸕鷀港，白雲滿高原。',132,'全唐诗/poet.song.242000.json','["艤舟鸕鷀港，白雲滿高原。", "借問玄英居，遺搆無復存。", "精靈幾百載，山鬼憑幽昏。", "獨遺文字香，隠隠草樹根。", "轉盼東山麓，彷彿見柴門。", "啼猨助悽惻，亦復銷我魂。", "漁父促歸橈，牛羊下前村。", "長揖者誰子，未識情已溫。", "云十有六葉，咸通之耳孫。", "緬思幽人後，風雅天所敦。", "相携就茅屋，一笑酌瓦尊。"]'),
('40a915d4-6a03-4dd6-986d-049ef66cc1a9','原易','林景熙','宋','宋诗','song-poetry','','[]','滎河通崑源，古出龍馬瑞。',156,'全唐诗/poet.song.242000.json','["滎河通崑源，古出龍馬瑞。", "包犧真天人，一見測其秘。", "八卦已支離，重爲六十四。", "爻象互立名，繫辭發洙泗。", "盡洩元氣藏，柯葉布文字。", "有如木生癭，箋註漫百氏。", "燋龜與揲草，何能解人意。", "及滋天下疑，反以二物具。", "方寸不自靈，柄爲冥漠據。", "弧矢啟戰爭，書契長奸僞。", "緬思未畫前，標枝無一事。", "日月自循環，全易在天地。", "所以負苓人，因之發長喟。"]'),
('461b5d84-0d63-466b-82d7-7a0001e2f8e3','蔡琰歸漢圖','林景熙','宋','宋诗','song-poetry','','[]','文姬別胡地，一騎輕南馳。',192,'全唐诗/poet.song.242000.json','["文姬別胡地，一騎輕南馳。", "傷哉賢王北，一騎挾二兒。", "二兒抱父啼，問母何所之。", "停鞭屢回首，重會知無期。", "孰云天壤內，野心無人彝。", "凡物以類偶，濕化猶相隨。", "穹廬况萬里，日暮驚沙吹。", "惜哉辨琴智，不辨華與夷。", "縱憐形勢迫，難掩節義虧。", "獨有思漢心，寫入哀絃知。", "一朝天使至，千金贖蛾眉。", "雨露洗腥瘢，陽和變愁姿。", "出關拜漢月，照妾心苦悲。", "妾心倘未白，何以覲彤墀。", "狐死尚首丘，越鳥終南枝。", "如何李都尉，沒齒陰山陲。"]'),
('d550f70f-b468-4f4a-a122-75c5bbfb0a48','用拙爲金罍徐氏賦','林景熙','宋','宋诗','song-poetry','','[]','久知拙無用，飾巧以相賢。',108,'全唐诗/poet.song.242000.json','["久知拙無用，飾巧以相賢。", "而君獨用拙，好古與世懸。", "不見百圍櫟，濩落終天年。", "豈其棄匠石，無用用乃全。", "孔門七十子，愚魯承禪傳。", "沖質抱元素，神工謝雕鎸。", "續鳬而刻馬，適以戕其天。", "柳州正坐巧，望星猶乞憐。", "一墮叔文累，挽海不可湔。"]'),
('3efbc587-5e7c-4d4c-a56f-4bacf0676bda','精衛','林景熙','宋','宋诗','song-poetry','','[]','形微意良苦，前身葬長鯨。',60,'全唐诗/poet.song.242000.json','["形微意良苦，前身葬長鯨。", "天高不可訴，宿憤何時平。", "欲填東海深，能使西山傾。", "山傾海乃深，日夜空悲鳴。", "情知力不任，誓將畢此生。"]'),
('33f16ee6-30a9-4fdf-a15b-63a90070bc8b','納凉過林氏居','林景熙','宋','宋诗','song-poetry','','[]','出郭已虛曠，入門轉蕭森。',96,'全唐诗/poet.song.242000.json','["出郭已虛曠，入門轉蕭森。", "筠棲無六月，聊以解我襟。", "紅日不到地，白雲時滿林。", "坐久石根冷，酒醒荷氣深。", "飄飄黄冠客，臨流鼓瑶琴。", "一鼓洗我耳，再鼓空我心。", "山高水復迥，彷彿蓬萊音。", "興盡拂衣去，城笳吹夕陰。"]'),
('da5d95c4-9d0f-49b2-aa23-b37368a15705','宴德初書樓','林景熙','宋','宋诗','song-poetry','','[]','樓高不二尋，已作百尺想。',84,'全唐诗/poet.song.242000.json','["樓高不二尋，已作百尺想。", "中有湖海豪，開襟納萬象。", "頗延素心人，談笑落清響。", "鄰花吹午香，簷竹薦秋爽。", "於中了行藏，此外斷俯仰。", "西樓富薰天，歌鐘樂華敞。", "荒凉風雨餘，山夔自來往。"]'),
('7eb4cfd1-13ca-4b35-a43c-a60bc37c69be','李兩山侍郎仲氏儒而醫解后會稽索詩識別','林景熙','宋','宋诗','song-poetry','','[]','我懷兩山翁，夙抱經濟略。',204,'全唐诗/poet.song.242000.json','["我懷兩山翁，夙抱經濟略。", "曾驅部使車，所至問民瘼。", "昆陽斗大州，漁吏久竭澤。", "三尺行風霆，四知厲冰蘗。", "公餘接寒士，促膝談禮樂。", "以我獨閉門，前茅訪林壑。", "當途盡挾貴，此道可敦薄。", "浮雲於我如，霖雨用汝作。", "如何歲龍蛇，斯人竟冥漠。", "平生詩萬篇，耿耿志誰託。", "頗聞仲氏賢，風骨似其伯。", "爾來一披霧，月梁慰離索。", "紛紛雞鶩中，夭矯見孤鶴。", "陽秋皮裏鑒，太素指下脈。", "猶有刀圭功，可敵廊廟爵。", "四百有四病，如禽應弦落。", "真病在人心，問君有何藥。"]'),
('68145bec-04b5-4bbc-8f5f-ce2966e85e6f','王德輔邀飲新醅予與陳用賓老輒先醉座上分韻得水字','林景熙','宋','宋诗','song-poetry','','[]','朔風號枯林，吹寒入肌髓。',156,'全唐诗/poet.song.242000.json','["朔風號枯林，吹寒入肌髓。", "江湖客影孤，况復懷萬里。", "白戰不持鐵，何以破愁壘。", "惟有無功鄉，歲暮足可恃。", "良朋邀我游，瓦盤列山卉。", "軋軋鳴珠泉，灧灧浮翠蟻。", "初疑變氣候，漸覺忘我爾。", "一觴復一觴，頹然兩衰齒。", "桓桓諸少年，互爵方未已。", "雖醉不敢譁，諧談亦書史。", "所以柴桑翁，濁醪有妙理。", "我渴夢西泠，攀條嚼冰蕊。", "醒來步虛廊，天空月在水。"]'),
('eabde303-cbac-4447-b1f5-66ade9b75a44','鹿城晚眺','林景熙','宋','宋诗','song-poetry','','[]','古城仙鹿遠，百感赴斜曛。',48,'全唐诗/poet.song.242000.json','["古城仙鹿遠，百感赴斜曛。", "海氣千年聚，山形九斗分。", "神鴉饑啄蘚，宰木蠹藏雲。", "何處鳴鉦發，春屯又易軍。"]'),
('9503be03-9d95-4d29-b2a4-ef7fa76743e2','初夏','林景熙','宋','宋诗','song-poetry','','[]','春歸不知處，溪楝日初長。',48,'全唐诗/poet.song.242000.json','["春歸不知處，溪楝日初長。", "舊篋題詩扇，疏簾讀易香。", "田蛙占水旱，海燕語興亡。", "復恐閑愁起，聽泉過石梁。"]'),
('a08f7311-96fd-4a52-96e5-ee9c1d002f13','過北雁蕩山下','林景熙','宋','宋诗','song-poetry','','[]','驛路入芙蓉，秋高見早鴻。',48,'全唐诗/poet.song.242000.json','["驛路入芙蓉，秋高見早鴻。", "蕩雲飛作雨，海日射成虹。", "一水通龍穴，諸峰盡佛宮。", "如何靈運屐，不到此山中。"]'),
('0ad89bba-9483-40c1-bfe4-ab633181fac4','禹穴','林景熙','宋','宋诗','song-poetry','','[]','古迹微茫久，雲深鎖薜蘿。',48,'全唐诗/poet.song.242000.json','["古迹微茫久，雲深鎖薜蘿。", "洞前青壁坼，世外素書多。", "猿狎垂山木，龍靈起井波。", "相傳通海眼，魚網得金科。"]'),
('767a8aae-90ea-4a05-b3bd-37086d388d11','禹廟','林景熙','宋','宋诗','song-poetry','','[]','萬國曾朝會，群山尚鬰盤。',48,'全唐诗/poet.song.242000.json','["萬國曾朝會，群山尚鬰盤。", "嚴祠鎮玄璧，故代守黄冠。", "窆入雲根古，梁歸雨氣寒。", "年年送春事，來拂蘚碑看。"]'),
('e40c78d4-9b3a-4762-95ac-4a2a5f37aafd','荷錢','林景熙','宋','宋诗','song-poetry','','[]','盈盈新疊碧，難借柳條穿。',48,'全唐诗/poet.song.242000.json','["盈盈新疊碧，難借柳條穿。", "鑄景菰蒲外，買鄰鷗鷺邊。", "炎官初掌柄，水國不書年。", "漸長薰風價，折筩供酒船。"]'),
('a35fb529-ae70-4065-84e2-7eb49e3e533e','過陶嶺有錢王井又三里有錢王石庵','林景熙','宋','宋诗','song-poetry','','[]','沙井泉初試，石庵苔已荒。',48,'全唐诗/poet.song.242000.json','["沙井泉初試，石庵苔已荒。", "不知更宋代，猶自說錢王。", "古塚木根怪，春山雲氣香。", "詩成無紙筆，駐馬語殘陽。"]'),
('ce8f113f-bc2a-433a-8485-69ddeb25e24c','久雨','林景熙','宋','宋诗','song-poetry','','[]','閉門荒草合，宿雨掩春華。',48,'全唐诗/poet.song.242000.json','["閉門荒草合，宿雨掩春華。", "西海無回日，東風幾落花。", "霧冥猿自嘯，蕩冷雁猶家。", "誰是補天手，空懷鍊石媧。"]'),
('a00eaf4c-8e88-4d74-8f9e-ddbedb432562','訪武伯山居','林景熙','宋','宋诗','song-poetry','','[]','照書雙眼碧，天欲壽斯文。',48,'全唐诗/poet.song.242000.json','["照書雙眼碧，天欲壽斯文。", "白髮前朝士，青山半屋雲。", "遲花春後見，遠瀑夜深聞。", "迴看重華夢，荒田自鹿麕。"]'),
('039add73-ab76-4ee0-91ae-56fe2e0f4913','客意','林景熙','宋','宋诗','song-poetry','','[]','獨夜愁如此，殊鄉老柰何。',48,'全唐诗/poet.song.242000.json','["獨夜愁如此，殊鄉老柰何。", "故人經亂少，歸夢入秋多。", "衣敝鄰砧動，書沈海雁過。", "燈前空拂劍，酒薄不成歌。"]'),
('46e0c70b-4ec8-4932-af71-e4a404366e62','漁笛','林景熙','宋','宋诗','song-poetry','','[]','楚竹聲何遠，蒼茫想釣舟。',48,'全唐诗/poet.song.242000.json','["楚竹聲何遠，蒼茫想釣舟。", "橫當半篷月，吹破一江秋。", "落葉紛前浦，驚鴻過別洲。", "曲終枕蓑卧，無夢到凉州。"]'),
('d75c29bf-4985-4f78-8eeb-117ac1689463','雨土','林景熙','宋','宋诗','song-poetry','','[]','豐凶不可問，疑入瘴鄉春。',48,'全唐诗/poet.song.242000.json','["豐凶不可問，疑入瘴鄉春。", "高漢枯無潤，剛風吹作塵。", "園林霜後色，樵牧霧中身。", "四望荒荒白，誰爲洗日人。"]'),
('a9e539c6-20c7-4733-8857-99ee7ad07fcc','枯樹','林景熙','宋','宋诗','song-poetry','','[]','凋悴緣何事，青青憶舊叢。',48,'全唐诗/poet.song.242000.json','["凋悴緣何事，青青憶舊叢。", "有枝撐夜月，無葉起秋風。", "暑路行人惜，寒巢宿鳥空。", "倘留心不死，噓拂待春工。"]'),
('b3535903-5917-443d-bb59-b563bd74c6a8','潘山長入括','林景熙','宋','宋诗','song-poetry','','[]','爲官轉多事，行役到寒氈。',48,'全唐诗/poet.song.242000.json','["爲官轉多事，行役到寒氈。", "落日鄰州樹，西風逆水船。", "飯牛懷白石，訪鶴入青田。", "我欲看行卷，仙峰雪瀑邊。"]'),
('b6fd022c-78de-4dee-8725-0f5afc1baead','江心寺','林景熙','宋','宋诗','song-poetry','','[]','佛借龍宮五百年，平分城樹與村烟。',64,'全唐诗/poet.song.242000.json','["佛借龍宮五百年，平分城樹與村烟。", "叢林忽湧中流地，雙塔曾擎半壁天。", "石色带雲籠客袖，磬聲和月落漁船。", "袈袍不限侵門水，十載何人坐象筵。"]'),
('25e8832e-d76f-4b26-845d-356ab37807de','長至日','林景熙','宋','宋诗','song-poetry','','[]','觀物閒中得化機，相隨野鶴立多時。',64,'全唐诗/poet.song.242000.json','["觀物閒中得化機，相隨野鶴立多時。", "遺編蠹老芸空辟，舊念灰寒管不吹。", "夜氣清明非藥鼎，春風消息在梅枝。", "三杯美酒微微醉，細和堯夫擊壤詩。"]'),
('4fd2a617-f4cc-43c6-ada5-7b5399304a89','元日得家書喜','林景熙','宋','宋诗','song-poetry','','[]','爆竹聲殘事事新，獨憐臨鏡尚儒巾。',64,'全唐诗/poet.song.242000.json','["爆竹聲殘事事新，獨憐臨鏡尚儒巾。", "寒窗琴冊燈花曉，衰鬢江湖柏酒春。", "道在老天扶客健，書來稚子識家貧。", "舊山亦有閒風月，歸與漁樵作主人。"]'),
('8924aba7-94e5-4b3a-8999-941f1f52fac3','次翁秀峰','林景熙','宋','宋诗','song-poetry','','[]','花柳湖西別此翁，十年鬢雪忽重逢。',64,'全唐诗/poet.song.242000.json','["花柳湖西別此翁，十年鬢雪忽重逢。", "唐陵愁問永和帖，楚水夢聞長樂鐘。", "黄嬭秋燈餘舊癖，素侯野服拜新封。", "世情雲雨何時了，千古青青太玉峰。"]'),
('5dd88ce4-7aa5-4ddc-bfa2-b0ccf0a11202','立春郊行次唐玉潜','林景熙','宋','宋诗','song-poetry','','[]','道人清事飯溪蔬，無酒閑愁已破除。',64,'全唐诗/poet.song.242000.json','["道人清事飯溪蔬，無酒閑愁已破除。", "五夜雪聲梅角底，一春烟景竹筇初。", "園林芳信醒愁蝶，田野豐年入夢魚。", "冰下流泉清老耳，東風先已到郊居。"]'),
('bb40f156-d2ff-4595-b2ae-7e426dc27d3a','寄七山人','林景熙','宋','宋诗','song-poetry','','[]','十年疏鬢爲誰斑，天借儒冠日月閒。',64,'全唐诗/poet.song.242000.json','["十年疏鬢爲誰斑，天借儒冠日月閒。", "欹枕寒生雙瀑澗，開門春滿七星山。", "鶴歸尚覺遼城是，鵑老空聞蜀道難。", "欲覓九還憑寄語，青牛何日度函關。"]'),
('8b6c66b3-eca6-4ddc-b6f8-a77e5cea586a','王德玉席上賦牡丹','林景熙','宋','宋诗','song-poetry','','[]','露洗檀心迥絕塵，猩袍曾受百花臣。',64,'全唐诗/poet.song.242000.json','["露洗檀心迥絕塵，猩袍曾受百花臣。", "東風喚起清平曲，西洛移來富貴春。", "金縷杯深如勸客，香霞幄暖欲薰人。", "年年此地開芳席，看到兒孫色更新。"]'),
('db8c495d-991b-4bcf-b074-a04ecde1dbb7','和王德游夜感','林景熙','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','小池荷凈雨初晴，世念消磨未到僧。',64,'全唐诗/poet.song.242000.json','["小池荷凈雨初晴，世念消磨未到僧。", "衣带長江空北固，觚稜舊月隔西興。", "一春空負花前酒，獨夜相知竹下燈。", "自笑老來甘鷁退，少年雲路健追鵬。"]'),
('3d8cffce-9297-425a-be10-3dfb4c034e05','荷花','林景熙','宋','宋诗','song-poetry','','[]','凈根元不競芳菲，萬柄亭亭出碧漪。',64,'全唐诗/poet.song.242000.json','["凈根元不競芳菲，萬柄亭亭出碧漪。", "乘露醉肌渾欲洗，無風清氣自相吹。", "製裳香冷微雲護，傾蓋盟深獨月知。", "却笑滿城紛繡縠，濂溪此意更同誰。"]'),
('df2ea6f4-1351-48d5-a0a4-345efa76ed65','納凉','林景熙','宋','宋诗','song-poetry','','[]','黄卷無端作睡媒，火雲萬朵鬰崔嵬。',64,'全唐诗/poet.song.242000.json','["黄卷無端作睡媒，火雲萬朵鬰崔嵬。", "暑如酷吏何當去，薰自重華知幾來。", "脚踏層冰思遠壑，手遮赤日厭飛埃。", "披襟坐石不能夜，忽聽南山起怒雷。"]'),
('b095a43e-0e4f-4129-9ad6-4f1e8700b149','次王脩竹監簿送羽士過龍瑞宮','林景熙','宋','宋诗','song-poetry','','[]','龍迎葱珮出珠宮，鏡水凉生碧樹中。',64,'全唐诗/poet.song.242000.json','["龍迎葱珮出珠宮，鏡水凉生碧樹中。", "崖裂千尋根到海，劍懸七尺氣橫空。", "晝閒謾寫琴三疊，曉發猶餘鼓一通。", "猿鶴無期雲自在，人間何更有空同。"]'),
('4f8c9ad9-e595-4d3f-b45f-bd341796b8b0','王監簿陶山禱雨志喜','林景熙','宋','宋诗','song-poetry','','[]','城居苦熱念林丘，偶向殊庭送羽流。',64,'全唐诗/poet.song.242000.json','["城居苦熱念林丘，偶向殊庭送羽流。", "雙袖携雲禹穴曉，一瓢分雨舜田秋。", "溪聲冉冉來松壑，秋意蕭蕭滿竹樓。", "我與蠅蚊爭晝夜，夢中猶及赴清游。"]'),
('dcd264ce-40f3-4d60-b090-8f0e1de7697d','次韻山中見寄','林景熙','宋','宋诗','song-poetry','','[]','物外高棲豈好奇，愛凉坐到雨來時。',64,'全唐诗/poet.song.242000.json','["物外高棲豈好奇，愛凉坐到雨來時。", "四愁歲月空平子，三樂乾坤自啟期。", "晉代諸賢曲水會，鎬京遺澤變風詩。", "世交翻覆如雲雨，野鶴孤心老竹知。"]'),
('d11941a6-345b-4376-9f75-9089015621dd','王監簿南墅新樓落成','林景熙','宋','宋诗','song-poetry','','[]','玉佩珊珊不可招，眼空塵界等秋毫。',64,'全唐诗/poet.song.242000.json','["玉佩珊珊不可招，眼空塵界等秋毫。", "山林貞白三層迥，湖海元龍百尺高。", "自笑行藏關氣數，肯將歌舞換風騷。", "卷簾最愛南山近，坐聽松聲起碧濤。"]'),
('de093841-6b14-4885-9a32-2fbcb0a5752b','石門洞','林景熙','宋','宋诗','song-poetry','','[]','臨溪雙石如層城，中有洞天門不扃。',192,'全唐诗/poet.song.242000.json','["臨溪雙石如層城，中有洞天門不扃。", "杖藜穿莎入微逕，古藤絡樹春冥冥。", "渴猿引子下飲澗，山瓢我亦分清泠。", "一重一掩翳復朗，朱門金榜開殊庭。", "衆峰環拱受約束，何年神造驅五丁。", "縹緲樓臺鐘磬寂，薜荔紛披窗戶青。", "黄冠羽服者誰子，瓊臺坐閲南華經。", "客來揖坐松下石，呼茶味瀹枸杞靈。", "笑遣青衣導予步，峰回路轉銀河傾。", "初看絕壁走雲霧，倏聽萬壑驅風霆。", "不知何代擘青峽，明珠萬斛皆龍腥。", "欲喚琴高借仙鯉，濛濛山雨吹孤亭。"]'),
('2d5dc601-93bc-4846-a119-6450ffcc525e','荷珠','林景熙','宋','宋诗','song-poetry','','[]','霞衣葱珮來珊珊，水晶之宮綠玉盤。',128,'全唐诗/poet.song.242000.json','["霞衣葱珮來珊珊，水晶之宮綠玉盤。", "誰與馮夷作戲劇，貝闕驅入神瓢翻。", "又疑罷織蛟人泣，碧漥融作水銀汁。", "圓或爲璧方爲珪，寒光滉漾不可拾。", "古來欹器戒覆傾，真宰之柄常惡盈。", "季倫買笑輕百斛，金谷轉首迷榛荆。", "紛紛魚目爭貴惜，道眼獨懸諸幻息。", "須臾海霽山日高，綠雲萬柄凈如拭。"]'),
('6b207d7c-843e-44fe-9476-1a0851936e3a','遊九鎖山 入九鎖山門','林景熙','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','肥馬輕裘到此難，名標九鎖翠微間。',64,'全唐诗/poet.song.242000.json','["肥馬輕裘到此難，名標九鎖翠微間。", "天開洞府幾千載，地隔風塵此一關。", "謝屐空憐迷雁蕩，蘇詩不是夢廬山。", "他生修得清緣在，擬扣金堂覓大還。"]'),
('0716f074-030f-4eb5-acd8-6cbf28f1e75e','遊九鎖山 松間','林景熙','宋','宋诗','song-poetry','','[]','客杖偶逢山鶴引，儒冠幸免野猿嗔。',32,'全唐诗/poet.song.242000.json','["客杖偶逢山鶴引，儒冠幸免野猿嗔。", "吹來松氣清人骨，爲洗東華萬斛塵。"]'),
('5aad5924-d337-4b98-a01f-e4d78e513427','遊九鎖山 鳳洞','林景熙','宋','宋诗','song-poetry','','[]','日澹梧枝洞鎖苔，人間矰繳幾驚猜。',32,'全唐诗/poet.song.242000.json','["日澹梧枝洞鎖苔，人間矰繳幾驚猜。", "九苞自是沖霄物，曾爲簫韶一出來。"]'),
('465df3a1-17d1-4005-a7b9-2eea2a189862','遊九鎖山 龍洞','林景熙','宋','宋诗','song-poetry','','[]','雲濕林腥隠石扉，不知何代有龍歸。',32,'全唐诗/poet.song.242000.json','["雲濕林腥隠石扉，不知何代有龍歸。", "却疑此洞元無底，下挾滄溟作雨飛。"]'),
('4cf80d2d-2a0c-4e25-abbf-7d052e8cad22','遊九鎖山 翠蛟亭','林景熙','宋','宋诗','song-poetry','','[]','百雷鬭我前，八溟覆我後。',156,'全唐诗/poet.song.242000.json','["百雷鬭我前，八溟覆我後。", "誰哉擘巨崖，縱此翠蛟走。", "又疑蜀川下，萬騎赴峽口。", "凭闌神爲摇，清寒逼兩肘。", "久乃與之忘，一洗耳目垢。", "骨冷春木臞，魂驚夜猿吼。", "神仙亦愛奇，臨流并瓊玖。", "乘鯉琴高風，捉月太白手。", "跳入水晶宮，身世亦何有。", "緬懷玉局翁，不受荒幻誘。", "爾來謁空祠，采蘋奠玄酒。", "百年等一漚，道先天地壽。", "逝者固如斯，川上嘆魯叟。"]'),
('a1b6e941-7708-4ea5-b249-975ca16cadd5','遊九鎖山 洞霄宮','林景熙','宋','宋诗','song-poetry','','[]','洞天有別雲，福地無凡土。',144,'全唐诗/poet.song.242000.json','["洞天有別雲，福地無凡土。", "嘉名此兼擅，靈氣適專聚。", "峰巒互重掩，雲霧自吞吐。", "飄然乘泠風，一瓣謁瓊宇。", "住山老黄冠，迎客琪樹午。", "魚魚美少年，華裾集齋鼓。", "往者修鍊人，飛昇接高武。", "爾來何寂寥，山川亦今古。", "甲第擬王侯，億萬富倉庾。", "所以氣體移，學道不精苦。", "吾聞郭許儔，卓庵老林莽。", "終日對白雲，餐松飲石乳。"]'),
('992e532a-62ed-4a41-a2af-6ea4387a98fc','遊九鎖山 大滌洞天','林景熙','宋','宋诗','song-poetry','','[]','九鎖絕人寰，一嶂聳天柱。',168,'全唐诗/poet.song.242000.json','["九鎖絕人寰，一嶂聳天柱。", "自從開闢來，著此洞天古。", "奇石千萬姿，元不費神斧。", "帝勑守六丁，山夔孰敢侮。", "白晝中冥冥，游者必持炬。", "或絢若霞敷，或蹙若波詭。", "或豎若旌幢，或懸若鐘鼓。", "或虎而爪踞，或鳳而翅舞。", "異狀紛獻酬，清音起擊拊。", "不知金堂仙，恍惚在何許。", "褰衣下側逕，層嵐結瓊乳。", "逕極罅轉深，幽潭蓄風雨。", "劣容童豎入，恐觸蛟龍怒。", "凜乎不可留，長嘯出巖戶。"]'),
('064d4c21-01fb-4c79-84ae-ef684652539a','遊九鎖山 棲真洞','林景熙','宋','宋诗','song-poetry','','[]','聞有真人白日昇，洞天千古卓崚嶒。',64,'全唐诗/poet.song.242000.json','["聞有真人白日昇，洞天千古卓崚嶒。", "頂高絕似撐華蓋，穴暝初疑入武陵。", "秋靜石枰空暈蘚，寒生泉縫忽懸冰。", "依依谷口斜陽在，已覺熏風濕杖藤。"]'),
('19b03e4d-bb1b-4a8d-8de8-809e60326931','遊九鎖山 天柱峰','林景熙','宋','宋诗','song-poetry','','[]','誰卓孤峰紫翠巔，流泉一脈到宮前。',32,'全唐诗/poet.song.242000.json','["誰卓孤峰紫翠巔，流泉一脈到宮前。", "却憐千尺擎天柱，不拄東南半壁天。"]'),
('aac2ebcd-9dc9-4135-8b0b-0368e405835d','遊九鎖山 神仙隱跡','林景熙','宋','宋诗','song-poetry','','[]','仙子渾無涉世勞，屐痕一尺寄孤高。',32,'全唐诗/poet.song.242000.json','["仙子渾無涉世勞，屐痕一尺寄孤高。", "幾人失脚風波裏，可是雲根立得牢。"]'),
('197fb80b-132f-4f72-8ef6-7390833db854','遊九鎖山 過石壁丹泉二亭','林景熙','宋','宋诗','song-poetry','','[]','華表鶴歸處，林深別有天。',48,'全唐诗/poet.song.242000.json','["華表鶴歸處，林深別有天。", "雲陰生石壁，杉影落丹泉。", "宇宙名山在，神仙古洞懸。", "歸來凡骨換，寂照起三田。"]'),
('d56499dc-dc87-4fff-9bcd-4ebf786f3c84','留寄沈介石高士','林景熙','宋','宋诗','song-poetry','','[]','名山隔風雨，幾度夢空馳。',48,'全唐诗/poet.song.242000.json','["名山隔風雨，幾度夢空馳。", "谷口重來路，雲根舊別時。", "玄門尊老宿，白髮長嬰兒。", "欲問還丹事，林深鶴已知。"]'),
('74c095d6-7686-4515-aed0-6c89969748cd','懷葉鄧二友','林景熙','宋','宋诗','song-poetry','','[]','中歲修玄學，懸崖結屋危。',48,'全唐诗/poet.song.242000.json','["中歲修玄學，懸崖結屋危。", "幻身風露襲，淺戶虎狼窺。", "九鎖洞中志，一瓢身後詩。", "定知明月夜，雙鶴影相隨。"]'),
('34a7b2cc-8b49-4ec9-a87f-2ca1bd9406b9','半雲庵','林景熙','宋','宋诗','song-poetry','','[]','天地等蘧廬，結廬復何事。',120,'全唐诗/poet.song.242000.json','["天地等蘧廬，結廬復何事。", "一間亦寄耳，况乃寄所寄。", "我身正似雲，於此適相值。", "買鄰不用錢，平分有餘地。", "豈不愛專壑，孤立聖所懼。", "平生志八荒，澤物乃吾素。", "我行雲不隨，雲行我復住。", "出處兩何心，得非以時故。", "造物無全功，蒼生竟誰籲。", "石床坐忘言，各分一半愧。"]'),
('e3ad2576-9607-4ece-a4f7-608547ea0627','端午次韻懷古或疑屈原曹娥死非正命是不知殺身成仁者也併爲發之','林景熙','宋','宋诗','song-poetry','','[]','葵榴入眼明，得酒慰衰齒。',120,'全唐诗/poet.song.242000.json','["葵榴入眼明，得酒慰衰齒。", "胡爲浪自悲，懷古淚紛委。", "湘江沈忠臣，越江沈孝子。", "沈骨不沈名，清風兩江水。", "或云非正命，是昧舍生理。", "歸全豈髮膚，所懼本心毀。", "哭父天爲驚，憂君國將燬。", "於焉偷吾生，何以立戴履。", "脩短在百年，芳穢垂千紀。", "之人死猶生，滔滔真死矣。"]'),
('b1318da8-eb2d-4a4f-89db-f9470542e1f5','陳子植草廬成求予賦','林景熙','宋','宋诗','song-poetry','','[]','老矣杜陵客，草堂倚江干。',132,'全唐诗/poet.song.242000.json','["老矣杜陵客，草堂倚江干。", "故人相幽築，皇天愍生還。", "君家付楚炬，結搆當時囏。", "謂得風雅力，竹木供大官。", "城邊夜歸鶴，杳杳發長歎。", "朱甍昔峨峨，碧草今曼曼。", "何如蔭白茅，容膝有餘安。", "我哀喪亂餘，人烟半凋殘。", "風凄狐兔警，露重星斗寒。", "丈夫坐一室，此念馳九寰。", "所以草堂人，安得千萬間。"]'),
('3d7c2f07-e750-40ff-ae8e-ec8098cadb1d','有感','林景熙','宋','宋诗','song-poetry','','[]','逢春感孤羈，抱古來衆吠。',48,'全唐诗/poet.song.242000.json','["逢春感孤羈，抱古來衆吠。", "如何陵谷遷，芳草亦蕭艾。", "自憐歲月晚，復覺湖海隘。", "野鷗不受招，興在萬里外。"]'),
('c9121baf-752b-4121-af41-e147e7ebea2e','寄四明陳楙陽','林景熙','宋','宋诗','song-poetry','','[]','高人謝世紛，誅茅在絕壁。',84,'全唐诗/poet.song.242000.json','["高人謝世紛，誅茅在絕壁。", "十年不下山，舊路掩深棘。", "出門復踟躕，觸步有崩石。", "下臨千仞淵，毒鱗正紛籍。", "腥風鼓洪濤，石齒鳴咋咋。", "失勢倘一落，萬綆那可及。", "不如息我軀，猿鶴與朝夕。"]'),
('5d037128-2e70-44b9-882a-5baded52f7f6','贈東谷上人','林景熙','宋','宋诗','song-poetry','','[]','岸陵幾紛紛，岐路誰了了。',48,'全唐诗/poet.song.242000.json','["岸陵幾紛紛，岐路誰了了。", "中有定慧人，翛然坐深窈。", "山空諸念消，月墮孤禪悄。", "一室虛白生，天雞弄清曉。"]'),
('8cae3974-24fd-4a6f-8a0f-ccc00e75505c','題水雲深處','林景熙','宋','宋诗','song-poetry','','[]','霏霏弄閒態，灧灧揚素紋。',48,'全唐诗/poet.song.242000.json','["霏霏弄閒態，灧灧揚素紋。", "幽人不可即，但見水與雲。", "蒼狗紛世情，瞿塘在平地。", "所以盟白鷗，萬荷最深處。"]'),
('d4dcdf36-561e-4c1d-b7d9-fdae0e618f79','送胡汲古歸嚴陵覲親','林景熙','宋','宋诗','song-poetry','','[]','胡君白雲心，鄉夢攪幽夕。',132,'全唐诗/poet.song.242000.json','["胡君白雲心，鄉夢攪幽夕。", "挑燈起我言，相對竟惻惻。", "問君何時歸，心已寄飛翼。", "我歸萬山遥，君歸一水直。", "十年湖海間，耕硯苦不穡。", "居然保章甫，晨省無愧色。", "高堂椿樹蒼，萱花在堂北。", "再拜捧壽巵，晴芳滿瑶席。", "塤箎夜床溫，冠蓋春巷塞。", "萬古天倫中，真樂非外借。", "明朝浙東西，片雲渺何極。"]'),
('bc080387-56ad-4968-9340-a61a26c3b652','哭薛榆溆同舍','林景熙','宋','宋诗','song-poetry','','[]','桂死月亦灰，鵬枯海爲陸。',216,'全唐诗/poet.song.242000.json','["桂死月亦灰，鵬枯海爲陸。", "自我哭斯文，老淚幾盈掬。", "故國忽春夢，故人復霜木。", "矯矯榆溆君，白首尚儒服。", "解后一寫心，乾坤兩眉蹙。", "無力能怒飛，有道欲私淑。", "憶游東浦雲，馬帳肯同宿。", "孤燈照寒雨，蕭蕭半窗竹。", "君器碩以方，有如舟萬斛。", "歛華就本根，耆年謂可卜。", "昨別猶是人，今乃在鬼錄。", "爲善未必遐，嗚呼真宰酷。", "往年海若怒，風濤卷人屋。", "脫身鯨魚吻，長寐固應熟。", "寡妻泣帷荒，有子繼經術。", "彼哉暴殄夫，食必饌金玉。", "一士苜蓿腸，奪之胡忍速。", "問天天夢夢，秋聲滿巖谷。"]'),
('76bf65c9-007d-4ce0-96a6-88e4a2ecc39c','贈蘭坡星翁','林景熙','宋','宋诗','song-poetry','','[]','深林澹孤芳，一洗桃李姿。',132,'全唐诗/poet.song.242000.json','["深林澹孤芳，一洗桃李姿。", "采采坡雲暮，持之欲遺誰。", "故人青雲端，或在江海涯。", "青雲達者路，江海幽人期。", "有如一種蘭，升沈亦殊岐。", "南宮香滿握，誰使紉湘纍。", "客笑試問君，君曰數所爲。", "嗟予偶閲理，焚膏自童時。", "功名千載芬，白首心已違。", "富貴倘貽臭，不如貧賤怡。", "吾生吾自斷，爲謝君平帷。"]'),
('67bf4629-493c-4f96-9a3b-469a5aceb73d','雪後','林景熙','宋','宋诗','song-poetry','','[]','開簾殘酒醒，雪意尚垂垂。',48,'全唐诗/poet.song.242000.json','["開簾殘酒醒，雪意尚垂垂。", "夜色沈奎久，春容變柳遲。", "寒塘鷗自聚，荒歲鶴同饑。", "便欲誅茅隠，何山有紫芝。"]'),
('280fa66f-a8f4-419d-ade8-509251f3fcae','山中早行','林景熙','宋','宋诗','song-poetry','','[]','短策穿幽徑，山樵半掩扉。',48,'全唐诗/poet.song.242000.json','["短策穿幽徑，山樵半掩扉。", "月斜林影薄，石盡水聲微。", "一犬隔籬吠，孤僧何處歸。", "相逢松下立，風露滿秋衣。"]'),
('6b6a9558-2fc2-494a-b466-abe4aac00f7a','寄薌林故人','林景熙','宋','宋诗','song-poetry','','[]','狺狺多楚狗，何處續離騷。',48,'全唐诗/poet.song.242000.json','["狺狺多楚狗，何處續離騷。", "草徑無塵入，秋峰與節高。", "菰香清野飯，柳色老宮袍。", "笑問劉安鼎，相看已二毛。"]'),
('37bf04fa-31d1-4e08-88fe-849c95b6c2a4','疏懶爲四明何君賦','林景熙','宋','宋诗','song-poetry','','[]','野意雲同散，閑門草自新。',48,'全唐诗/poet.song.242000.json','["野意雲同散，閑門草自新。", "不知世網密，爲謝客車頻。", "風月兼忘我，山林亦恕人。", "咸陽歎黄犬，榮辱古爲鄰。"]'),
('166a2bc8-937b-4256-9a66-c2ab647d4c22','答山中侃上人','林景熙','宋','宋诗','song-poetry','','[]','竹房分半席，流水白雲間。',48,'全唐诗/poet.song.242000.json','["竹房分半席，流水白雲間。", "丹竈餘千載，青鞋第幾山。", "有詩多解悟，無髮得高閒。", "因笑塵中客，重逢改舊顔。"]'),
('516ba7d1-185a-4578-8db1-e393b0387c4c','山陰秋懷','林景熙','宋','宋诗','song-poetry','','[]','舊游渾似夢，短髮不勝簪。',48,'全唐诗/poet.song.242000.json','["舊游渾似夢，短髮不勝簪。", "風雨行金氣，乾坤老鐵心。", "舜田秋稗滿，禹穴夕雲深。", "正自登臨懶，凄凉隔水砧。"]'),
('3a2c2680-11e4-422e-86b6-c6e28a78a13d','初夏病起','林景熙','宋','宋诗','song-poetry','','[]','青衫蕉鹿夢，江海一畸人。',48,'全唐诗/poet.song.242000.json','["青衫蕉鹿夢，江海一畸人。", "舊國愁生暮，衰年病過春。", "天垂湖色湛，雨洗月痕新。", "猶抱遺經在，心銜覆載仁。"]'),
('632dbfaf-4c84-4a6e-9a2f-9f57ed69dcb2','溪亭','林景熙','宋','宋诗','song-poetry','','[]','清秋有餘思，日暮尚溪亭。',48,'全唐诗/poet.song.242000.json','["清秋有餘思，日暮尚溪亭。", "高樹月初白，微風酒半醒。", "獨行穿落葉，閒坐數流螢。", "何處漁歌起，孤燈隔遠汀。"]'),
('d223abe5-ee05-4460-a2e4-222770f81a54','答陳景賢','林景熙','宋','宋诗','song-poetry','','[]','一劍掛寒壁，艱危氣不衰。',48,'全唐诗/poet.song.242000.json','["一劍掛寒壁，艱危氣不衰。", "鬢痕朝鏡覺，書味夜燈知。", "夢斷潮生枕，愁新雁入詩。", "思君心欲折，又負菊花期。"]'),
('f9b37f11-6a5a-47d9-8ae5-c684cc4c21cf','薛德之之江東簡熊西玉諸公','林景熙','宋','宋诗','song-poetry','','[]','乍逢還又別，龍竹葛陂陰。',48,'全唐诗/poet.song.242000.json','["乍逢還又別，龍竹葛陂陰。", "野水流春遠，江雲入暮深。", "新知滿湖海，遺老在山林。", "解后如相問，憑君道素心。"]'),
('adbbd68c-64e7-4c6b-8629-8100f4b27d11','五日次韻','林景熙','宋','宋诗','song-poetry','','[]','客鄉吊古重登臨，隔水斜陽鳥語深。',64,'全唐诗/poet.song.242000.json','["客鄉吊古重登臨，隔水斜陽鳥語深。", "賜葛尚餘唐闕夢，傾葵猶抱楚臣心。", "蒲邊臘釀供華髮，楝後春風在綠陰。", "桃印靈符何必佩，乾坤正氣古猶今。"]'),
('a54e72da-b6d9-42bd-9021-a22e49312f3f','酬合沙徐君寅','林景熙','宋','宋诗','song-poetry','','[]','歸鶴悠悠度海遲，閒來野寺看僧棋。',64,'全唐诗/poet.song.242000.json','["歸鶴悠悠度海遲，閒來野寺看僧棋。", "鄉心荔子薰風國，客路槐花細雨時。", "天地一身愁自語，江湖諸老澹相知。", "烏絲醉後淋漓墨，片月娟娟照硯池。"]'),
('fe71675f-7688-49ee-9f9d-a4051e059023','重游鏡曲次韻','林景熙','宋','宋诗','song-poetry','','[]','青眼重逢白髮新，舊游却恐是前身。',64,'全唐诗/poet.song.242000.json','["青眼重逢白髮新，舊游却恐是前身。", "野鳩妬客招呼雨，江燕隨人管領春。", "曾附仙舟追李郭，獨提詩律繼黄陳。", "鏡中恨不移家住，山水蒼蒼老釣綸。"]'),
('f655e44f-9145-4ff8-876c-14f10aaac933','和監簿山中自壽','林景熙','宋','宋诗','song-poetry','','[]','梅傳春信菊延秋，萬壑千巖引勝遊。',64,'全唐诗/poet.song.242000.json','["梅傳春信菊延秋，萬壑千巖引勝遊。", "明月半船招賀監，清風滿袖挹浮丘。", "意閒自得琴書樂，身隠猶懷畎畝憂。", "但得八荒皆壽域，飯疏飲水亦何求。"]'),
('9f7290a3-a312-445c-b160-ac270acde785','立秋日作','林景熙','宋','宋诗','song-poetry','','[]','苦熱如焚想雪山，清商一夕破愁顔。',64,'全唐诗/poet.song.242000.json','["苦熱如焚想雪山，清商一夕破愁顔。", "炎光斷雨殘虹外，凉意平蕪遠樹間。", "忙踏槐花猶入夢，老催蒲扇共投閑。", "城頭遥望纍纍塚，遼海荒寒鶴未還。"]'),
('65b8b6a2-3552-4b6e-8b78-0733318c4897','中秋山中對月','林景熙','宋','宋诗','song-poetry','','[]','收拾山河片影圓，舉杯笑酌結鄰仙。',64,'全唐诗/poet.song.242000.json','["收拾山河片影圓，舉杯笑酌結鄰仙。", "萬家絃管誰無月，一壑樓臺別有天。", "丹桂梯寒醒舊夢，玄霜杵熟授長年。", "此秋此夜無清句，花亦笑人空醉眠。"]'),
('12c6b669-b880-4c9b-ae5d-27a550fcd744','浙中饑甚六月一雨頗慰','林景熙','宋','宋诗','song-poetry','','[]','雨餘燈火坐茅齋，此夕田家有好懷。',64,'全唐诗/poet.song.242000.json','["雨餘燈火坐茅齋，此夕田家有好懷。", "造物心終扶畎畝，蒼生命已墮顛崖。", "燕山漕粟初航海，浙水移家半入淮。", "貞觀三錢誰復識，擁衣數起望台階。"]'),
('5d2b7eec-2828-4fd7-9997-07d4d4571fcc','秋日言懷次韻','林景熙','宋','宋诗','song-poetry','','[]','禹穴風烟老尚游，青門回首憶瓜疇。',64,'全唐诗/poet.song.242000.json','["禹穴風烟老尚游，青門回首憶瓜疇。", "海槎片影星河曙，城角一聲天地秋。", "臨水忽驚餘鬢落，看雲還悟此生浮。", "杖藜擬訪神仙宅，中有長眉不掛愁。"]'),
('b989240d-c75e-4d75-8de5-05ae01fc0350','喜監簿得陶山舜田','林景熙','宋','宋诗','song-poetry','','[]','耕隠山中久卜鄰，愛奇不厭買山勤。',64,'全唐诗/poet.song.242000.json','["耕隠山中久卜鄰，愛奇不厭買山勤。", "重華事往人何在，萬古春深鳥自耘。", "閒拂巖花問陵谷，獨懸茅屋管烟雲。", "滿林剡竹供揮洒，天壽斯文正屬君。"]'),
('29c7688f-ec4b-49a2-8a20-e4c703662d73','別王監簿','林景熙','宋','宋诗','song-poetry','','[]','玄髮相逢雪滿顛，一番欲別一凄然。',64,'全唐诗/poet.song.242000.json','["玄髮相逢雪滿顛，一番欲別一凄然。", "離亭落日馬嘶渡，舊國西風人喚船。", "湖海已空彈鋏夢，山林猶有著書年。", "蓬萊不隔青禽信，還折南枝寄老仙。"]'),
('0b775b86-3a69-4c0a-a9ce-d9cf56eecf8e','次韻謝諸公見壽','林景熙','宋','宋诗','song-poetry','','[]','千載東籬有晉香，客床風雨夢潯陽。',64,'全唐诗/poet.song.242000.json','["千載東籬有晉香，客床風雨夢潯陽。", "白頭湖海孤心在，青眼詩書舊味長。", "哭兀已知懽此厦，溫柔何必老爲鄉。", "殷勤還祝南山壽，歲歲梅花歲歲觴。"]'),
('96f43dcd-4c4a-4a2f-8e14-6263722bd434','訪僧鄰庵次韻','林景熙','宋','宋诗','song-poetry','','[]','拂石題詩滿袖嵐，尋僧又過竹溪南。',64,'全唐诗/poet.song.242000.json','["拂石題詩滿袖嵐，尋僧又過竹溪南。", "乾坤浩蕩酒鄉寄，山水蒼寒琴意參。", "老燕未歸同是客，孤雲無住孰爲庵。", "寂寥午夜松風響，疑是神仙接麈談。"]'),
('96c34f5d-a1fe-47f9-ad91-632e29b4fabc','答金華王玉成','林景熙','宋','宋诗','song-poetry','','[]','詩吞楚澤渺無邊，不用神丹骨已仙。',64,'全唐诗/poet.song.242000.json','["詩吞楚澤渺無邊，不用神丹骨已仙。", "九萬里程驚落羽，三千年事撫遺編。", "銅盤老淚胡笳裏，金粟荒愁杜宇前。", "惟有雙溪溪上月，清光照客尚依然。"]'),
('ea2436bb-c539-4578-a5e6-d19f036ca6c0','送友人孔濟之之金華','林景熙','宋','宋诗','song-poetry','','[]','餘子紛紛氣可吞，青霄萬里合孤騫。',64,'全唐诗/poet.song.242000.json','["餘子紛紛氣可吞，青霄萬里合孤騫。", "藻芹池冷三年客，絲竹堂高幾世孫。", "前輩修名似山斗，斯文清氣在乾坤。", "故人要路如相問，爲說蒼苔獨閉門。"]'),
('203e5c68-e344-4571-80f0-ab1f21104135','述懷次柴主簿','林景熙','宋','宋诗','song-poetry','','[]','獨閉柴門木石親，詩筒剝啄不妨頻。',64,'全唐诗/poet.song.242000.json','["獨閉柴門木石親，詩筒剝啄不妨頻。", "青燈風雨多離夢，白髮江湖少故人。", "謾讀楚騷招太乙，誰聽郢曲和陽春。", "書香劍氣俱寥落，虛老乾坤父母身。"]'),
('b4624968-e4cf-479b-a9fa-e9c384bff594','次曹近山見寄','林景熙','宋','宋诗','song-poetry','','[]','扣角歌殘夜正長，懶將龜筴卜行藏。',64,'全唐诗/poet.song.242000.json','["扣角歌殘夜正長，懶將龜筴卜行藏。", "風烟萬里別離夢，草木一溪文字香。", "仙泣銅盤辭渭水，鶴歸華表認遼陽。", "愁來偶上西樓立，耿耿寒奎色照霜。"]'),
('9c841728-0dff-409b-a143-81ea1106774f','送葉伯幾之奉化','林景熙','宋','宋诗','song-poetry','','[]','親携琴冊出烟蘿，海國儒風近若何。',64,'全唐诗/poet.song.242000.json','["親携琴冊出烟蘿，海國儒風近若何。", "筆挾龍湫靈不盡，官鄰雪竇冷偏多。", "詩書千載關經濟，師友三年要琢磨。", "老去喜逢奎運轉，送君猶拂舊冠峨。"]'),
('9a336c71-fba4-433e-b4a4-2afa2f71ee77','新晴偶出','林景熙','宋','宋诗','song-poetry','','[]','琴床茶鼎澹相依，偶爲尋僧出竹扉。',64,'全唐诗/poet.song.242000.json','["琴床茶鼎澹相依，偶爲尋僧出竹扉。", "風動松枝山鵲語，雪消菜甲野蟲飛。", "看花春入桄榔杖，聽瀑寒生薜荔衣。", "古寺無人雲漠漠，溪行喚得小船歸。"]'),
('e13bdde4-c293-4f2a-81b3-87eeec7ed7d1','題海上人棲雲樓','林景熙','宋','宋诗','song-poetry','','[]','水村烟景隔晴霏，十二闌干在翠微。',64,'全唐诗/poet.song.242000.json','["水村烟景隔晴霏，十二闌干在翠微。", "一壑暮年閒獨倚，半簷秋影澹相依。", "柏爐貝葉香猶潤，紙帳梅花夢不飛。", "會得此中無所住，來來去去總玄機。"]'),
('c4ad5f2d-25fc-4e94-8e97-be9e999ccc23','催梅','林景熙','宋','宋诗','song-poetry','','[]','參橫月落幾相思，第一春風向此期。',64,'全唐诗/poet.song.242000.json','["參橫月落幾相思，第一春風向此期。", "乘興竹筇霜後路，寄聲籬落水邊枝。", "禁中鼓絕花奴老，海上宮深鳥使遲。", "獨抱素心誰是伴，羅浮仙夢隔天涯。"]'),
('dde512c2-4ef4-402d-b68f-b2a14d0f93b3','柳下漁次韻','林景熙','宋','宋诗','song-poetry','','[]','瓦甌一醉萬事了，醒來然竹清溪曉。',96,'全唐诗/poet.song.242000.json','["瓦甌一醉萬事了，醒來然竹清溪曉。", "半蓑烟雨披春寒，堤上落紅已如掃。", "荒磯白鳥無離愁，明月清風滿幽抱。", "却憐灞水長亭西，幾樹柔條不得老。", "漢槎丙穴今已非，網罟相尋縱鱗少。", "何如卷釣兩忘機，魚向樹根吹絮飽。"]'),
('99823213-b308-4326-99b4-ae04a4f7918b','書陸放翁詩卷後','林景熙','宋','宋诗','song-poetry','','[]','天寶詩人詩有史，杜鵑再拜淚如水。',128,'全唐诗/poet.song.242000.json','["天寶詩人詩有史，杜鵑再拜淚如水。", "龜堂一老旗鼓雄，勁氣往往摩其壘。", "輕裘駿馬成都花，冰甌雪椀建溪茶。", "承平麾節半海宇，歸來鏡曲盟鷗沙。", "詩墨淋漓不負酒，但恨未飲月氏首。", "床頭孤劍空有聲，坐看中原落人手。", "青山一髮愁濛濛，干戈况滿天南東。", "來孫却見九州同，家祭如何告乃翁。"]'),
('37bf964d-bd9b-45da-9a95-4ba1a75f4ecc','贈會稽尹醫師','林景熙','宋','宋诗','song-poetry','','[]','相逢湖海說醫靈，學更參玄世味輕。',32,'全唐诗/poet.song.242000.json','["相逢湖海說醫靈，學更參玄世味輕。", "薊子他年游碧落，空留藥市會稽城。"]'),
('03589b24-0aef-4b3e-9454-f3ae26fe51da','汪東巖爲余寫容求贈詩余以其學佛者也故後章及之  其一','林景熙','宋','宋诗','song-poetry','','[]','丰神閒整坐凝然，一笑聊憑筆意傳。',32,'全唐诗/poet.song.242000.json','["丰神閒整坐凝然，一笑聊憑筆意傳。", "却有丹青難畫處，獨遺好醜在千年。"]'),
('39b244ee-8e85-406f-b298-b6b9c3e095ea','汪東巖爲余寫容求贈詩余以其學佛者也故後章及之  其二','林景熙','宋','宋诗','song-poetry','','[]','因形有像轉支離，妙筆從君壓畫師。',32,'全唐诗/poet.song.242000.json','["因形有像轉支離，妙筆從君壓畫師。", "若向禪中參一指，寫余父母未生時。"]'),
('24cf13d6-d048-4bef-91c9-5f20b39b0ff7','夢回','林景熙','宋','宋诗','song-poetry','','[]','夢回荒館月籠秋，何處砧聲喚客愁。',32,'全唐诗/poet.song.242000.json','["夢回荒館月籠秋，何處砧聲喚客愁。", "深夜無風蓮葉響，水寒更有未眠鷗。"]'),
('34d9ae5b-f276-4d70-af23-9d66a68fd5ee','送春','林景熙','宋','宋诗','song-poetry','','[]','蜀魄聲聲訴綠陰，誰家門巷落花深。',32,'全唐诗/poet.song.242000.json','["蜀魄聲聲訴綠陰，誰家門巷落花深。", "遊絲不繫春暉住，愁絕天涯寸草心。"]'),
('fa9059ea-dd92-4f13-8392-aa83871df269','聞蟬二首  其一','林景熙','宋','宋诗','song-poetry','','[]','翼綃微動自宮商，幾曳殘聲送夕陽。',32,'全唐诗/poet.song.242000.json','["翼綃微動自宮商，幾曳殘聲送夕陽。", "喚得槐柯芳夢覺，薰風一曲換西凉。"]'),
('b38bde5b-1b1c-4563-8e9f-4e356cc13ead','聞蟬二首  其二','林景熙','宋','宋诗','song-poetry','','[]','近交紙薄雲翻手，舊夢冠空雪滿顛。',32,'全唐诗/poet.song.242000.json','["近交紙薄雲翻手，舊夢冠空雪滿顛。", "却憶畫船曾聽處，夕陽高柳斷橋邊。"]'),
('e2cde607-2281-4b91-a1f1-003edb007d19','與邵德芳同舍三首  其一','林景熙','宋','宋诗','song-poetry','','[]','聚散雲萍亦偶然，十年曾此繫秋船。',32,'全唐诗/poet.song.242000.json','["聚散雲萍亦偶然，十年曾此繫秋船。", "當時別意芙蓉老，不道相逢又十年。"]'),
('411af487-9bfa-4559-bc0b-7abeb4766789','與邵德芳同舍三首  其二','林景熙','宋','宋诗','song-poetry','','[]','年少同游古辟雍，文光萬丈掃秋虹。',32,'全唐诗/poet.song.242000.json','["年少同游古辟雍，文光萬丈掃秋虹。", "不須舊事談如夢，燈下相看亦夢中。"]'),
('fb885d4a-2cd3-4578-ac41-130bd737aa8f','與邵德芳同舍三首  其三','林景熙','宋','宋诗','song-poetry','','[]','葵心戀日還終在，橘性踰淮已不同。',32,'全唐诗/poet.song.242000.json','["葵心戀日還終在，橘性踰淮已不同。", "誰識鱸江持釣手，曾搴月窟一枝紅。"]'),
('6dc1abbb-89ba-4fc2-9b88-0a7269aa25b0','夢中作四首  其一','林景熙','宋','宋诗','song-poetry','','[]','珠亡忽震蛟龍睡，軒敝寧忘犬馬情。',32,'全唐诗/poet.song.242000.json','["珠亡忽震蛟龍睡，軒敝寧忘犬馬情。", "親拾寒瓊出幽草，四山風雨鬼神驚。"]'),
('3e90227f-c1d5-4603-aee3-6d96ddc19df9','夢中作四首  其二','林景熙','宋','宋诗','song-poetry','','[]','一抔自築珠丘土，雙匣猶傳竺國經。',32,'全唐诗/poet.song.242000.json','["一抔自築珠丘土，雙匣猶傳竺國經。", "獨有春風知此意，年年杜宇泣冬青。"]'),
('0f82dd1f-0002-479d-b36a-cc2c70b59542','夢中作四首  其三','林景熙','宋','宋诗','song-poetry','','[]','昭陵玉匣走天涯，金粟堆前幾吠鴉。',32,'全唐诗/poet.song.242000.json','["昭陵玉匣走天涯，金粟堆前幾吠鴉。", "水到蘭亭轉嗚咽，不知真帖落誰家。"]'),
('6681f26a-980b-4391-a7ec-1cf21f1660a4','夢中作四首  其四','林景熙','宋','宋诗','song-poetry','','[]','珠鳬玉雁又成埃，斑竹臨江首重回。',32,'全唐诗/poet.song.242000.json','["珠鳬玉雁又成埃，斑竹臨江首重回。", "猶憶年時寒食祭，天家一騎捧香來。"]'),
('35dd891a-de9a-465b-9ab9-94ebd9be5dbc','冬青花','林景熙','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u82b1", "\u5199\u82b1"]','冬青花，花時一日腸九折。',76,'全唐诗/poet.song.242000.json','["冬青花，花時一日腸九折。", "隔江風雨清影空，五月深山護微雪。", "石根雲氣龍所藏，尋常螻蟻不敢穴。", "移來此種非人間，曾識萬年觴底月。", "蜀魂飛遶百鳥臣，夜半一聲山竹裂。"]'),
('18445413-6fb0-47b5-ab68-e244f8add7ad','六言  其一','林景熙','宋','宋诗','song-poetry','','[]','沙鷗對立機外，胡蝶相逢夢中。',28,'全唐诗/poet.song.242000.json','["沙鷗對立機外，胡蝶相逢夢中。", "帆去帆來野水，花開花落春風。"]'),
('754f483c-d173-429d-9210-1519f1c73a1d','六言  其二','林景熙','宋','宋诗','song-poetry','','[]','流水獨吟花逕，好山重約雲門。',28,'全唐诗/poet.song.242000.json','["流水獨吟花逕，好山重約雲門。", "茶甌疏竹孤寺，桐角斜陽遠村。"]'),
('829930a2-f101-4149-b668-ce51e441a3c3','讀文山集','林景熙','宋','宋诗','song-poetry','','[]','黑風夜撼天柱折，萬里飛塵九溟竭。',144,'全唐诗/poet.song.242000.json','["黑風夜撼天柱折，萬里飛塵九溟竭。", "誰欲抶之兩腕絕，英淚浪浪滿襟血。", "龍庭戈鋋爛如雪，孤臣生死早已决。", "綱常萬古懸日月，百年身世輕一髮。", "苦寒尚握蘇武節，垂盡猶存杲卿舌。", "膝不可下頭可截，白日不照吾忠切。", "哀鴻上訴天欲裂，一編千載虹光發。", "書生倚劍歌激烈，萬壑松聲助幽咽。", "世間淚洒兒女別，大丈夫心一寸鐵。"]'),
('d7dd83a5-2b03-42e4-8b20-da9f787a5d26','錦屏山','林景熙','宋','宋诗','song-poetry','','[]','錦障鬰嵯峨，秀出城之西。',144,'全唐诗/poet.song.242000.json','["錦障鬰嵯峨，秀出城之西。", "直是神氣積，宛若屏障開。", "蒼翠接重壤，上與浮雲齊。", "幽花被晴壁，古樹欹層崖。", "下有張夫子，讀書事幽棲。", "于今幾百歲，衣冠世多才。", "偉哉據名勝，林泉足徘徊。", "茲晨幸休暇，杖屨同攀躋。", "和風襲輕裾，好鳥鳴喈喈。", "勇往遽忘疲，窮深陟崔嵬。", "極目萬里外，頓覺羣山低。", "長嘯倚蒼松，暢然舒我懷。"]'),
('b4cfa6b6-1bfd-4270-9060-ea286779604a','瑞安院','林景熙','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','倚山寶閣照崔嵬，山鳥山雲自去來。',64,'全唐诗/poet.song.242000.json','["倚山寶閣照崔嵬，山鳥山雲自去來。", "竹籟曉和幽梵合，藤花春入古松開。", "丹空遺竈形難蛻，草暗孤城首重回。", "處士凄凉猶是晉，廬山蓮社許參陪。"]'),
('cb55bf6b-232f-4079-8f1f-2a835c44edcc','知宗柑詩用韻頗險予既知之復取所未用之韻續賦一首三十韻','林景熙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','書閲揚州貢，功觀禹化覃。',288,'全唐诗/poet.song.242000.json','["書閲揚州貢，功觀禹化覃。", "香包分橘柚，秋色動江潭。", "破暑花凝雪，凌寒葉染藍。", "金衣愛日照，珠實碧波涵。", "未止諸侯計，曾聞四皓談。", "顔歡陸績母，業世李衡男。", "送客愈吟桂，書時坡韻儋。", "洞庭夸浙右，溫郡冠江南。", "節物清霜重，家山綠蒂含。", "青黄出籬落，朱綠耀林嵐。", "昔貢千金顆，遥馳萬里函。", "新宜薦寢廟，香可供瞿曇。", "夔子那能比，羅浮未許參。", "何人傳是陸，端類列非聃。", "在品寧爲四，蒙恩或賜三。", "鄉情寄初熟，旅况憶幽探。", "嘉拜親開合，珍藏凈洗甔。", "行將解印綬，歸種當田蠶。", "根向橫陽覓，泥尋斥鹵擔。", "荒蕪耘徑草，封植伴溪柟。", "不用千頭富，聊資一餉湛。", "茅齋闢杜甫，僊井汲蘇耽。", "佳境妙餐蔗，閑庭勝蒔苷。", "雁行三峽荔，奴視四明蚶。"]'),
('b5d21dd8-bdac-404a-9945-2d56ad78f53b','句','林景熙','宋','宋诗','song-poetry','','[]','君不記，犬之年，羊之月，辟歷一聲天地裂。',20,'全唐诗/poet.song.242000.json','["君不記，犬之年，羊之月，辟歷一聲天地裂。"]'),
('40507620-bb78-4fa4-9c6f-1990db335681','題陸秀夫負帝蹈海圖','林景熙','宋','宋诗','song-poetry','','[]','紫宸黄閣共樓船，海氣昏昏日月偏。',64,'全唐诗/poet.song.242000.json','["紫宸黄閣共樓船，海氣昏昏日月偏。", "平地已無行在所，丹心猶數中興年。", "生藏魚腹不見水，死抱龍髯直上天。", "板蕩純臣有如此，流芳千古更無前。"]'),
('e38df1bc-e8f7-4be5-84cb-08d23cf8f20f','偈頌二十三首  其一','釋雲岫','宋','宋诗','song-poetry','','[]','夜半金烏出，寥寥照寰宇。',24,'全唐诗/poet.song.242000.json','["夜半金烏出，寥寥照寰宇。", "兩眼對青山，通身淚如雨。"]'),
('8e0facb5-0c66-46c3-b8a4-9b4b32a14448','偈頌二十三首  其二','釋雲岫','宋','宋诗','song-poetry','','[]','大覺世尊，臘月八夜，子正四刻，覩明星而悟道。',48,'全唐诗/poet.song.242000.json','["大覺世尊，臘月八夜，子正四刻，覩明星而悟道。", "引得後代兒孫，夜半染皁。", "智門昨夜傷風，打嚏湊得恰好。"]'),
('489907fb-f439-4042-bdd8-1c51a1f0156e','偈頌二十三首  其三','釋雲岫','宋','宋诗','song-poetry','','[]','久渴逢甘雨，他鄉見故知。',24,'全唐诗/poet.song.242000.json','["久渴逢甘雨，他鄉見故知。", "洞房花燭夜，金牓狀元歸。"]'),
('784a74e1-6fcb-4290-86d4-80bdcdd238de','偈頌二十三首  其四','釋雲岫','宋','宋诗','song-poetry','','[]','崑崙之水易發，少林之春難芳。',58,'全唐诗/poet.song.242000.json','["崑崙之水易發，少林之春難芳。", "一臂忽斷，九年頓忘。", "雷暈紋於象齒，花釀蜜於蜂房。", "派列枝分兮子孫繁碎，烏非馬似兮言語文章。"]'),
('912310e4-4fb3-4c3e-9345-e45afafbb7c5','偈頌二十三首  其五','釋雲岫','宋','宋诗','song-poetry','','[]','半夜劈破太空，太陽正照白晝。',46,'全唐诗/poet.song.242000.json','["半夜劈破太空，太陽正照白晝。", "掩却萬象生鐵一團，二俱列下別有商量。", "南海觀音菩薩，端坐水月道場。"]'),
('59a290c8-0251-4d18-bcfc-7075800a7f84','偈頌二十三首  其六','釋雲岫','宋','宋诗','song-poetry','','[]','春山疊亂青，春水漾虛碧。',24,'全唐诗/poet.song.242000.json','["春山疊亂青，春水漾虛碧。", "寥寥天地間，獨立望何極。"]'),
('c2ede8d5-cf34-4568-913d-e66b677a9522','偈頌二十三首  其七','釋雲岫','宋','宋诗','song-poetry','','[]','西風凋木葉，蟋蟀啼壞牆。',52,'全唐诗/poet.song.242000.json','["西風凋木葉，蟋蟀啼壞牆。", "明月照破屋，露冷黄金牀。", "藏經一卷，儒書一章。", "讀不成句，書不成行，天空地闊誰商量。"]'),
('77519b8f-3871-42d8-adf4-4ebd8edf6752','偈頌二十三首  其八','釋雲岫','宋','宋诗','song-poetry','','[]','曙色纔分鷄便唱，春風未動鳥先啼。',32,'全唐诗/poet.song.242000.json','["曙色纔分鷄便唱，春風未動鳥先啼。", "一牀胡蝶家家夢，祖意無人肯入思。"]'),
('7ed92974-cc40-41c8-aeb5-1d86a2185403','偈頌二十三首  其九','釋雲岫','宋','宋诗','song-poetry','','[]','左顧右盻，皆我良輔。',36,'全唐诗/poet.song.242000.json','["左顧右盻，皆我良輔。", "雲生兮從龍，風生兮從虎。", "山僧坐繩牀說禪，按拄杖作主。"]'),
('2ead9920-72bf-4683-96cd-dfe064f286a3','偈頌二十三首  其一○','釋雲岫','宋','宋诗','song-poetry','','[]','蟋蟀啼壞牆，蝦蟆叫春水。',24,'全唐诗/poet.song.242000.json','["蟋蟀啼壞牆，蝦蟆叫春水。", "時節使之然，處處聒人耳。"]'),
('fc199dc7-110b-4492-a49d-7d36665804f5','偈頌二十三首  其一一','釋雲岫','宋','宋诗','song-poetry','','[]','一句子，玄中玄，妙中妙。',47,'全唐诗/poet.song.242000.json','["一句子，玄中玄，妙中妙。", "寒暑不相干，陰陽不相到，必竟如何通耗。", "鷺鷥立雪非同色，明月蘆花不似他。"]'),
('2285b020-3ad4-4e6f-b05d-3358938e9205','偈頌二十三首  其一二','釋雲岫','宋','宋诗','song-poetry','','[]','千巖带雪，萬水生冰。',106,'全唐诗/poet.song.242000.json','["千巖带雪，萬水生冰。", "今夜寒極歲極，明朝日新月新。", "山僧禪牀角頭拂子，長時間挂不犯纖塵。", "信手拈來，春回大地。", "展慈容於釋迦老子，收怒氣於金剛眼睛。", "只者一著，最妙最靈。", "今正是時，如何委悉，浩浩塵中尋不見，見無見處却分明。"]'),
('6c95e7dd-d8a2-4e46-b236-d0fc9c221923','偈頌二十三首  其一三','釋雲岫','宋','宋诗','song-poetry','','[]','分歲家貧無可有，白牛牽出爲人烹。',32,'全唐诗/poet.song.242000.json','["分歲家貧無可有，白牛牽出爲人烹。", "堂中不問僧多少，一箇還他一分羹。"]'),
('d3d9d66d-609e-4485-a72c-7c5e286bcc45','偈頌二十三首  其一四','釋雲岫','宋','宋诗','song-poetry','','[]','蕩盡是非窠窟，截斷葛藤露布。',54,'全唐诗/poet.song.242000.json','["蕩盡是非窠窟，截斷葛藤露布。", "今日放開布袋，不要東去西去。", "拗折拄杖，向者裏住。", "碧眼胡僧坐九年，心膽渾如生鐵鑄。"]'),
('784b9eb0-3a28-4920-b439-c7d0939c7c00','偈頌二十三首  其一五','釋雲岫','宋','宋诗','song-poetry','','[]','如來藏中有一常圓之月，大如車輪，冷如冰雪，犀牛扇子何曾別。',66,'全唐诗/poet.song.242000.json','["如來藏中有一常圓之月，大如車輪，冷如冰雪，犀牛扇子何曾別。", "怒濤推出海，恰值中秋節。", "若也喚作白蓮花，浮出龍王宮。", "我道玉川子，胡說亂說。"]'),
('6d674f9e-659f-4988-9f1c-131d4eeb810d','偈頌二十三首  其一六','釋雲岫','宋','宋诗','song-poetry','','[]','達磨眼睛，八斛四斗。',32,'全唐诗/poet.song.242000.json','["達磨眼睛，八斛四斗。", "斷貫索子穿來，諸人面前抖擻，天上人間阿誰有。"]'),
('a9718d25-c92a-4561-a40d-fe6b05e26299','偈頌二十三首  其一七','釋雲岫','宋','宋诗','song-poetry','','[]','意存言外，道在機前。',34,'全唐诗/poet.song.242000.json','["意存言外，道在機前。", "求人思搭對，見面懶寒暄。", "古劍長埋匣，閒弓不上弦。"]'),
('6f926df3-bb61-471e-be0a-07d21779a071','偈頌二十三首  其一八','釋雲岫','宋','宋诗','song-poetry','','[]','流而不返名曰情，湛而不摇名曰性。',48,'全唐诗/poet.song.242000.json','["流而不返名曰情，湛而不摇名曰性。", "靈而不昏名曰神，光而不亂名曰明。", "迷此四者爲之凡，悟此四者爲之聖。"]'),
('dbb349e0-84ca-403e-9e1c-33464ec19e5e','偈頌二十三首  其一九','釋雲岫','宋','宋诗','song-poetry','','[]','天地熱如爐，萬物同一煮。',24,'全唐诗/poet.song.242000.json','["天地熱如爐，萬物同一煮。", "衲僧煮不殺，出來拍手舞。"]'),
('08951f4a-cfa6-461e-899a-dd13d83a47a6','偈頌二十三首  其二○','釋雲岫','宋','宋诗','song-poetry','','[]','海水縮，天風寒。',32,'全唐诗/poet.song.242000.json','["海水縮，天風寒。", "一陽破坤，六陰生乾。", "君子之道日長，小人之道日消。"]'),
('e5d723ff-c5fe-437c-bf36-c3619ab51e7c','偈頌二十三首  其二一','釋雲岫','宋','宋诗','song-poetry','','[]','髮生爪長常如此，筋轉脈摇休問他。',32,'全唐诗/poet.song.242000.json','["髮生爪長常如此，筋轉脈摇休問他。", "動靜不干消長事，從教門外雪寒多。"]'),
('3f1a5137-7b93-4c50-b3bc-2c186fa521c5','偈頌二十三首  其二二','釋雲岫','宋','宋诗','song-poetry','','[]','世尊雙眼明，看天上星。',70,'全唐诗/poet.song.242000.json','["世尊雙眼明，看天上星。", "智門雙眼明，看天上星。", "智門雙眼瞎，世尊雙眼明。", "世尊雙眼瞎，智門雙眼明。", "互復二千年，彼此心不平。", "世尊世尊，今日誰底時節。"]'),
('00bc26b2-96a3-4045-a3fc-33cdc7afec18','偈頌二十三首  其二三','釋雲岫','宋','宋诗','song-poetry','','[]','東邨王老夜燒錢，保當新年勝舊年。',32,'全唐诗/poet.song.242000.json','["東邨王老夜燒錢，保當新年勝舊年。", "三珓俱通三扣齒，太平無事樂平平。"]'),
('30c93aa0-5a64-4302-8ff7-63c59692acd9','頌古十首  其一','釋雲岫','宋','宋诗','song-poetry','','[]','荷葉團團團似鏡，菱角尖尖尖似錐。',32,'全唐诗/poet.song.242000.json','["荷葉團團團似鏡，菱角尖尖尖似錐。", "尀耐古人無意智，預先偷我一聯詩。"]'),
('e2f39a5a-5ad2-4e43-97ea-2bef8e5b0360','頌古十首  其二','釋雲岫','宋','宋诗','song-poetry','','[]','孝滿曹山脫布衣，風流輸與大家兒。',32,'全唐诗/poet.song.242000.json','["孝滿曹山脫布衣，風流輸與大家兒。", "阿爹死了有錢使，醉酒狂歌日日嬉。"]'),
('c71ec720-8ea3-4589-930f-a37917a6cd09','頌古十首  其三','釋雲岫','宋','宋诗','song-poetry','','[]','破燈盞裏已無油，放去光明照九州。',32,'全唐诗/poet.song.242000.json','["破燈盞裏已無油，放去光明照九州。", "暴雨暴風吹滅了，光明不在舊牀頭。"]'),
('36d11f04-5835-4370-b84d-5c312e742531','頌古十首  其四','釋雲岫','宋','宋诗','song-poetry','','[]','有意三迴遭點額，無心一躍過龍門。',32,'全唐诗/poet.song.242000.json','["有意三迴遭點額，無心一躍過龍門。", "歸來冷地思量著，痛處難忘不是恩。"]'),
('6f78f401-6239-4557-876b-a99ea36bd62e','頌古十首  其五','釋雲岫','宋','宋诗','song-poetry','','[]','百尺竿頭親進步，分明一啞更無增。',32,'全唐诗/poet.song.242000.json','["百尺竿頭親進步，分明一啞更無增。", "是誰未到竿頭者，也說鵬飛九萬里。"]'),
('16c4c9b0-a73c-44b1-90fd-111a8bec4586','頌古十首  其六','釋雲岫','宋','宋诗','song-poetry','','[]','打疊行裝早出門，相逢舊友且論文。',32,'全唐诗/poet.song.242000.json','["打疊行裝早出門，相逢舊友且論文。", "歸家共飲三杯酒，不覺天邊日又昏。"]'),
('4533b070-ffdb-4bd9-8c1a-106db3a80a54','頌古十首  其七','釋雲岫','宋','宋诗','song-poetry','','[]','三月春風開牡丹，道人徒說看花還。',32,'全唐诗/poet.song.242000.json','["三月春風開牡丹，道人徒說看花還。", "世間不是趙昌手，縱有丹青畫亦難。"]'),
('e6ceb402-81b7-4c63-8d76-e634a9d85f6c','頌古十首  其八','釋雲岫','宋','宋诗','song-poetry','','[]','良醫捉手病纔分，妙劑投之不易論。',32,'全唐诗/poet.song.242000.json','["良醫捉手病纔分，妙劑投之不易論。", "一服聽他迷悶去，三朝五日自還魂。"]'),
('611d4d46-6ce6-4b82-8d2b-fe299419839a','頌古十首  其九','釋雲岫','宋','宋诗','song-poetry','','[]','真實問安真實答，曾無一句是虛言。',32,'全唐诗/poet.song.242000.json','["真實問安真實答，曾無一句是虛言。", "可憐失却當時意，直至如今話未圓。"]'),
('ea1bdb3c-14f9-4b11-8d46-f9a6082e1db6','頌古十首  其一○','釋雲岫','宋','宋诗','song-poetry','','[]','有道君王傳號令，頻催羯鼓要花開。',32,'全唐诗/poet.song.242000.json','["有道君王傳號令，頻催羯鼓要花開。", "眼頭一曲風光好，日暖鶑聲出谷來。"]'),
('858b6665-8a30-458b-ab80-ae85b8035465','讀本師語錄','釋雲岫','宋','宋诗','song-poetry','','[]','青旗斜出畫橋西，楊柳飛花水滿堤。',32,'全唐诗/poet.song.242000.json','["青旗斜出畫橋西，楊柳飛花水滿堤。", "一酌誤人千日酒，醉埋荒塚不思歸。"]'),
('1787b1aa-d393-44bf-a3d8-115faf9688da','寄陳太傅','釋雲岫','宋','宋诗','song-poetry','','[]','種竹栽花遶屋櫩，交僧也學著偏衫。',32,'全唐诗/poet.song.242000.json','["種竹栽花遶屋櫩，交僧也學著偏衫。", "時清曾見修文日，天子旁搜到傅巖。"]'),
('5a7b0658-ea80-459a-ac89-550319c17055','西庵夜坐','釋雲岫','宋','宋诗','song-poetry','','[]','一室寒燈坐夜長，八千里路到梅陽。',32,'全唐诗/poet.song.242000.json','["一室寒燈坐夜長，八千里路到梅陽。", "西山固不如洋嶼，也道薰風殿閣凉。"]'),
('5a2435e4-40c3-44d1-8e3c-cba69211b087','古月號','釋雲岫','宋','宋诗','song-poetry','','[]','千年桂魄不肯死，夜夜在人頭上飛。',32,'全唐诗/poet.song.242000.json','["千年桂魄不肯死，夜夜在人頭上飛。", "每愛中庭一方白，長天萬里沒雲時。"]'),
('a10c9e3e-de78-486c-87b9-439c1170a188','題梓巖和尚吟卷','釋雲岫','宋','宋诗','song-poetry','','[]','字字不因容易得，燈花曾落五更鐘。',32,'全唐诗/poet.song.242000.json','["字字不因容易得，燈花曾落五更鐘。", "東湖浪闊瓶聲遠，流出一谿霜葉風。"]'),
('9cd5120c-aeae-4263-b03e-556b7a62a373','悼清藏主','釋雲岫','宋','宋诗','song-poetry','','[]','修行衆苦人難到，六指重來火後尋。',32,'全唐诗/poet.song.242000.json','["修行衆苦人難到，六指重來火後尋。", "遺恨百年消不得，一聲杜宇一關心。"]'),
('4e27f0d9-bf46-4d86-a18e-b08ad08f5f9a','秋日山行','釋雲岫','宋','宋诗','song-poetry','','[]','半塢夕陽紅樹葉，一邨鷄犬野人家。',32,'全唐诗/poet.song.242000.json','["半塢夕陽紅樹葉，一邨鷄犬野人家。", "牧童歌笑牛羊下，太古淳風盡屬他。"]'),
('a554a6c2-36c8-492c-80c3-9a7ed44a8c29','問法','釋雲岫','宋','宋诗','song-poetry','','[]','乾陀國裏舊城河，遥憶河邊棗樹花。',32,'全唐诗/poet.song.242000.json','["乾陀國裏舊城河，遥憶河邊棗樹花。", "白象繫來年代遠，榮枯今日事如何。"]'),
('62eff1e8-63f6-4fd0-91e6-20f0c50d183a','金山頭陀巖','釋雲岫','宋','宋诗','song-poetry','','[]','半間石屋安禪地，蓋代功高不易磨。',32,'全唐诗/poet.song.242000.json','["半間石屋安禪地，蓋代功高不易磨。", "白蟒化龍歸海去，山中留得老頭陀。"]'),
('9ca9c194-a5f2-491e-aece-a2a83c552631','鶴林寺','釋雲岫','宋','宋诗','song-poetry','','[]','夾山當日見船子，法眼無瑕亦有瑕。',32,'全唐诗/poet.song.242000.json','["夾山當日見船子，法眼無瑕亦有瑕。", "一棹朱涇風浪急，和根移却杜鵑花。"]'),
('e2fa3004-1498-4963-9f50-3bd406ea5ac6','呈中竺雪屋和尚','釋雲岫','宋','宋诗','song-poetry','','[]','重重法界華嚴境，煙柳滿城春正深。',32,'全唐诗/poet.song.242000.json','["重重法界華嚴境，煙柳滿城春正深。", "彈指門開相見後，善財灰盡一生心。"]'),
('c53387f8-1d77-4e20-bce6-8695866f1bdd','訪友人庵居','釋雲岫','宋','宋诗','song-poetry','','[]','好山行盡眼重開，菜葉流金逐水來。',32,'全唐诗/poet.song.242000.json','["好山行盡眼重開，菜葉流金逐水來。", "莫謂閒門容易掩，松邊有路不生苔。"]'),
('9911ca78-2837-4438-8049-86688201b66b','蜾蠃','釋雲岫','宋','宋诗','song-poetry','','[]','借得桑蟲足子孫，聲聲類我祝朝昏。',32,'全唐诗/poet.song.242000.json','["借得桑蟲足子孫，聲聲類我祝朝昏。", "只因祝得渾相似，代代不能高戶門。"]'),
