('7ba57e99-7476-4ee3-9301-5830d341efe9','題汶藏主行卷','釋雲岫','宋','宋诗','song-poetry','','[]','玲瓏巖畔看雲處，帢幘峰頭步月時。',32,'全唐诗/poet.song.242000.json','["玲瓏巖畔看雲處，帢幘峰頭步月時。", "一句庭前柏樹子，何曾吟作五言詩。"]'),
('b1a5dec8-29dc-41d1-9af1-e633e09a5c8f','寄昌化治平和尚','釋雲岫','宋','宋诗','song-poetry','','[]','老來長憶唐昌寺，剃髮染衣情未磨。',32,'全唐诗/poet.song.242000.json','["老來長憶唐昌寺，剃髮染衣情未磨。", "萬疊山高雙澗急，仲宣樓上月明多。"]'),
('0b6fe459-1ecc-41ad-91b8-f5c12d46b74c','百舌','釋雲岫','宋','宋诗','song-poetry','','[]','尋常多逐衆禽飛，纔得春風百樣啼。',32,'全唐诗/poet.song.242000.json','["尋常多逐衆禽飛，纔得春風百樣啼。", "毛羽不佳讒舌便，桃花枝上駡黄鸝。"]'),
('eca15c5a-e70b-4308-8a43-cd2ae1abd96e','寄五師北山講主','釋雲岫','宋','宋诗','song-poetry','','[]','一書不問不相違，指迹慕歸誰救遲。',32,'全唐诗/poet.song.242000.json','["一書不問不相違，指迹慕歸誰救遲。", "鶑脰湖邊官驛路，舟車十里到鳬磯。"]'),
('9e717644-bd47-4229-b522-68aaefcae2dc','楚心蓀維那','釋雲岫','宋','宋诗','song-poetry','','[]','千載騷人沉骨冷，冰霜葉底見幽香。',32,'全唐诗/poet.song.242000.json','["千載騷人沉骨冷，冰霜葉底見幽香。", "乾坤一種忠良氣，彈壓春風衆草芳。"]'),
('ef912255-bd52-483d-a56c-2451e585e411','答法華東洲和尚','釋雲岫','宋','宋诗','song-poetry','','[]','干戈倒用識安危，方便垂慈接箇誰。',32,'全唐诗/poet.song.242000.json','["干戈倒用識安危，方便垂慈接箇誰。", "每每見僧陪面笑，祖師門戶放教低。"]'),
('648e9d85-cc24-452a-b51e-d5e0d73162aa','答源侍者','釋雲岫','宋','宋诗','song-poetry','','[]','鐵航未肯下滄海，消息無端忽寄來。',32,'全唐诗/poet.song.242000.json','["鐵航未肯下滄海，消息無端忽寄來。", "六載雪山明底事，不知己眼爲誰開。"]'),
('be501b2c-4b26-4917-87b2-e25e80c6a507','病起','釋雲岫','宋','宋诗','song-poetry','','[]','病起稜層骨數莖，盡情提挈强爲生。',32,'全唐诗/poet.song.242000.json','["病起稜層骨數莖，盡情提挈强爲生。", "思量襏襫當年事，道在大雄山上行。"]'),
('d331d39b-4b70-4e23-addf-631a5c02df09','憶錢塘','釋雲岫','宋','宋诗','song-poetry','','[]','初心未歇憶錢塘，不爲閒遊再渡江。',32,'全唐诗/poet.song.242000.json','["初心未歇憶錢塘，不爲閒遊再渡江。", "自恨一生多癖病，四明山好懶開窗。"]'),
('381cb6dc-b91d-434c-b208-23847878b7a6','與大知客','釋雲岫','宋','宋诗','song-poetry','','[]','趙州道個喫茶去，一滴何曾濕口唇。',32,'全唐诗/poet.song.242000.json','["趙州道個喫茶去，一滴何曾濕口唇。", "到此果能相見得，不妨全主更全賓。"]'),
('a73abdc1-ed25-4ee5-854f-ee2696b23d32','憶母二首  其一','釋雲岫','宋','宋诗','song-poetry','','[]','胞衣瓶葬海南邊，匝地鯨波到眼前。',32,'全唐诗/poet.song.242000.json','["胞衣瓶葬海南邊，匝地鯨波到眼前。", "有例可攀心未穩，蒲鞋賣不直多錢。"]'),
('5f9dade3-a983-4055-aa9e-709c677ce3df','憶母二首  其二','釋雲岫','宋','宋诗','song-poetry','','[]','天不高兮海不深，白雲飛處定關心。',32,'全唐诗/poet.song.242000.json','["天不高兮海不深，白雲飛處定關心。", "蒲鞋難上時人眼，那更西風葉落金。"]'),
('91e13f0f-918a-43cb-9cba-0bc797fd3f35','哭雲外老人','釋慧日','宋','宋诗','song-poetry','','[]','水天空闊竟忘遥，太白巍巍望九霄。',32,'全唐诗/poet.song.242000.json','["水天空闊竟忘遥，太白巍巍望九霄。", "面目儼然雲雨外，孰云生死不同條。"]'),
('adffc7a5-9e0e-436a-aee7-faafb36864c1','擬古  其一','黄庚','宋','宋诗','song-poetry','','[]','畹中有幽蘭，風露飽清抱。',48,'全唐诗/poet.song.242000.json','["畹中有幽蘭，風露飽清抱。", "含章不求聞，坐見九秋老。", "夫君日已遠，佩飾爲誰好。", "何如歛餘芳，山林養枯槁。"]'),
('995f6fb6-e765-4527-9ea7-a6a9f78dd30d','擬古  其二','黄庚','宋','宋诗','song-poetry','','[]','驪龍有明珠，奇氣久磅礴。',60,'全唐诗/poet.song.242000.json','["驪龍有明珠，奇氣久磅礴。", "一爲鮫人采，夜半泣海若。", "至寶諒難得，珍藏思遠託。", "如何賤所貴，用之以彈雀，彈雀亦何惜，一去恐流落。"]'),
('a5e7001b-c368-4fb9-9206-bdd37b31a552','擬古  其三','黄庚','宋','宋诗','song-poetry','','[]','名門有貞女，始結絲蘿盟。',60,'全唐诗/poet.song.242000.json','["名門有貞女，始結絲蘿盟。", "嬿婉席未溫，良人已遠行。", "遠行何時歸，妾身不自輕。", "空幃守寂寞，誓以終此生。", "雖云受恩淺，耿耿懷至情。"]'),
('572d3208-ff2b-4ca3-abb5-4f7757b25593','擬古  其四','黄庚','宋','宋诗','song-poetry','','[]','山中怪物變，草木自四時。',60,'全唐诗/poet.song.242000.json','["山中怪物變，草木自四時。", "秋水照短髮，血氣日已衰。", "寒藤不知枯，青青上疏籬。", "繁陰縱有托，已迫風霜期。", "餘生方自憐，孤吟欲何爲。"]'),
('c7f885d1-c28c-44e3-8890-751e4cd66ebc','擬古  其五','黄庚','宋','宋诗','song-poetry','','[]','徂徠有嘉木，薿薿高連天。',84,'全唐诗/poet.song.242000.json','["徂徠有嘉木，薿薿高連天。", "修柯濯雨露，沃葉藏雲烟。", "根蟠九地暖，聲落四壁寒。", "由來所養□，不與春相干。", "歲久産茯苓，玉色腴且堅。", "山人劚爲藥，至味通靈仙。", "願言事服餌，身可三千年。"]'),
('73cb903a-47e1-41e3-81ad-de9c2d07bdce','旦景','黄庚','宋','宋诗','song-poetry','','[]','雞鳴起濯髮，披衣出戶牖。',48,'全唐诗/poet.song.242000.json','["雞鳴起濯髮，披衣出戶牖。", "自汲古澗泉，落月猶在手。", "三潄吞朝霞，餘光散花柳。", "茲意難語人，延竚忽良久。"]'),
('2946a78c-44a0-4139-a3d9-750a5fac585c','至後','黄庚','宋','宋诗','song-poetry','','[]','道人坐茅宇，獨抱無絃琴。',72,'全唐诗/poet.song.242000.json','["道人坐茅宇，獨抱無絃琴。", "對此景物變，夕雲散還陰。", "雨氣一簾潤，雲意千山深。", "新陽暢微暄，疏花點孤林。", "芳時坐消歇，孰同歲寒心。", "孤梅發清夜，庭樹驚棲禽。"]'),
('c487aecb-7055-481d-af1c-7672b5dd251f','故相賈秋壑舊府','黄庚','宋','宋诗','song-poetry','','[]','當年搆華屋，權勢傾衛霍。',120,'全唐诗/poet.song.242000.json','["當年搆華屋，權勢傾衛霍。", "堂宇窮斧斤，天氣煥丹雘。", "花石擬平泉，水陸致茲壑。", "惟聞丞相嗔，肯後天下樂。", "朱門鎖荆榛，花木已蕭索。", "蒼生顛墮崖，國亡身孰托。", "空悲上蔡犬，不返華表鶴。", "丈夫表勳名，風采照麟閣。", "故爲一聲鉦，聚鐵鑄此錯。", "回頭暮烟昏，不能掩餘怍。"]'),
('8b3b1a25-761e-49eb-b461-3df2331e3537','九日會王修竹西樓預坐者七人以落霞與孤鶩齊飛分韻予得落字即席走筆','黄庚','宋','宋诗','song-poetry','','[]','冉冉五雲深，山西日光薄。',96,'全唐诗/poet.song.242000.json','["冉冉五雲深，山西日光薄。", "登樓集羣賢，縱目天宇廓。", "落木悲徂年，寒光照杯酌。", "浩歌興悠然，意行非澗壑。", "緬懷龍山遊，此樂久寂寞。", "胡爲落帽人，白首戀賓幕。", "醉餘發詩情，分韻盡佳作。", "吾愛漉酒巾，西風吹不落。"]'),
('df3e37d4-b979-4020-adf0-1d6c30f5b8ae','綠珠','黄庚','宋','宋诗','song-poetry','','[]','娉婷名家姝，榮顯晉朝使。',72,'全唐诗/poet.song.242000.json','["娉婷名家姝，榮顯晉朝使。", "斛珠不論貲，得備巾櫛侍。", "一笑金谷春，粉黛皆歛避。", "豈知步障中，乃復爲愁地。", "念主愛妾深，因妾爲主累。", "□樓風月愁，殘花抱春墜。"]'),
('7de26882-e7ef-4980-806e-8555a3e5065d','燕子樓','黄庚','宋','宋诗','song-poetry','','[]','繁華隨逝水，日暮高樓空。',72,'全唐诗/poet.song.242000.json','["繁華隨逝水，日暮高樓空。", "哀哀徐陵妾，事主不及終。", "空房輟膏沐，明粧爲誰容。", "春風燕子來，秋風燕子去。", "去來影带雙，孤鸞抱憔悴。", "回首醉嬌時，百花不敢媚。"]'),
('5864429e-b9e8-4ae9-9255-ddb1fe33a459','潘淑妃','黄庚','宋','宋诗','song-poetry','','[]','二八入宮掖，一笑輕三千。',72,'全唐诗/poet.song.242000.json','["二八入宮掖，一笑輕三千。", "雲階渺何許，步步生金蓮。", "繡鞋不勝春，風若凌波仙。", "榮華一回首，荆棘生我前。", "君恩花上露，妾心井中泉。", "井泉誓不波，下照青青天。"]'),
('600e070c-3e1f-4f65-a79d-89f71fbb6380','秋胡妻','黄庚','宋','宋诗','song-poetry','','[]','陌上桑葉稀，家中蠶正饑。',72,'全唐诗/poet.song.242000.json','["陌上桑葉稀，家中蠶正饑。", "妾心知採桑，安知使君誰。", "結髮爲人婦，幾年守空幃。", "婦義不移天，黄金欲何爲。", "老姑倚門久，不待盈筐歸。", "爲妾謝使君，風化關庭闈。"]'),
('073f5aeb-2a8b-43c8-9187-e356bfa9d7be','紀夢是歲太旱','黄庚','宋','宋诗','song-poetry','','[]','老年屏人事，北窗寄高眠。',180,'全唐诗/poet.song.242000.json','["老年屏人事，北窗寄高眠。", "夢魂御風去，金闕開九天。", "虎豹獰不嗔，知予有仙緣。", "玉座擁五雲，香爐飛紫烟。", "青衣兩童子，舉手導我前。", "下土蟣虱臣，愚衷欲敷宣。", "兵戈幸休息，饑饉方連綿。", "洪惟大生德，實司水旱權。", "願言回哀眷，與世解倒懸。", "玉帝允臣請，乃曰賜豐年。", "再拜謝闕下，回飈墮林泉。", "夜雷聲殷殷，甘澤朝滿田。", "沉思喜且驚，異夢非偶然。", "士懷當世憂，□□□□□。", "貞觀有房杜，斗米三文錢。"]'),
('4b0b3dc7-15f5-4e8e-ba8c-b078f84987a5','病後謝友人顧問','黄庚','宋','宋诗','song-poetry','','[]','索居坐孤陋，却掃甘隠淪。',216,'全唐诗/poet.song.242000.json','["索居坐孤陋，却掃甘隠淪。", "荒徑無轍迹，蓬藋方蓁蓁。", "風雨撼四壁，一榻寄屈伸。", "誰念相如病，豈堪原憲貧。", "友人隔河梁，懷思賦停雲。", "柴車忽過我，問勞何殷勤。", "促膝話契闊，道合情更親。", "語言邁流俗，意氣含至真。", "情懷談不盡，澣我胸中塵。", "盤蔬與束脯，草草爲爾陳。", "瓦盆煮新酒，味有太古春。", "非徒洗磈磊，亦足消鬰陻。", "北窗坐終日，薄暝生秋旻。", "斜陽戀客影，把袂不忍分。", "此去歲月邁，何時復相親。", "我輩重道義，勢利何足云。", "榮華易消歇，德齒久彌新。", "願言保名節，努力配古人。"]'),
('8d6b77c3-0a8c-4613-95ac-67621f035600','遊謝仙巖飛霞觀巖下李參政墓','黄庚','宋','宋诗','song-poetry','','[]','鬼工鑿山骨，何年驅六丁。',156,'全唐诗/poet.song.242000.json','["鬼工鑿山骨，何年驅六丁。", "飛霞邊石洞，縹緲開珠庭。", "永懷謝仙伯，坐斷山水城。", "我來事幽雅，登臨委客情。", "松風驅溽暑，自覺毛骨清。", "猿鶴亦仙意，人生空營營。", "石麟卧荒草，問是誰家塋。", "野老對我言，其人昔公卿。", "金玉埋黄壤，送日冠蓋傾。", "興衰變百年，所重非脩名。", "乃知鐘鼎貴，不如芝薇馨。", "所以世外人，返老還孩嬰。", "倚杖空歎息，洞口雲冥冥。"]'),
('c81a99cc-de51-4431-ab0a-9261f5f971b2','約王琴所不來舟中偶成','黄庚','宋','宋诗','song-poetry','','[]','清飈捲炎埃，碧水出秋素。',84,'全唐诗/poet.song.242000.json','["清飈捲炎埃，碧水出秋素。", "迢迢見山亭，回首隔烟霧。", "酒帘颺漁村，笳鼓響軍戍。", "倚蓬問舟人，云是三江路。", "籬落雞欲棲，野水牛已渡。", "釣翁炊荻烟，稚子收漁具。", "抱琴人不來，殘陽在高樹。"]'),
('aafb5ede-8838-48f2-bf90-b95516b513f1','種松','黄庚','宋','宋诗','song-poetry','','[]','去年種松樹，未有蒿與蓬。',48,'全唐诗/poet.song.242000.json','["去年種松樹，未有蒿與蓬。", "今年松漸長，埋沒蓬蒿中。", "老髯何蒼蒼，歲華不改容。", "回視蒿與蓬，零落悲秋風。"]'),
('5e668e43-620f-4204-8fb2-3b512bf17b23','題三月梅花卷','黄庚','宋','宋诗','song-poetry','','[]','紛紛姚魏家，顔色競嫵媚。',60,'全唐诗/poet.song.242000.json','["紛紛姚魏家，顔色競嫵媚。", "人方眩春華，東皇出古意。", "素花飾鼎實，縞袂立蒼翠。", "猶如喧啾中，孤鳳忽呈瑞。", "巋然山林尊，坐使衆芳愧。"]'),
('8b47035e-24fa-44a6-a1e4-598fb90814f7','讀文丞相吟嘯稿','黄庚','宋','宋诗','song-poetry','','[]','垂垂大厦顛，一木支無力。',60,'全唐诗/poet.song.242000.json','["垂垂大厦顛，一木支無力。", "精衛悲滄海，銅駝化荆棘。", "英風傲几砧，濱死猶鐵脊。", "血洒沙場秋，寒日赤爲碧。", "惟留吟嘯編，千載光奕奕。"]'),
('94960362-b57a-4bd1-85b7-72dca83a4b4e','雲間有懷','黄庚','宋','宋诗','song-poetry','','[]','風流懷二陸，才名動三吳。',132,'全唐诗/poet.song.242000.json','["風流懷二陸，才名動三吳。", "荒塚今何許，千載空烟蕪。", "當時逞文筆，萬象爭先驅。", "有如明月璧，美價傾鴻都。", "古運有翻覆，韞匵空良圖。", "惜哉去就輕，喪此千金軀。", "人生各有死，百年同須臾。", "獨遺文字芳，乃與天壤俱。", "凄凄九山塞，冉冉谷水枯。", "白鶴久已寂，黄犬不復呼。", "斯人今已矣，弔古空嗟吁。"]'),
('8b988a5f-91a5-4394-a365-8d2da395d908','偶書  其一','黄庚','宋','宋诗','song-poetry','','[]','百歲集孤夜，山樓起呼月。',60,'全唐诗/poet.song.242000.json','["百歲集孤夜，山樓起呼月。", "秋蟲聲轉悲，感此衆芳歇。", "人身非金石，青鬢忽已雪。", "逾淮橘心秋，出山泉水汩。", "猗蘭抱香死，不受蓁莽沒。"]'),
('96460b53-aca8-48c9-876f-cfbdcc616af8','偶書  其二','黄庚','宋','宋诗','song-poetry','','[]','鳳德嗟已衰，宣尼欲浮海。',72,'全唐诗/poet.song.242000.json','["鳳德嗟已衰，宣尼欲浮海。", "頼有載道經，神功補元宰。", "刪詩挽風變，繫易憂世駭。", "春秋筆削嚴，西秦書乃來。", "微義將誓周，逆悲大運改。", "悠悠千古心，死後文書在。"]'),
('e72ae446-b485-4879-ad6c-0f77b56f4665','古意','黄庚','宋','宋诗','song-poetry','','[]','庭前有高樹，風撓無停枝。',72,'全唐诗/poet.song.242000.json','["庭前有高樹，風撓無停枝。", "寒鴉噤不鳴，夜半環樹飛。", "托身未得所，三匝情依依。", "高飛犯霜露，低飛觸茅茨。", "乾坤豈不容，振羽將安之。", "徘徊戀明月，顧影徒傷悲。"]'),
('7b8c24bb-218d-4512-9403-1788e249dec4','感懷','黄庚','宋','宋诗','song-poetry','','[]','入山採芝薇，豺虎據我丘。',72,'全唐诗/poet.song.242000.json','["入山採芝薇，豺虎據我丘。", "入海尋蓬萊，鯨鯢掀我舟。", "山海俱有礙，瞻望凝遠愁。", "乾坤如許大，此身常浮漚。", "依托豈無地，皇皇將安求。", "何當跨鳳鵬，相從安期遊。"]'),
('71463b67-8142-4494-a52c-32fcae51a9c1','漁隠爲周仲明賦','黄庚','宋','宋诗','song-poetry','','[]','一笠戴春雨，扁舟寄此情。',48,'全唐诗/poet.song.242000.json','["一笠戴春雨，扁舟寄此情。", "世間塵網密，江上釣絲輕。", "不羨魚蝦利，惟尋鷗鷺盟。", "狂奴臺下水，猶作漢時清。"]'),
('26d638d1-a109-4e35-96bd-7138398a7d1e','九日偶書','黄庚','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','水國雁已到，山籬菊未開。',48,'全唐诗/poet.song.242000.json','["水國雁已到，山籬菊未開。", "判吹頭上帽，莫放手中杯。", "暮雨滕王閣，西風項羽臺。", "人生能幾屐，餘恨付蒼苔。"]'),
('df9dfffe-c874-44dd-9080-3412216ed5ff','秋晚山行','黄庚','宋','宋诗','song-poetry','','[]','鏗然短策聲，無事覺身輕。',48,'全唐诗/poet.song.242000.json','["鏗然短策聲，無事覺身輕。", "落葉山行輭，流泉澗飲清。", "蟹痕沙露濕，雁影夕陽明。", "歸路逢林叟，班荆歃隠盟。"]'),
('0676d8ce-ea1b-44b0-a7ed-2e43bcb7fc69','夜坐即事','黄庚','宋','宋诗','song-poetry','','[]','對景坐清夜，蕭然鬢已華。',48,'全唐诗/poet.song.242000.json','["對景坐清夜，蕭然鬢已華。", "詩慳難就稿，燈暗不成花。", "易醉愁邊酒，頻歸夢裏家。", "何時鋤舊圃，學種邵平瓜。"]'),
('5a14e349-3165-4ca5-9faa-99cb582a77e3','禹廟送春','黄庚','宋','宋诗','song-poetry','','[]','鼓歌滿湖濱，傾城出送春。',48,'全唐诗/poet.song.242000.json','["鼓歌滿湖濱，傾城出送春。", "波光明畫艇，山色醉遊人。", "禹穴靈何在，梅梁迹已陳。", "我來閒弔古，回首一沾巾。"]'),
('2786b33d-77ad-4eda-b0c8-ab2458c7b42d','晚窗即事','黄庚','宋','宋诗','song-poetry','','[]','一枕紗窗下，池塘草夢殘。',48,'全唐诗/poet.song.242000.json','["一枕紗窗下，池塘草夢殘。", "炷雲金鴨暖，滴露玉蜍寒。", "晉帖從頭寫，唐詩著眼看。", "晚來吟思倦，和月凭闌干。"]'),
('2b06267d-b841-498f-9a0c-ff3fd6089405','幽居','黄庚','宋','宋诗','song-poetry','','[]','幽居少塵事，贏得一身閑。',48,'全唐诗/poet.song.242000.json','["幽居少塵事，贏得一身閑。", "竹屋無人到，柴門盡日關。", "斜陽明晚浦，落葉瘦秋山。", "隔水雙飛鷺，忘機自往還。"]'),
('e8377154-9e7e-482c-8ace-7230d52a5abe','宿龍瑞山房次周雲隠韻','黄庚','宋','宋诗','song-poetry','','[]','木葉秋容瘦，客懷思故鄉。',48,'全唐诗/poet.song.242000.json','["木葉秋容瘦，客懷思故鄉。", "淡雲微見月，薄露不成霜。", "忽忽朱顔改，悠悠白日長。", "空心仍獨夜，減盡昔年狂。"]'),
('2f41aeff-6178-4ed7-a114-1827ac7c9c71','寄表兄王升之','黄庚','宋','宋诗','song-poetry','','[]','客袂臨分日，楊花落酒邊。',48,'全唐诗/poet.song.242000.json','["客袂臨分日，楊花落酒邊。", "重來期半月，一去忽經年。", "莎草平詩屋，江潮沒釣船。", "何時歸舊隠，風雨對床眠。"]'),
('798b3232-4bba-46f2-87a4-8b2a794701fe','翠峰庵即事','黄庚','宋','宋诗','song-poetry','','[]','竟日尋幽處，杖藜不憚遥。',48,'全唐诗/poet.song.242000.json','["竟日尋幽處，杖藜不憚遥。", "客行黄葉路，僧立碧溪橋。", "巖瀑飛寒雪，松風吼夜潮。", "是山皆可隠，何用楚辭招。"]'),
('7861085c-9167-4752-b4a6-e2d752ba4424','王修竹館舍即事','黄庚','宋','宋诗','song-poetry','','[]','池館翠深處，寬閒稱客居。',48,'全唐诗/poet.song.242000.json','["池館翠深處，寬閒稱客居。", "未仙猶閬苑，不夢亦華胥。", "竹凈堪居鶴，荷香欲醉魚。", "心清無箇事，長日一編書。"]'),
('bfa5de41-1d41-477b-a3c5-b1a20d31f27b','寄雲谷王府判','黄庚','宋','宋诗','song-poetry','','[]','曾記還家日，重來約夏初。',48,'全唐诗/poet.song.242000.json','["曾記還家日，重來約夏初。", "自從一別後，又是十年餘。", "原憲非關病，嵇康懶讀書。", "無從問消息，近况果何如。"]'),
('3b3196f1-a38d-4e19-a9a1-ea6ba4c9b016','餞越守','黄庚','宋','宋诗','song-poetry','','[]','旌旆漲天飛，江山慘夕暉。',48,'全唐诗/poet.song.242000.json','["旌旆漲天飛，江山慘夕暉。", "傾城餞州牧，別淚點朝衣。", "人指生祠說，春隨祖帳歸。", "自來言越瘠，公去轉難肥。"]'),
('ca7f459d-08bf-44d9-9aa5-c47079a0443a','別山陰諸友','黄庚','宋','宋诗','song-poetry','','[]','好風殘臘盡，春意動園林。',48,'全唐诗/poet.song.242000.json','["好風殘臘盡，春意動園林。", "柳色獨青眼，梅花同素心。", "江湖方轉徙，歲月自侵尋。", "忍別山陰去，徘徊憶舊吟。"]'),
('d8079a85-ee6c-4ddf-aed3-b49190269764','贈葛秋巖時寓能仁蘭若','黄庚','宋','宋诗','song-poetry','','[]','蘭若分清隠，秋窗飽看山。',48,'全唐诗/poet.song.242000.json','["蘭若分清隠，秋窗飽看山。", "風霜雙鬢老，天地一身閒。", "拄杖穿雲去，吟囊貯月還。", "詩成誰與語，時訪竹林間。"]'),
('43618fe7-ee6b-49b0-82bb-68b57657a532','書懷','黄庚','宋','宋诗','song-poetry','','[]','平生湖海氣，老去歎飄蓬。',48,'全唐诗/poet.song.242000.json','["平生湖海氣，老去歎飄蓬。", "知命難求富，安貧不送窮。", "江空思捉月，天闊欲行風。", "俗眼從渠白，無人識此翁。"]'),
('2b9099e7-1cb4-4151-a7a0-9f51a7c52b3b','寄菊坡吳府判','黄庚','宋','宋诗','song-poetry','','[]','客懷元自惡，非是爲秋悲。',48,'全唐诗/poet.song.242000.json','["客懷元自惡，非是爲秋悲。", "一別又三載，百年能幾時。", "音書無雁寄，心事有鷗知。", "遥想菊坡菊，西風香滿籬。"]'),
('a6544473-d0d2-42cf-955b-79d0122e5398','夜坐即事呈修竹監簿','黄庚','宋','宋诗','song-poetry','','[]','一室冷於冰，秋高夜氣清。',48,'全唐诗/poet.song.242000.json','["一室冷於冰，秋高夜氣清。", "月窗攙燭影，風葉亂琴聲。", "寡慾知身健，安貧覺累輕。", "吟邊閑倚竹，誰識此時情。"]'),
('9cdc00b8-0cd4-4e33-ae71-509f2d06aff9','晚春即事','黄庚','宋','宋诗','song-poetry','','[]','園林芳事歇，風雨暗荒城。',48,'全唐诗/poet.song.242000.json','["園林芳事歇，風雨暗荒城。", "轉眼青春過，臨頭白髮生。", "啼鵑亡國恨，歸鶴故鄉情。", "三徑多荒草，東還計未成。"]'),
('14e49e4b-286d-42ba-9b36-d12b29097cec','登寶林佛閣次韻','黄庚','宋','宋诗','song-poetry','','[]','曳杖陟高閣，登臨思渺然。',48,'全唐诗/poet.song.242000.json','["曳杖陟高閣，登臨思渺然。", "閑身空歲月，老眼幾山川。", "落照明秋浦，飛帆濕暮煙。", "倚閣悵今昔，餘恨付吟篇。"]'),
('5dc72dbe-882e-4540-af0e-ea6973589a69','夜坐讀書','黄庚','宋','宋诗','song-poetry','','[]','寂寞寒窗下，觀書勝苦吟。',48,'全唐诗/poet.song.242000.json','["寂寞寒窗下，觀書勝苦吟。", "青燈風雪夜，黄卷聖賢心。", "吾道關興廢，斯文幾古今。", "鳳兮胡不至，三歎淚沾襟。"]'),
('a2e1580a-5c39-4a8b-91e3-0c5f07ddd701','春日西園晚步','黄庚','宋','宋诗','song-poetry','','[]','爲愛園林好，支筇伴獨行。',48,'全唐诗/poet.song.242000.json','["爲愛園林好，支筇伴獨行。", "花香能醉蝶，柳色欲迷鶑。", "但得青春在，何妨白髮生。", "斜陽紅盡處，一抹暮山橫。"]'),
('f237b387-c575-4786-9275-7a549727c022','書所寓','黄庚','宋','宋诗','song-poetry','','[]','不厭茅廬小，栖栖寄此身。',48,'全唐诗/poet.song.242000.json','["不厭茅廬小，栖栖寄此身。", "菊殘如倦客，梅瘦似詩人。", "有地堪藏拙，無醫可療貧。", "并州故鄉夢，長憶鑑湖春。"]'),
('8151070f-7646-47e0-adf7-dd9e84910b26','書懷寄呈諸友','黄庚','宋','宋诗','song-poetry','','[]','寂寞茅簷下，窮居更待時。',48,'全唐诗/poet.song.242000.json','["寂寞茅簷下，窮居更待時。", "吾儕貧可忍，餘子俗難醫。", "風月最宜酒，江山多是詩。", "廣文無鄭老，誰與共襟期。"]'),
('429f297c-59b7-4762-89e6-16f3bba07a8a','題義上人清虛閣','黄庚','宋','宋诗','song-poetry','','[]','偶來成一宿，便覺與禪通。',48,'全唐诗/poet.song.242000.json','["偶來成一宿，便覺與禪通。", "看塔月影盡，捲簾秋色空。", "因知釋氏學，亦有晉人風。", "吟到忘言處，悠然此意同。"]'),
('a943a565-8cc2-452a-9cad-14e1c458bbea','秋夕和呂講師韵','黄庚','宋','宋诗','song-poetry','','[]','誰彈招隠操，雲外伴清幽。',48,'全唐诗/poet.song.242000.json','["誰彈招隠操，雲外伴清幽。", "午夜山林月，一花天地秋。", "經窗凉影淡，禪榻古香浮。", "不作蟾宮夢，悽然憶舊遊。"]'),
('2b4d0bde-4af5-44ad-9f7e-8b1850c7e9ac','偶書','黄庚','宋','宋诗','song-poetry','','[]','豪氣消磨盡，携書客海濱。',48,'全唐诗/poet.song.242000.json','["豪氣消磨盡，携書客海濱。", "文章難遇主，天地不憐貧。", "家累依劉表，妻兒笑買臣。", "彼蒼還可問，吾道幾時春。"]'),
('901ed420-3def-413d-9372-acac9ca5de68','九日','黄庚','宋','宋诗','song-poetry','','[]','萸節今朝是，秋光又一年。',48,'全唐诗/poet.song.242000.json','["萸節今朝是，秋光又一年。", "但教樽有酒，休問篋無錢。", "白髮羞唐帽，黄花識晉賢。", "龍山渺何許，回首思凄然。"]'),
('1ea0dedc-c9f2-427d-bcab-9437e1c73866','送別胡汲古','黄庚','宋','宋诗','song-poetry','','[]','自憐身是客，又送客登舟。',48,'全唐诗/poet.song.242000.json','["自憐身是客，又送客登舟。", "雖有重來約，難禁一別愁。", "風烟迷柳驛，草樹暗春洲。", "後夜懷人處，山空月滿樓。"]'),
('accf5716-f419-4347-8259-194cc1fa3c73','西嶼即事','黄庚','宋','宋诗','song-poetry','','[]','松陰迷草徑，緩步曳吟筇。',48,'全唐诗/poet.song.242000.json','["松陰迷草徑，緩步曳吟筇。", "秋鶴有仙意，寒花無冶容。", "漁洲烟浦笛，僧寺夕陽鐘。", "回首來時路，白雲深幾重。"]'),
('f8396a8e-f5b2-4ffa-b50d-6d56c8512195','春日和韻','黄庚','宋','宋诗','song-poetry','','[]','新晴天氣好，老去倦尋芳。',48,'全唐诗/poet.song.242000.json','["新晴天氣好，老去倦尋芳。", "桃李自春色，園林又夕陽。", "捲簾通燕入，掃徑惜花香。", "寒食清明近，松楸憶故鄉。"]'),
('ba79f65b-5c9e-414c-8543-27177dab3e1f','述懷','黄庚','宋','宋诗','song-poetry','','[]','柴門閑掩晝，雲護竹窗深。',48,'全唐诗/poet.song.242000.json','["柴門閑掩晝，雲護竹窗深。", "茂草多生意，枯松見古心。", "有書消白日，無術化黄金。", "客問生涯事，長年只苦吟。"]'),
('95dcdde5-9a80-4ad2-bcb0-70b3a093e7e7','對竹','黄庚','宋','宋诗','song-poetry','','[]','門對南鄰竹，青青玉萬竿。',48,'全唐诗/poet.song.242000.json','["門對南鄰竹，青青玉萬竿。", "雖然無地種，且得隔籬看。", "露葉晴猶濕，風枝夏亦寒。", "但教休剪伐，日用報平安。"]'),
('55a4dcc4-dcd1-47f0-a0a2-b32f8ce5b95e','秋色','黄庚','宋','宋诗','song-poetry','','[]','憑高望不極，望斷動愁情。',48,'全唐诗/poet.song.242000.json','["憑高望不極，望斷動愁情。", "落日凄凉處，西風點染成。", "丹楓明野驛，白水浸江城。", "馬上人回首，戎戎黯客程。"]'),
('a0aad322-0a0b-43b3-8eee-7f8c3d3f58c4','幽居','黄庚','宋','宋诗','song-poetry','','[]','結屋依山住，幽窗與靜宜。',48,'全唐诗/poet.song.242000.json','["結屋依山住，幽窗與靜宜。", "藤花上疏竹，苔石卧荒籬。", "挈榼童沽酒，敲門客送詩。", "老慚生計拙，役役又何爲。"]'),
('2dc4f7bc-3fa4-47d2-8a6b-f049d4d2036c','懷友','黄庚','宋','宋诗','song-poetry','','[]','柴門春事盡，未見故人來。',48,'全唐诗/poet.song.242000.json','["柴門春事盡，未見故人來。", "樹密鳥相語，山空花自開。", "傾心多日別，屈指幾時回。", "爲問頻書札，何時共酒杯。"]'),
('c943c6cc-bf33-4d18-8468-de00b549ca7d','夏夜小酌','黄庚','宋','宋诗','song-poetry','','[]','小酌酬清興，憑闌看月移。',48,'全唐诗/poet.song.242000.json','["小酌酬清興，憑闌看月移。", "分茶醒醉客，添燭了殘棋。", "螢影明桐井，蛙聲出草池。", "荒城江漏遠，試問夜何其。"]'),
('b0244c2a-db7c-460a-93aa-56c97b3a91fb','王修竹約觀打魚分韵得圓字','黄庚','宋','宋诗','song-poetry','','[]','隔岸呼漁伴，輕篙破曉烟。',48,'全唐诗/poet.song.242000.json','["隔岸呼漁伴，輕篙破曉烟。", "鳴榔舟葉聚，撒網浪花圓。", "饞鷺窺高樹，驚鱗過別川。", "洋洋聊付物，生意自無邊。"]'),
('bbf9882c-3e86-4c7d-aa75-aec1f5d3b264','新雁','黄庚','宋','宋诗','song-poetry','','[]','來賓何太早，嘹嚦過南樓。',48,'全唐诗/poet.song.242000.json','["來賓何太早，嘹嚦過南樓。", "數點乍離塞，一聲初報秋。", "行行驚客眼，字字寫鄉愁。", "仗節人何在，帛書能寄不。"]'),
('5d910bb3-d962-4c4c-b906-238d3e51991c','病中','黄庚','宋','宋诗','song-poetry','','[]','讀易窗閑久，多時不點硃。',48,'全唐诗/poet.song.242000.json','["讀易窗閑久，多時不點硃。", "硯乾蟾渴水，篋破蠹侵書。", "氣味如僧淡，形容似鶴癯。", "交遊空滿眼，誰念病相如。"]'),
('11f09925-ccd4-40b5-ada1-4088e44967a1','月山書館','黄庚','宋','宋诗','song-poetry','','[]','山色青邊屋，幽深稱隠居。',48,'全唐诗/poet.song.242000.json','["山色青邊屋，幽深稱隠居。", "瓶梅香筆硯，窗雪冷琴書。", "壁有先賢像，門無俗客車。", "代耕惟舌在，何必耦長沮。"]'),
('dc7d2a2d-4f74-4088-88b3-a23d91700097','秋夜獨坐','黄庚','宋','宋诗','song-poetry','','[]','黄庭重讀罷，掩卷對寒檠。',48,'全唐诗/poet.song.242000.json','["黄庭重讀罷，掩卷對寒檠。", "髮爲憂時白，心因學道清。", "一窗秋月色，四壁夜蛩聲。", "坐倦閑欹枕，詩成夢不成。"]'),
('9abb27a8-a87c-4ee7-9f6c-ae7eb3c07711','九日書懷','黄庚','宋','宋诗','song-poetry','','[]','客鬢同秋老，鄉心逐雁飛。',48,'全唐诗/poet.song.242000.json','["客鬢同秋老，鄉心逐雁飛。", "重陽今日是，三徑幾時歸。", "籬下多黄菊，門前少白衣。", "無人慰岑寂，獨立對斜暉。"]'),
('73f499b5-5b3f-4749-9f06-8b2698d49ecd','古松','黄庚','宋','宋诗','song-poetry','','[]','夭矯森寒翠，髯蛟勢倚天。',48,'全唐诗/poet.song.242000.json','["夭矯森寒翠，髯蛟勢倚天。", "喬陰無六月，老氣已千年。", "斸藥人能壽，巢枝鳥亦仙。", "秋風響柯葉，彷彿奏虞絃。"]'),
('40cab81e-ed05-47f8-ad6f-48a6a68cc807','聽雪','黄庚','宋','宋诗','song-poetry','','[]','撲簌敲窗紙，寒齋剡水濱。',48,'全唐诗/poet.song.242000.json','["撲簌敲窗紙，寒齋剡水濱。", "六花初落夜，孤枕未眠人。", "耳靜聲逾細，心清趣自真。", "愛梅情更苦，恐壓一枝春。"]'),
('39aa6d99-62b3-458c-b3ee-1c51001efd72','石窗爲明上人賦','黄庚','宋','宋诗','song-poetry','','[]','何年鑿山骨，八面鎖蒼苔。',48,'全唐诗/poet.song.242000.json','["何年鑿山骨，八面鎖蒼苔。", "海月照還白，天風吹不開。", "玲瓏宜丈室，明潔稱經臺。", "眼界皆通透，閒雲任去來。"]'),
('0e6dfd78-0112-4eeb-bf71-9c0413a57860','對鏡','黄庚','宋','宋诗','song-poetry','','[]','勳業夢不到，曉窗時一看。',48,'全唐诗/poet.song.242000.json','["勳業夢不到，曉窗時一看。", "是非須內照，妍醜付旁觀。", "客鬢從渠白，詩肩本自寒。", "儼然瞻視處，頼汝整衣冠。"]'),
('25d228a2-344c-47b2-af4b-8cc356e2b3f1','夜坐','黄庚','宋','宋诗','song-poetry','','[]','世事等輕雲，蘧廬寄此身。',48,'全唐诗/poet.song.242000.json','["世事等輕雲，蘧廬寄此身。", "青燈少年夢，白髮異鄉人。", "按劍驚山鬼，吞丹養谷神。", "黄庭重讀罷，吾得葆吾真。"]'),
('b39423c0-5d71-43ac-ad9d-df66602d6af9','西州即事','黄庚','宋','宋诗','song-poetry','','[]','一雨洗空碧，江城獨倚樓。',48,'全唐诗/poet.song.242000.json','["一雨洗空碧，江城獨倚樓。", "山吞殘日沒，水挾斷雲流。", "燈影深村夜，鐘聲古寺秋。", "西州舊遊地，十載此淹留。"]'),
('7ca0ec8b-d0ae-48d3-a68d-a41e460f6412','春日即事','黄庚','宋','宋诗','song-poetry','','[]','扶杖行幽徑，園林欲暮天。',48,'全唐诗/poet.song.242000.json','["扶杖行幽徑，園林欲暮天。", "錦棠紅濯雨，絲柳綠繰烟。", "春事忽三月，風光又一年。", "客懷正愁絕，那復聽啼鵑。"]'),
('75e6a7e9-065c-4442-8c12-6f4914b62ad1','採菊','黄庚','宋','宋诗','song-poetry','','[]','籬東閑採菊，三徑碧苔深。',48,'全唐诗/poet.song.242000.json','["籬東閑採菊，三徑碧苔深。", "曉露冷雙屐，秋風香一襟。", "餐英供小酌，嗅蕊伴清吟。", "會得悠然處，方知靖節心。"]'),
('8adb754c-a7bd-4ec0-bf36-f6f8d1be3559','春日','黄庚','宋','宋诗','song-poetry','','[]','春色濃於酒，何須醉玉觴。',48,'全唐诗/poet.song.242000.json','["春色濃於酒，何須醉玉觴。", "柳疏鶑占影，花雜蝶分香。", "往事隨流水，閒愁付夕陽。", "吟邊自歌舞，猶學少年狂。"]'),
('bbea02d2-3e26-4329-a667-44d1cc83ad5d','六月白菊','黄庚','宋','宋诗','song-poetry','','[]','□客背時芳，何須晚節香。',48,'全唐诗/poet.song.242000.json','["□客背時芳，何須晚節香。", "人間方夏熱，籬下自秋光。", "便是重陽日，真成六月霜。", "若教陶令見，應以醉爲鄉。"]'),
('6e5567af-5aa6-4b0d-a90b-a7cccc0c90b2','白蓮','黄庚','宋','宋诗','song-poetry','','[]','泰華峰頭種，移根植野塘。',48,'全唐诗/poet.song.242000.json','["泰華峰頭種，移根植野塘。", "一池秋夜月，萬柄曉天霜。", "西帝羅青蓋，真妃逞素狂。", "鷺飛無認處，點點水雲鄉。"]'),
('7b87a7d5-dd16-4590-a772-80867f1dabc5','石門','黄庚','宋','宋诗','song-poetry','','[]','羸馬東山路，駸駸抵石門。',48,'全唐诗/poet.song.242000.json','["羸馬東山路，駸駸抵石門。", "落花春夜雨，流水暮烟村。", "久客悲行役，清愁攪夢魂。", "勞生多感慨，餘恨付乾坤。"]'),
('bcdd9655-72c4-45cc-a07f-af8d5d9ae9c6','書山陰驛','黄庚','宋','宋诗','song-poetry','','[]','迢遞三山道，重來感舊遊。',48,'全唐诗/poet.song.242000.json','["迢遞三山道，重來感舊遊。", "潮聲寒带雨，山色淡生秋。", "寄驛通鄉信，題詩記旅愁。", "江湖十年客，兩度到西州。"]'),
('39ea4ac1-9ba2-4979-94d7-0af7282b86de','偶書','黄庚','宋','宋诗','song-poetry','','[]','老眼看書暗，桑榆景漸催。',48,'全唐诗/poet.song.242000.json','["老眼看書暗，桑榆景漸催。", "文章身後貴，懷抱酒邊開。", "燈火夢猶在，功名心已灰。", "客來休問字，且覆掌中杯。"]'),
('07a5570c-4974-4426-ae94-bbb2ac9b35e2','宿甘露寺','黄庚','宋','宋诗','song-poetry','','[]','山險疑無路，縈迴一徑通。',48,'全唐诗/poet.song.242000.json','["山險疑無路，縈迴一徑通。", "鐘聲寒瀑外，塔影夕陽中。", "窗出茶烟白，爐分葑火紅。", "禪房遇耆舊，清話數宵同。"]'),
('ce2d00b8-a96d-4a26-9649-66ec16801c38','江樓','黄庚','宋','宋诗','song-poetry','','[]','凭高閒眺望，老眼倍增明。',48,'全唐诗/poet.song.242000.json','["凭高閒眺望，老眼倍增明。", "林白山雲出，潮紅海日生。", "登臨懷舊恨，吟笑遣閑情。", "客裏逢心友，開樽敘昔盟。"]'),
('f8a837f6-dce3-489d-84d2-a69821a63450','竹杖','黄庚','宋','宋诗','song-poetry','','[]','一枝蒼節瘦，恰稱地行仙。',48,'全唐诗/poet.song.242000.json','["一枝蒼節瘦，恰稱地行仙。", "不但挑詩卷，尤堪掛酒錢。", "看梅敲雪落，引鶴卓苔穿。", "莫近葛陂水，化龍飛上天。"]'),
('9266b1ed-fb54-4924-9ac1-4179f25074d9','次韻書懷','黄庚','宋','宋诗','song-poetry','','[]','風霜頭已白，悔不早歸耕。',48,'全唐诗/poet.song.242000.json','["風霜頭已白，悔不早歸耕。", "客路遠千里，儒冠誤一生。", "世情雲共薄，心事月同明。", "老去便疏散，逢人懶送迎。"]'),
('2e45a454-2695-4993-ae7d-306cf8bd123c','秋日','黄庚','宋','宋诗','song-poetry','','[]','旅食幾時休，生涯未有謀。',48,'全唐诗/poet.song.242000.json','["旅食幾時休，生涯未有謀。", "西風一夜雨，落葉萬山秋。", "起石終當隠，草玄殊可羞。", "江鄉烟水遠，何日買歸舟。"]'),
('668ba2de-6d08-4c6d-9a75-c75b54eb63c6','贈皎上人','黄庚','宋','宋诗','song-poetry','','[]','破衲和雲著，何時下赤城。',48,'全唐诗/poet.song.242000.json','["破衲和雲著，何時下赤城。", "高年頭未白，得道骨全青。", "詩思秋空闊，禪心夜月明。", "何當捐世事，來結遠公盟。"]'),
('3cac1b01-c1eb-4026-b977-c88640283edd','王直翁相過','黄庚','宋','宋诗','song-poetry','','[]','芒鞋朝踏雨，來自赤城山。',48,'全唐诗/poet.song.242000.json','["芒鞋朝踏雨，來自赤城山。", "久別翻生面，相看各老顔。", "開樽茅屋裏，煮茗竹林間。", "此去須榮遇，寧愁行路難。"]'),
('e31521f3-2554-4c9e-808e-f60bec3e2dec','鴛鴦梅','黄庚','宋','宋诗','song-poetry','','[]','孤花忽嫵媚，並蒂占春陽。',48,'全唐诗/poet.song.242000.json','["孤花忽嫵媚，並蒂占春陽。", "自有雙成意，全勝姑射粧。", "月溪同浴影，雪樹共棲香。", "玉笛頻吹處，交飛落野塘。"]'),
('365756ac-216a-444c-a074-cb5909966871','王琴所話別','黄庚','宋','宋诗','song-poetry','','[]','羈懷不可述，頼有古琴知。',48,'全唐诗/poet.song.242000.json','["羈懷不可述，頼有古琴知。", "客舍相逄日，江楓正落時。", "夕陽村店酒，秋色野橋詩。", "別去吳江上，悠悠動遠思。"]'),
('9861e3bc-4aa5-4d0e-b5c7-f9c30ba87f92','除夜即事','黄庚','宋','宋诗','song-poetry','','[]','除夕無詩侶，燈窗酒獨斟。',48,'全唐诗/poet.song.242000.json','["除夕無詩侶，燈窗酒獨斟。", "三更風雪夜，一片歲寒心。", "衰老常憂病，清閑不廢吟。", "明朝年八十，晚景惜榆陰。"]'),
('959a2810-cf41-4e68-8de1-5ef31919959c','王可交昇仙臺四首  其一','黄庚','宋','宋诗','song-poetry','','[]','人去臺猶在，飛昇事可嘉。',48,'全唐诗/poet.song.242000.json','["人去臺猶在，飛昇事可嘉。", "神仙多變幻，塵世總虛花。", "煉氣顔難老，勞心鬢易華。", "千年留古跡，題詠屬詩家。"]'),
('02d5ab12-c197-46ce-8be4-89802323ea70','王可交昇仙臺四首  其二','黄庚','宋','宋诗','song-poetry','','[]','異人鍾秀氣，草木亦精神。',48,'全唐诗/poet.song.242000.json','["異人鍾秀氣，草木亦精神。", "見說爲漁父，誰知悟道真。", "仙家多勝景，世路有迷津。", "安得騎黄鶴，相隨入昊旻。"]'),
('20a7b7c5-8b65-4d3d-8468-b2fca2efc3c9','王可交昇仙臺四首  其三','黄庚','宋','宋诗','song-poetry','','[]','仙翁不可見，惟有一空亭。',48,'全唐诗/poet.song.242000.json','["仙翁不可見，惟有一空亭。", "地冷春留雪，林深晝見星。", "松篁團秀色，蘭蕙吐幽馨。", "立盡斜陽影，閑看鶴刷翎。"]'),
('bf5fd4eb-2355-454f-b3d2-63b3b2a4638d','王可交昇仙臺四首  其四','黄庚','宋','宋诗','song-poetry','','[]','我來閑弔古，觸景覺凄凉。',48,'全唐诗/poet.song.242000.json','["我來閑弔古，觸景覺凄凉。", "踏石雲侵履，捫蘿露濕裳。", "森森林木茂，馥馥野花香。", "寺近尋僧話，談禪坐竹床。"]'),
('e17b5d94-2f67-4cdc-8c98-8f4eafac0d7d','冬夜即事','黄庚','宋','宋诗','song-poetry','','[]','獨寢書窗下，其如寒夜何。',48,'全唐诗/poet.song.242000.json','["獨寢書窗下，其如寒夜何。", "頭邊枕黄嬭，脚底踏湯婆。", "紙帳梅花暖，布衾春意多。", "道人無妄想，夢不到南柯。"]'),
('9f70f3ed-7670-4e8f-a02d-2e514e0d458f','寄友人','黄庚','宋','宋诗','song-poetry','','[]','相望咫尺地，久不到蝸廬。',48,'全唐诗/poet.song.242000.json','["相望咫尺地，久不到蝸廬。", "室邇人何遠，心親迹任疏。", "交遊常念舊，情意只如初。", "我欲携囊去，相逢勝寄書。"]'),
('3e0ef788-0a54-4b49-9d0b-198e7d0d338d','偶書','黄庚','宋','宋诗','song-poetry','','[]','老來驚歲晚，愁裏度年華。',48,'全唐诗/poet.song.242000.json','["老來驚歲晚，愁裏度年華。", "雲凍天將雪，山寒梅未花。", "曉窗留客飯，午寺覓僧茶。", "歸路江村暝，行行及暮鴉。"]'),
('015dc810-0622-4e8d-af67-ccf1466fd5e4','孤雁','黄庚','宋','宋诗','song-poetry','','[]','長空獨嘹唳，隠約背斜暉。',48,'全唐诗/poet.song.242000.json','["長空獨嘹唳，隠約背斜暉。", "塞北離羣遠，江南失侶歸。", "度雲憐隻影，照水認雙飛。", "却羨投林鳥，相逢入翠微。"]'),
('6614ab0b-e312-4f87-8ff8-978b9e7a13d3','呈曾蒲澗提刑','黄庚','宋','宋诗','song-poetry','','[]','詩自茶山後，如公世所稀。',48,'全唐诗/poet.song.242000.json','["詩自茶山後，如公世所稀。", "特來參活字，應肯授玄機。", "寒澗孤松老，秋雲獨鶴飛。", "台山千萬丈，望望未能歸。"]'),
('10ea675d-72bb-4071-aba8-1c4a7d6578dc','和茅亦山韻二首  其一','黄庚','宋','宋诗','song-poetry','','[]','一生場屋夢，老去付悠悠。',48,'全唐诗/poet.song.242000.json','["一生場屋夢，老去付悠悠。", "始信功名事，難爲智力謀。", "有才如孔孟，無命不伊周。", "吾道今如此，蒼天可問不。"]'),
('a585877c-27ca-429f-b17d-1e5a2f2cd2a6','和茅亦山韻二首  其二','黄庚','宋','宋诗','song-poetry','','[]','愛靜吟成僻，躭書近欲癡。',48,'全唐诗/poet.song.242000.json','["愛靜吟成僻，躭書近欲癡。", "事多因錯省，節不爲貧移。", "長物新添畫，生涯舊有詩。", "窮通係天命，知命復何疑。"]'),
('8cb4d9ce-7723-4bfd-9d9d-4043ef29995b','題嚴子陵','黄庚','宋','宋诗','song-poetry','','[]','故人雖即位，自不願爲官。',48,'全唐诗/poet.song.242000.json','["故人雖即位，自不願爲官。", "天下事已定，山中人可閑。", "一絲江月色，千古客星寒。", "捷徑終南士，聞風定報然。"]'),
('48955e0d-4547-4f8e-93db-f53b004e3ad9','除夕','黄庚','宋','宋诗','song-poetry','','[]','爆竹驚殘臘，冬春此夕分。',48,'全唐诗/poet.song.242000.json','["爆竹驚殘臘，冬春此夕分。", "且斟分歲酒，懶賦送窮文。", "客思愁簷雨，鄉心逐海雲。", "陽和在何處，明日問東君。"]'),
('4511fe07-2cc5-4786-ae66-3471999125e0','和鄭梅深','黄庚','宋','宋诗','song-poetry','','[]','江湖新識面，恰似舊相知。',48,'全唐诗/poet.song.242000.json','["江湖新識面，恰似舊相知。", "腹貯三餘學，才工十詠詩。", "聲名蘇太史，家世鄭當時。", "客路携琴去，終須遇子期。"]'),
('7d8ed49e-6246-42cf-b914-21e373d818be','即事','黄庚','宋','宋诗','song-poetry','','[]','雀羅門戶靜，無客扣柴扃。',48,'全唐诗/poet.song.242000.json','["雀羅門戶靜，無客扣柴扃。", "索句髭先白，看書眼尚青。", "雲粘題石壁，月浸汲泉瓶。", "笑殺利名客，沉酣死不醒。"]'),
('2675ecfe-8652-4ade-a70d-d683d8f7b39c','對客','黄庚','宋','宋诗','song-poetry','','[]','窗下篝燈坐，相看白髮新。',48,'全唐诗/poet.song.242000.json','["窗下篝燈坐，相看白髮新。", "共談爲客事，同是異鄉人。", "詩寫梅花月，茶煎穀雨春。", "明朝愁遠別，離思欲沾巾。"]'),
('90cc6fc9-2a48-4753-bf22-1980862289f5','寒夜呈梅深','黄庚','宋','宋诗','song-poetry','','[]','空齋對孤客，寂寞似僧家。',48,'全唐诗/poet.song.242000.json','["空齋對孤客，寂寞似僧家。", "爐冷頻燒葉，燈昏不吐花。", "夜長添睡思，歲晚憶年華。", "吟倦推窗坐，梅簷月未斜。"]'),
('13600e6c-18ea-4a07-9a05-71e08bcde0e2','林霽山架閣同宿山中','黄庚','宋','宋诗','song-poetry','','[]','秋風山館客，移席近燈前。',48,'全唐诗/poet.song.242000.json','["秋風山館客，移席近燈前。", "共語忽深夜，相看非少年。", "斗垂天末樹，鱗出雨餘天。", "亦有茅簷下，飯牛人未眠。"]'),
('6891138d-5a5d-48be-86d1-c9d276fbd9aa','遊東庵','黄庚','宋','宋诗','song-poetry','','[]','庵連兜率寺，三徑竹邊開。',48,'全唐诗/poet.song.242000.json','["庵連兜率寺，三徑竹邊開。", "林密暑不到，窗虛月自來。", "暮山啼鳥靜，雲樹嘯猿哀。", "拂拭殘碑字，年深半綠苔。"]'),
('7bc3fc6c-b974-4640-9ceb-6552bf7a5b43','贈了上人抄化','黄庚','宋','宋诗','song-poetry','','[]','破衲卷秋雲，入山深更深。',48,'全唐诗/poet.song.242000.json','["破衲卷秋雲，入山深更深。", "近聞營梵剎，應不累禪心。", "寒瀑瀉蒼壁，晚花生古林。", "遥思明月夜，誰聽穎師琴。"]'),
('67aeea87-ca64-4d42-8cb0-2332561e852b','呈茅一齋先生','黄庚','宋','宋诗','song-poetry','','[]','前輩凋零盡，如公尚典型。',48,'全唐诗/poet.song.242000.json','["前輩凋零盡，如公尚典型。", "爲僧眉獨白，見客眼長青。", "教子成三俊，傳家有六經。", "我來問奇字，應許扣柴扃。"]'),
('1b2f99fa-0a7a-400f-a70b-bd01bd76dc62','別徐敬菊','黄庚','宋','宋诗','song-poetry','','[]','契闊又兩載，光陰一擲梭。',48,'全唐诗/poet.song.242000.json','["契闊又兩載，光陰一擲梭。", "祇因離別久，不覺語言多。", "安得長留此，其如欲去何。", "詩盟終未冷，早晚更相過。"]'),
('fe6ac168-8cc6-47c7-9c4d-3598fce8c9f3','寄姜仕可','黄庚','宋','宋诗','song-poetry','','[]','獨學苦無友，年來媿廣文。',48,'全唐诗/poet.song.242000.json','["獨學苦無友，年來媿廣文。", "懷賢歌伐木，憶別賦停雲。", "病後少出戶，夢中多見君。", "盍簪須有日，却與共論文。"]'),
('31346a57-d781-4d6b-9605-a2fa7a10e851','寄月山太守','黄庚','宋','宋诗','song-poetry','','[]','下車方數月，早已政聲馳。',48,'全唐诗/poet.song.242000.json','["下車方數月，早已政聲馳。", "太守一身瘦，東川百姓肥。", "勤勞惟聽政，閑暇即吟詩。", "官况依然在，何須賦式微。"]'),
('315ffb7b-36a4-4091-92a0-ae788b8d5e17','歲晚書懷呈月山太守','黄庚','宋','宋诗','song-poetry','','[]','光陰催我老，衰病亦堪憐。',48,'全唐诗/poet.song.242000.json','["光陰催我老，衰病亦堪憐。", "殘臘不多日，餘生能幾年。", "有爲俱是妄，無事即成仙。", "近得安心法，蒲團學坐禪。"]'),
('eab6cae5-870d-4b05-a5c5-a0de2a6ab5bf','鶴林仙壇寺','黄庚','宋','宋诗','song-poetry','','[]','古壇歸鶴杳，野鹿自成羣。',48,'全唐诗/poet.song.242000.json','["古壇歸鶴杳，野鹿自成羣。", "嵐氣浮清曉，鐘聲出白雲。", "樹穿僧屋老，水到寺門分。", "人世無窮事，山中了不聞。"]'),
('24386e1e-85da-4018-b517-1ee9591352e6','枕易','黄庚','宋','宋诗','song-poetry','','[]','古鼎烟銷倦點朱，翛然高卧夜寒初。',64,'全唐诗/poet.song.242000.json','["古鼎烟銷倦點朱，翛然高卧夜寒初。", "四簷寂寂半床夢，兩鬢蕭蕭一卷書。", "日月冥心知代謝，陰陽回首驗盈虛。", "起來萬象皆吾有，收拾乾坤在草廬。"]'),
('c60ba7be-f971-4aca-bfeb-35987eaf1a78','棋聲','黄庚','宋','宋诗','song-poetry','','[]','何處仙翁愛手談，時聞剝啄竹林間。',64,'全唐诗/poet.song.242000.json','["何處仙翁愛手談，時聞剝啄竹林間。", "一枰子玉敲雲碎，幾度午窗驚夢殘。", "緩著應知心路遠，急圍不放耳根閑。", "爛柯人去收殘局，寂寂空亭石几寒。"]'),
('19e919a6-17fc-4ac0-980e-768f5b594a57','題李藍溪梅花吟卷','黄庚','宋','宋诗','song-poetry','','[]','孤芳不與衆芳同，肯媚東君事冶容。',64,'全唐诗/poet.song.242000.json','["孤芳不與衆芳同，肯媚東君事冶容。", "寒苦一生蘇武雪，清高千古伯夷風。", "瓊瑶照樹偏宜晚，鐵石盤根却耐冬。", "幾度看花立霜曉，斷腸都在角聲中。"]'),
('8f05fb01-f9a7-48d3-9b1e-da204b63638b','秋夜','黄庚','宋','宋诗','song-poetry','','[]','博山香冷夜將闌，紅影摇窗燭未殘。',64,'全唐诗/poet.song.242000.json','["博山香冷夜將闌，紅影摇窗燭未殘。", "庭樹露濃花氣濕，井梧風老葉聲乾。", "世情冷暖知心少，朋舊東西會面難。", "一段客愁吟不就，無言背月倚闌干。"]'),
('9145d148-94ab-41fd-8ec3-b8a608572e01','秋夜和月山韻','黄庚','宋','宋诗','song-poetry','','[]','凉夜殘燈照客愁，衾單添盡鷫鸘裘。',64,'全唐诗/poet.song.242000.json','["凉夜殘燈照客愁，衾單添盡鷫鸘裘。", "半窗明月三更夢，一枕西風兩鬢秋。", "吟骨稜稜寬带眼，歸心切切望刀頭。", "何時束篋家山去，獨駕柴車訪伯休。"]'),
('bcfa4d5c-e24b-4c9d-a013-11e0e19050f4','蘭亭會飲觀晉帖','黄庚','宋','宋诗','song-poetry','','[]','祇說清談晉業虛，蘭亭之樂後來無。',64,'全唐诗/poet.song.242000.json','["祇說清談晉業虛，蘭亭之樂後來無。", "一時人物已陳迹，千古山林空畫圖。", "鐘带夕陽來遠寺，碑和春雨卧平蕪。", "昭陵玉匣猶難保，筆意從誰認鼠鬚。"]'),
('625ea23d-7c6a-4b55-b1b7-2ede4359b2b8','春游次王修竹監簿韵','黄庚','宋','宋诗','song-poetry','','[]','天色新晴带薄寒，主人飲客出城關。',64,'全唐诗/poet.song.242000.json','["天色新晴带薄寒，主人飲客出城關。", "蘭亭觴詠尋羲帖，窆石衣冠弔禹山。", "春水斷橋芳草碧，曉風啼鳥落花閑。", "囊中詩句壺中酒，何必仙人大小還。"]'),
('e112ba7c-3c28-4186-bb4c-1c0c6406bbf4','修竹宴客東園','黄庚','宋','宋诗','song-poetry','','[]','二月春光潑眼濃，携樽宴客小亭東。',64,'全唐诗/poet.song.242000.json','["二月春光潑眼濃，携樽宴客小亭東。", "酒當半醉半醒處，春在輕寒輕暖中。", "拂檻柳添吟鬢綠，壓闌花妬舞衣紅。", "晚來聽唱梁州曲，聲繞吳姬扇底風。"]'),
('4a27f71c-a127-4d88-8fe6-edc47f409a3e','書懷','黄庚','宋','宋诗','song-poetry','','[]','剛腸不撓是男兒，舌在囊中豈足悲。',64,'全唐诗/poet.song.242000.json','["剛腸不撓是男兒，舌在囊中豈足悲。", "落落世情難苟合，徨徨客路欲何之。", "舊時風月堪遺恨，好處江山尚欠詩。", "莫把閑愁縈素抱，人生雙鬢易成絲。"]'),
('69904467-54da-4c09-80d2-214c12b317e2','送張伯威提舉','黄庚','宋','宋诗','song-poetry','','[]','人生聚散等浮漚，憶昔過從與勝遊。',64,'全唐诗/poet.song.242000.json','["人生聚散等浮漚，憶昔過從與勝遊。", "棋局敲殘清夜月，菊花吟老半窗秋。", "客中送客難爲別，山外看山總是愁。", "回首片帆江路遠，疏烟斜雨到西州。"]'),
('b8930028-1e74-42b5-a43e-1393cab72cf6','春日即事','黄庚','宋','宋诗','song-poetry','','[]','園林芳事漸闌珊，客思無聊午夢殘。',64,'全唐诗/poet.song.242000.json','["園林芳事漸闌珊，客思無聊午夢殘。", "紅杏花繁蜂蜜飽，碧芹香老燕泥乾。", "光陰有限鬢已白，勳業無成心尚丹。", "倚遍吟闌天欲暮，一簾風雨捲青春。"]'),
('60a6f1e8-f4e1-45c5-8222-52512311368d','小酌','黄庚','宋','宋诗','song-poetry','','[]','小酌園林酒半醺，落紅影裏惜餘春。',64,'全唐诗/poet.song.242000.json','["小酌園林酒半醺，落紅影裏惜餘春。", "插花歸去蜂隨帽，傍柳行來鶑避人。", "白髮尚爲千里客，黄金難鑄百年身。", "何時歸賦滄浪水，澣我征衣萬斛塵。"]'),
('04e191b0-cb27-4e44-9ce3-693e60d28c27','城南即事','黄庚','宋','宋诗','song-poetry','','[]','支筇破曉出南城，古寺凄迷草自生。',64,'全唐诗/poet.song.242000.json','["支筇破曉出南城，古寺凄迷草自生。", "幾處亭臺空鎖鑰，百年人物盡丘塋。", "雕梁語燕應無主，廢圃殘花似有情。", "世事轉頭皆夢境，浮生何用苦營營。"]'),
('abd634c7-2e47-4668-bc68-940f83eb7bec','夜坐次林梅山韻','黄庚','宋','宋诗','song-poetry','','[]','人倚幽窗夜未闌，竹爐灰冷篆烟殘。',64,'全唐诗/poet.song.242000.json','["人倚幽窗夜未闌，竹爐灰冷篆烟殘。", "一天露氣星辰濕，萬壑風聲草木寒。", "老去客懷多感慨，年來世事轉艱難。", "何時歸隠孤山下，明月梅花約共看。"]'),
('0c457c4f-2216-4c58-8950-1e8c6be590d0','有感','黄庚','宋','宋诗','song-poetry','','[]','自嘆文章不遇時，平生壯志與心違。',64,'全唐诗/poet.song.242000.json','["自嘆文章不遇時，平生壯志與心違。", "十年湖海無家住，千里鄉關有夢歸。", "殘夜月寒燈暈淡，高秋天闊雁聲微。", "傷今思古愁無奈，老淚斑斑濕客衣。"]'),
('2dd7ed46-446a-4296-a561-9cd4c41f47f1','即事','黄庚','宋','宋诗','song-poetry','','[]','蠅頭蝸角兩無營，心地寬閒景亦清。',64,'全唐诗/poet.song.242000.json','["蠅頭蝸角兩無營，心地寬閒景亦清。", "山色淺深分遠近，雲容舒卷弄陰晴。", "曉窗對菊思元亮，秋佩紉蘭效屈平。", "獨倚西風凝望眼，一行雁影夕陽明。"]'),
('aa598642-57d6-4d4c-8ab9-bc685fb0da46','生朝自述','黄庚','宋','宋诗','song-poetry','','[]','都道人生七十稀，老逢初度歎衰遲。',64,'全唐诗/poet.song.242000.json','["都道人生七十稀，老逢初度歎衰遲。", "飛觴醉月貧無酒，走筆迎春富有詩。", "憔悴自憐蒲柳質，劬勞空起蓼莪思。", "門無賀客清如水，獨對蘭花誦楚辭。"]'),
('dbafa1c3-f1e6-4f84-ae8c-50544e77f311','雪','黄庚','宋','宋诗','song-poetry','','[]','片片隨風整復斜，飄來老鬢覺添華。',64,'全唐诗/poet.song.242000.json','["片片隨風整復斜，飄來老鬢覺添華。", "江山不夜月千里，天地無私玉萬家。", "遠岸未春飛柳絮，前村破曉壓梅花。", "羔羊金帳應粗俗，自掬水泉煮石茶。"]'),
('0762c662-9702-4506-b1fd-a139f53ca0d3','九日客懷','黄庚','宋','宋诗','song-poetry','','[]','烏帽斜欹白髮侵，老來空憶舊登臨。',64,'全唐诗/poet.song.242000.json','["烏帽斜欹白髮侵，老來空憶舊登臨。", "一枝黄菊西風淚，數畝蒼苔故國心。", "梧顫秋聲庭露冷，雁傳寒信塞雲深。", "不須貰酒酬佳節，只把陶詩細細吟。"]'),
('bf53fa01-cd5f-4e5c-8763-50af2164a178','舟次樗蒱廟','黄庚','宋','宋诗','song-poetry','','[]','短棹衝寒過浦東，扁舟一葉載詩翁。',64,'全唐诗/poet.song.242000.json','["短棹衝寒過浦東，扁舟一葉載詩翁。", "斷烟流水殘雲外，古木荒祠夕照中。", "吟罷小樓何處笛，酒醒孤枕半江風。", "潮生潮落朝還暮，堪歎人生自轉蓬。"]'),
('3bef9dcf-de12-485d-b901-1d04b30fc1d6','月夜登樓','黄庚','宋','宋诗','song-poetry','','[]','玉宇澄清暮靄收，吟邊怕倚仲宣樓。',64,'全唐诗/poet.song.242000.json','["玉宇澄清暮靄收，吟邊怕倚仲宣樓。", "寒蟾千里夜如晝，新雁一聲天欲秋。", "湖海誰青豪傑眼，風霜易白少年頭。", "更殘忽聽荒城角，吹老梅花總是愁。"]'),
('06555fc6-eee2-433f-932a-d47980e215ca','送慈州茅主簿入道','黄庚','宋','宋诗','song-poetry','','[]','儒冠不戴戴星冠，人世榮華作夢看。',64,'全唐诗/poet.song.242000.json','["儒冠不戴戴星冠，人世榮華作夢看。", "譜出三茅終得道，趣同五柳早休官。", "月寒緱嶺來笙鶴，春藹慈州憶枳鸞。", "笑指方壺最深處，凌空霞珮玉珊珊。"]'),
('2fda9f43-706e-4eb7-a02a-accee3eae5c2','月夜次修竹韻','黄庚','宋','宋诗','song-poetry','','[]','徙倚吟闌傍野塘，古譙蓮漏滴更長。',64,'全唐诗/poet.song.242000.json','["徙倚吟闌傍野塘，古譙蓮漏滴更長。", "月階夜靜蛩聲切，竹院秋深鶴夢凉。", "坐挹水風侵袂冷，眠分花露滿身香。", "浩歌欲遡明河去，醉喚天孫織錦囊。"]'),
('068e89c9-de45-4055-9f0d-8d5515149b2d','寓浦東書懷','黄庚','宋','宋诗','song-poetry','','[]','子規聲裏已非春，消遣光陰只苦吟。',64,'全唐诗/poet.song.242000.json','["子規聲裏已非春，消遣光陰只苦吟。", "肘後無方醫白髮，牀頭有易勝黄金。", "年來不作功名夢，老去全休富貴心。", "獨抱焦桐遊海角，紛紛俗耳少知音。"]'),
('e28ccfa6-8b4e-40d9-863a-c5b5ba5cef6a','呈營田司杜希聖提領','黄庚','宋','宋诗','song-poetry','','[]','行李擔書一鶴隨，蓮香𢅏幕政聲馳。',64,'全唐诗/poet.song.242000.json','["行李擔書一鶴隨，蓮香𢅏幕政聲馳。", "山川太史九州記，桑稼豳風七月詩。", "如晦箕裘傳相種，少陵衣鉢付孫枝。", "謀身儒術誰云拙，堯舜君民正此時。"]'),
('ad4a15b9-d4d4-4f33-b062-97c1dcf17e7c','寄毛素軒宣慰','黄庚','宋','宋诗','song-poetry','','[]','旌麾曾駐鑑湖邊，別去匆匆又兩年。',64,'全唐诗/poet.song.242000.json','["旌麾曾駐鑑湖邊，別去匆匆又兩年。", "清夜夢分千里月，同鄉人各一方天。", "素知心事有鷗在，欲寄音書無雁傳。", "見說使星臨浙右，明朝便買渡江船。"]'),
('c2be117f-a1ea-4020-83c8-71807812c864','酒趣','黄庚','宋','宋诗','song-poetry','','[]','濁醪妙理契心期，小甕新篘香滿巵。',64,'全唐诗/poet.song.242000.json','["濁醪妙理契心期，小甕新篘香滿巵。", "閑裏一生長是醉，飲中三昧有誰知。", "幕天席地忘形處，枕麯眠糟得意時。", "此味靈均應未解，獨醒到死欲何爲。"]'),
('8dadf9ac-03ed-46c8-b174-d7b5da069b6a','秋懷','黄庚','宋','宋诗','song-poetry','','[]','雨裏西風已倦遊，老懷悲感不禁秋。',64,'全唐诗/poet.song.242000.json','["雨裏西風已倦遊，老懷悲感不禁秋。", "世無阮籍誰青眼，今有杜陵人白頭。", "雁擺行知兄弟義，燕營巢爲子孫謀。", "誰憐湖海飄蓬客，隻影孤燈相對愁。"]'),
('900ed937-6c22-4c40-ad59-c6287ea7d6a5','偶書','黄庚','宋','宋诗','song-poetry','','[]','頻年踪跡墮江湖，三徑荒苔憶舊廬。',64,'全唐诗/poet.song.242000.json','["頻年踪跡墮江湖，三徑荒苔憶舊廬。", "身老方知生計拙，家貧漸覺故人疏。", "松薪拾去朝炊黍，漁火分來夜讀書。", "怨鶴驚猿應待我，台山何日賦歸歟。"]'),
('f1e6306a-5e3c-4845-b1d0-e5bfdb22aa09','觀史','黄庚','宋','宋诗','song-poetry','','[]','梧風蕭瑟雨初晴，凉入書堂夜氣清。',64,'全唐诗/poet.song.242000.json','["梧風蕭瑟雨初晴，凉入書堂夜氣清。", "耿耿蘭膏照千古，遲遲蓮漏轉三更。", "力於興廢應難助，氣爲忠邪幾不平。", "掩卷長嗟方就枕，窗前咿喔又雞鳴。"]'),
('f854db91-40a3-414a-b0f1-ee56534f22cb','暮春','黄庚','宋','宋诗','song-poetry','','[]','寂寞園林三月時，客中幾度見春歸。',64,'全唐诗/poet.song.242000.json','["寂寞園林三月時，客中幾度見春歸。", "柳眉綠皺鶑無語，花臉紅銷蝶倦飛。", "節物暗催雙鬢老，功名長與寸心違。", "百年身世成何事，回首西山又落暉。"]'),
('e4466819-acf0-4a3b-b16d-2d84f140ab78','對月','黄庚','宋','宋诗','song-poetry','','[]','萬里無雲天宇寬，十分秋色上樓看。',64,'全唐诗/poet.song.242000.json','["萬里無雲天宇寬，十分秋色上樓看。", "月浮滄海蟾光濕，星落明河象緯寒。", "醉後儘教詩筆健，吟邊莫放酒杯乾。", "一聲長笛知何處，愁殺夜深人倚闌。"]'),
('c222d562-1353-445c-b1b9-a682cdb54e9a','秋夜','黄庚','宋','宋诗','song-poetry','','[]','十分秋色滿軒窗，景物凄清夜氣凉。',64,'全唐诗/poet.song.242000.json','["十分秋色滿軒窗，景物凄清夜氣凉。", "篩月簾櫳金瑣碎，搗霜砧杵玉丁璫。", "井梧葉脫無多影，巖桂花稠不斷香。", "坐到更深吟興動，硯池滴露寫詩狂。"]'),
('26ceaa0d-b284-4741-a114-c9caccb2683b','寓舍即事','黄庚','宋','宋诗','song-poetry','','[]','矮屋編茅槿縛籬，詩人住處恰相宜。',64,'全唐诗/poet.song.242000.json','["矮屋編茅槿縛籬，詩人住處恰相宜。", "萬間突兀夢不到，一室凄清心自知。", "窗下無燈童睡早，林間有月鶴歸遲。", "八荒便作庭除看，南北東西任所之。"]'),
('207bae7f-25f0-4dbe-8ead-05dee32ae92b','書懷奉簡蘭若提舉','黄庚','宋','宋诗','song-poetry','','[]','十年湖海歎飄零，晚景投閑百念輕。',64,'全唐诗/poet.song.242000.json','["十年湖海歎飄零，晚景投閑百念輕。", "看水看山真有味，學書學劍恨無成。", "竹風吟曉詩情動，梧雨敲秋客夢驚。", "老傍人門非久計，不如歸去學淵明。"]'),
('41d5b5ae-a750-4588-a4cd-3e296b682518','登寶林飛來峰','黄庚','宋','宋诗','song-poetry','','[]','乘風飛步碧崔嵬，萬壑千巖入眼來。',64,'全唐诗/poet.song.242000.json','["乘風飛步碧崔嵬，萬壑千巖入眼來。", "古甃直穿滄海破，浮圖高拂白雲開。", "龜公埋沒今無塚，烏喙登臨舊有臺。", "立盡斜陽不歸去，一聲孤雁過蓬萊。"]'),
('ceaf601b-834a-4cb2-8fcc-bd9bb2cf4034','題吳實齋北山別業','黄庚','宋','宋诗','song-poetry','','[]','北山佳景勝南山，乘興登臨眼界寬。',64,'全唐诗/poet.song.242000.json','["北山佳景勝南山，乘興登臨眼界寬。", "樵斧伐雲春谷暗，漁榔敲月夜溪寒。", "一區池占林泉勝，四面天開圖畫看。", "竹屋數間塵不到，主人日日凭闌干。"]'),
('66917a2d-8f4c-4e8e-a824-440dce508532','書館','黄庚','宋','宋诗','song-poetry','','[]','池館深深鎖翠凉，課餘多暇日偏長。',64,'全唐诗/poet.song.242000.json','["池館深深鎖翠凉，課餘多暇日偏長。", "屋連湖水琴書潤，窗近花陰筆硯香。", "吾道尚存貧亦樂，客身長健老何妨。", "十年心事閑搔首，厭聽蟬聲送夕陽。"]'),
('481e443a-75b9-4161-a70f-b2ec44053045','依綠亭','黄庚','宋','宋诗','song-poetry','','[]','數椽瀟灑瞰清漪，蕩漾烟霏欲濕衣。',64,'全唐诗/poet.song.242000.json','["數椽瀟灑瞰清漪，蕩漾烟霏欲濕衣。", "闌角寒光摇翡翠，簷牙倒影浸琉璃。", "荷邊鼓瑟遊鱼聽，柳外敲棋睡鷺飛。", "洗盡紅塵青眼客，臨流何惜賦新詩。"]'),
('77aa78b2-a74e-4174-b1b5-c7acce7a3400','秋思','黄庚','宋','宋诗','song-poetry','','[]','天容凝碧換秋容，殘暑泠然一洗空。',64,'全唐诗/poet.song.242000.json','["天容凝碧換秋容，殘暑泠然一洗空。", "梧葉多應愁夜雨，葛衣漸覺怯西風。", "十分冷淡砧聲外，一片凄凉雁影中。", "興動蓴鱸欲歸去，季鷹心事恰相同。"]'),
('7b2665c6-ca0a-435d-9c27-17cff91b14e1','題四暢圖','黄庚','宋','宋诗','song-poetry','','[]','四暢圖中四散人，籐牀對坐遣閑情。',64,'全唐诗/poet.song.242000.json','["四暢圖中四散人，籐牀對坐遣閑情。", "搔頭真有爬梳態，搐鼻應無噴嚏聲。", "捫蝨未能談世事，撚髭元不爲科名。", "一時快意皆真樂，誰把丹青寫得成。"]'),
('b3d6e16e-b222-4d1c-9374-6173822b9488','登寶林塔','黄庚','宋','宋诗','song-poetry','','[]','屹立浮圖可摘星，吟邊喜與客同登。',64,'全唐诗/poet.song.242000.json','["屹立浮圖可摘星，吟邊喜與客同登。", "闌干六曲又六曲，梯級一層又一層。", "極目江山無障礙，著身霄漢欲飛騰。", "雁來疑是題名處，拂拭殘碑問寺僧。"]'),
('7a8e4544-3070-4696-944f-dbc882dd749d','偶述','黄庚','宋','宋诗','song-poetry','','[]','漂泊江湖祇自憐，人生窮達信關天。',64,'全唐诗/poet.song.242000.json','["漂泊江湖祇自憐，人生窮達信關天。", "老來干祿心灰矣，貧不求人氣浩然。", "五斗豈能留靖節，一瓢亦足樂顔淵。", "客來問我生涯事，閉戶開書對聖賢。"]'),
('c9dfa1b0-79e8-44cf-a639-b847cdf5867f','凉夜即事','黄庚','宋','宋诗','song-poetry','','[]','凉入虛堂睡思濃，夜深剪盡燭花紅。',64,'全唐诗/poet.song.242000.json','["凉入虛堂睡思濃，夜深剪盡燭花紅。", "光摇珠箔梧桐月，香透紗厨茉莉風。", "欹枕覺來人不寐，撚鬚吟罷句難工。", "小蠻問我詩成未，詩在池塘草夢中。"]'),
('4d6e89be-4f41-4856-88c2-fb0b3fa4e652','次月山少監客京韻','黄庚','宋','宋诗','song-poetry','','[]','匹馬攙春入帝京，秋深猶未問歸程。',64,'全唐诗/poet.song.242000.json','["匹馬攙春入帝京，秋深猶未問歸程。", "一書不及因風寄，千里空教共月明。", "霄漢已隨黄鵠舉，家山應負白鷗盟。", "便須了却封侯事，衣錦歸來客亦榮。"]'),
('fa6d1710-a44c-4c18-979e-b75d2c4a5a5d','聞角','黄庚','宋','宋诗','song-poetry','','[]','譙角咿嗚到枕邊，邊情似向曲中傳。',64,'全唐诗/poet.song.242000.json','["譙角咿嗚到枕邊，邊情似向曲中傳。", "梅花三弄月將晚，榆塞一聲霜滿天。", "織錦佳人應有恨，枕戈老將想無眠。", "爭如二月春風市，賣酒樓頭聽管絃。"]'),
('9fe57e68-e089-4e43-88e4-005141c72f52','舟行送王琴所之澉州','黄庚','宋','宋诗','song-poetry','','[]','晨星寥落曙光浮，柳岸風輕送客舟。',64,'全唐诗/poet.song.242000.json','["晨星寥落曙光浮，柳岸風輕送客舟。", "萬點遠山重疊恨，一江流水淺深愁。", "淡烟茅店家家曉，白露楓林處處秋。", "獨倚蓬窗還自笑，此身漂泊愧沙鷗。"]'),
('49295c0a-f433-4022-b79b-99bf75d5c676','寄峽山胡府判','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鑑湖狂客又西湖，筆硯生涯計已迂。',64,'全唐诗/poet.song.242000.json','["鑑湖狂客又西湖，筆硯生涯計已迂。", "五斗自慚腰不折，四方安得口能餬。", "家山迢遞鄉心遠，燈火凄凉客影孤。", "莫誤風前看落雁，尺書還肯寄來無。"]'),
('9b7700f8-f247-47ab-b124-484b64cc619c','送姜仕可去館','黄庚','宋','宋诗','song-poetry','','[]','行止非人可豫謀，愛君無計爲君留。',64,'全唐诗/poet.song.242000.json','["行止非人可豫謀，愛君無計爲君留。", "張儀失策猶存舌，穆傅知機可掉頭。", "黯黯別懷江路晚，蕭蕭行李驛亭秋。", "明年我亦携書去，不落人間第二籌。"]'),
('7b900ab6-adae-4a5f-a4e1-3ca932d96499','梅龍','黄庚','宋','宋诗','song-poetry','','[]','孤根蟠屈浸冰壺，蟄裏陽和發朽枯。',64,'全唐诗/poet.song.242000.json','["孤根蟠屈浸冰壺，蟄裏陽和發朽枯。", "雪樹鱗封寒水玉，月梢頷吐夜明珠。", "暗香吹冷龍涎濕，疏影涵清蛻骨癯。", "安得華光葉公筆，共描雲水卧雲圖。"]'),
('ab65f973-b95c-465a-93a7-4515ee2d3b7b','江湖偉觀','黄庚','宋','宋诗','song-poetry','','[]','環峙山川秀氣鍾，人煙樓閣鬰重重。',64,'全唐诗/poet.song.242000.json','["環峙山川秀氣鍾，人煙樓閣鬰重重。", "潮生潮落東西浙，雲去雲來南北峰。", "海曙扶桑紅影濕，堤春楊柳綠陰濃。", "子胥已遠岳侯死，斗柄聊洗磊塊胸。"]'),
('4d281167-b6c9-4304-ad47-a24dcc9d53b4','隨隠爲祝南山賦','黄庚','宋','宋诗','song-poetry','','[]','踪跡何拘似白雲，不專丘壑避紅塵。',64,'全唐诗/poet.song.242000.json','["踪跡何拘似白雲，不專丘壑避紅塵。", "田堪耕稼即莘野，水可釣魚皆渭濱。", "無礙滯心寧擇地，有幽閑處便容身。", "一筇忽入青山去，豈是終南捷徑人。"]'),
('e4cb2b24-57f8-499f-952a-80e6cc952cbe','春日郊居','黄庚','宋','宋诗','song-poetry','','[]','卜築幽居慰寂寥，數椽茅屋傍江郊。',64,'全唐诗/poet.song.242000.json','["卜築幽居慰寂寥，數椽茅屋傍江郊。", "庭前滕薛筍爭長，籬下陳雷蔓結交。", "杏圃花香蜂課蜜，芹塘泥暖燕營巢。", "山窗對景渾無事，吟得詩成手自抄。"]'),
('06735301-d7f0-49c1-99a8-6cceeb2dc128','偶書呈王修竹','黄庚','宋','宋诗','song-poetry','','[]','琴心不復寄松蘿，賀鑑湖邊水自波。',64,'全唐诗/poet.song.242000.json','["琴心不復寄松蘿，賀鑑湖邊水自波。", "晚節黄花秋思淡，夕陽紅樹客愁多。", "何時歸鶴招丁令，有意逃漁侶志和。", "不管白頭烏帽落，西風一曲付狂歌。"]'),
('c59caf0b-b601-409d-8c2b-0b2bcf886aa4','寄鄭樞山','黄庚','宋','宋诗','song-poetry','','[]','起敬英聲亦有年，酒邊曾見錦囊篇。',64,'全唐诗/poet.song.242000.json','["起敬英聲亦有年，酒邊曾見錦囊篇。", "吟情六義初刪後，古意三爻未畫前。", "放曠嗣宗應絕俗，清狂太白不妨仙。", "如今海內無工部，誰肯題詩寄鄭虔。"]'),
('bf67fa3f-5192-4b82-a473-9ee6d8dcbce8','燈花','黄庚','宋','宋诗','song-poetry','','[]','發生元不假栽培，一點春從午夜回。',64,'全唐诗/poet.song.242000.json','["發生元不假栽培，一點春從午夜回。", "自喜結根依小草，不愁飛片點蒼苔。", "熒熒有豔蛾頻撲，澹澹無香蝶不猜。", "窗下敲棋紅燼落，更深約客不曾來。"]'),
('8a66d675-6c6c-49d1-8511-1b94685c42f9','樂道','黄庚','宋','宋诗','song-poetry','','[]','門掩荒苔客到稀，閒情已與世相違。',64,'全唐诗/poet.song.242000.json','["門掩荒苔客到稀，閒情已與世相違。", "胸中宇宙自然景，眼底江山不盡詩。", "雲淡風輕皆道體，鳶飛魚躍總天機。", "吾心與物同真樂，此處寧容俗子知。"]'),
('f359e68b-b3ae-4458-8a20-18fed95ebbe3','次毛一齋韻','黄庚','宋','宋诗','song-poetry','','[]','詩夢驚殘何處棋，書窗又是夕陽時。',64,'全唐诗/poet.song.242000.json','["詩夢驚殘何處棋，書窗又是夕陽時。", "柳陰分綠籠琴几，花片飛紅點硯池。", "覽鏡自憐添白髮，傳杯不復倩蛾眉。", "東風故國年年恨，惟有啼春杜宇知。"]'),
('1e40f799-aef3-433a-a3ce-bce7df4b4112','寄月山少監','黄庚','宋','宋诗','song-poetry','','[]','一片襟懷海樣寬，眉頭肯爲別離攢。',64,'全唐诗/poet.song.242000.json','["一片襟懷海樣寬，眉頭肯爲別離攢。", "臂鷹慣識從君樂，汗馬寧辭行路難。", "角带邊聲關月冷，雁傳鄉信塞雲寒。", "歸來未許東山卧，見說蒼生望謝安。"]'),
('7153b72e-929b-446e-ba65-b7a259c436db','送文正公遺像與王東廬','黄庚','宋','宋诗','song-poetry','','[]','古畫從來寶繪堂，遺君敢借舊珍藏。',64,'全唐诗/poet.song.242000.json','["古畫從來寶繪堂，遺君敢借舊珍藏。", "貌存故國三公貴，澤衍來孫百世芳。", "家廟幾年成闕典，宗枝此日倍增光。", "當時種德根苗遠，分得槐陰到鶴鄉。"]'),
('af98dfe6-b1e7-4601-9479-cafc2b6a9b7d','遊西湖次毛玉田韻','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','觸目錢塘昨夢非，行春載酒憶當時。',64,'全唐诗/poet.song.242000.json','["觸目錢塘昨夢非，行春載酒憶當時。", "花間不輾香輪入，柳外空鞭駿馬飛。", "落日荒山和靖墓，斷雲流水子胥祠。", "忘情鷗鷺閒於我，應笑江湖客未歸。"]'),
('3f7985f5-a25e-4b01-905a-1389ee5eede1','故國有懷呈任子宏提舉','黄庚','宋','宋诗','song-poetry','','[]','十年不作還家夢，荒草深深鎖竹扉。',64,'全唐诗/poet.song.242000.json','["十年不作還家夢，荒草深深鎖竹扉。", "無主落花隨水去，有情啼鳥勸人歸。", "儒冠寥落風流減，客路凄凉故舊稀。", "何日携琴賦歸去，踏雲自採故山薇。"]'),
('dd6c8111-0988-4d93-ba80-7ffa69e50b85','寒夜即事','黄庚','宋','宋诗','song-poetry','','[]','倚徧闌干更漏長，柔髭撚斷爲詩忙。',64,'全唐诗/poet.song.242000.json','["倚徧闌干更漏長，柔髭撚斷爲詩忙。", "清分梅影夜宜月，寒入雁聲天正霜。", "懷古頓添孤客恨，追歡難憶少年狂。", "讀書窗下篝燈坐，一卷離騷一篆香。"]'),
('650d3a1d-2528-4a63-8eed-23a9a1b06986','謝章平遠惠筆','黄庚','宋','宋诗','song-poetry','','[]','管城二子樣尖新，分惠山房勝餽金。',64,'全唐诗/poet.song.242000.json','["管城二子樣尖新，分惠山房勝餽金。", "淮兔拔毛誇匠巧，魯魚正字見功深。", "抄書未得纖毫力，握管難忘一寸心。", "揮翰玉堂無夢到，雅宜茅屋寫清吟。"]'),
('31157ddd-c7b5-442e-8beb-b624c849879c','龍江館舍','黄庚','宋','宋诗','song-poetry','','[]','幽棲俗事不相關，家在青松翠竹間。',64,'全唐诗/poet.song.242000.json','["幽棲俗事不相關，家在青松翠竹間。", "繞屋四圍都是水，隔林一片不多山。", "詩篇陶寫清秋景，書冊消磨白日閒。", "門外沙鷗如舊識，忘機飛去又飛還。"]'),
('0a5a2733-19ba-46d3-b3b3-3e31f6da2f50','元日','黄庚','宋','宋诗','song-poetry','','[]','睡眼朦朧撐不開，雞聲唱曉夢驚回。',64,'全唐诗/poet.song.242000.json','["睡眼朦朧撐不開，雞聲唱曉夢驚回。", "竹爐尚有殘冬火，柏酒初斟新歲杯。", "身世百年如夢幻，功名兩字已心灰。", "門無賀客清閑甚，自汲寒泉浸古梅。"]'),
('2c7de3cf-0792-4195-845e-923831894fa6','偶題','黄庚','宋','宋诗','song-poetry','','[]','一春過半近清明，點滴簷聲未肯晴。',64,'全唐诗/poet.song.242000.json','["一春過半近清明，點滴簷聲未肯晴。", "細柳雨中垂綠重，殘花風裏落紅輕。", "世間白髮在公道，眼底青山不世情。", "富貴倘來忙不得，人生何必苦營營。"]'),
('8dc8cf58-c9c4-47a6-bdb6-bbf3a05532ed','俞景仁教諭相過','黄庚','宋','宋诗','song-poetry','','[]','江雲舒卷弄陰晴，新綠園林似染成。',64,'全唐诗/poet.song.242000.json','["江雲舒卷弄陰晴，新綠園林似染成。", "花怯曉風寒蝶夢，柳愁春雨濕鶑聲。", "棲遲茅屋無塵事，深閉柴門遠俗情。", "佳客相過慰岑寂，酒邊閑把近詩評。"]'),
('d257d40e-d10e-461e-96ad-1ad1c462929d','修竹有樓名與造物游對秦望山五雲門','黄庚','宋','宋诗','song-poetry','','[]','秦望諸山隠几看，仙居縹緲五雲端。',64,'全唐诗/poet.song.242000.json','["秦望諸山隠几看，仙居縹緲五雲端。", "天高地迥三千界，月白風清十二闌。", "滄海氣侵珠珮濕，明河影逼玉簫寒。", "超然身在鴻濛上，何必蓬萊跨紫鸞。"]'),
('9bf66fbd-9ff3-4dc0-beea-b4a6e8c7aac0','修竹宴客廣寒遊亭分韻得香字','黄庚','宋','宋诗','song-poetry','','[]','銀橋疑駕海天長，金粟離離照玉觴。',64,'全唐诗/poet.song.242000.json','["銀橋疑駕海天長，金粟離離照玉觴。", "影浸山河瓊殿冷，舞分風露羽衣香。", "亦知廣莫元無野，却笑溫柔別有鄉。", "閒折一枝驚昨夢，素娥憐我授玄霜。"]'),
('4b7c8b2b-43e2-4ae3-90a4-afaabc869248','酒邊呈張景純','黄庚','宋','宋诗','song-poetry','','[]','蓬萊閣上笑談餘，別後思君看畫圖。',64,'全唐诗/poet.song.242000.json','["蓬萊閣上笑談餘，別後思君看畫圖。", "萍水相逢俱老矣，家山自好盍歸乎。", "清風一榻莊周蝶，明月扁舟范蠡湖。", "此是達人真樂事，客中何必歎窮途。"]'),
('c15c3822-aba6-4f9b-bb81-38862ecb39df','江上客懷','黄庚','宋','宋诗','song-poetry','','[]','鏡裏從渠白髮添，吟邊抵掌復掀髯。',64,'全唐诗/poet.song.242000.json','["鏡裏從渠白髮添，吟邊抵掌復掀髯。", "十年爲客甘清苦，一枕忘情付黑甜。", "短褐怯風綿未絮，破窗漏月紙重粘。", "梅花應念人孤寂，寒夜吹香入竹簾。"]'),
('43e24cca-1c09-4971-97c1-104e6887e2f5','夜坐','黄庚','宋','宋诗','song-poetry','','[]','香篆烟銷夜氣清，篝燈開卷遣閒情。',64,'全唐诗/poet.song.242000.json','["香篆烟銷夜氣清，篝燈開卷遣閒情。", "半窗月落梅無影，三徑風來竹有聲。", "樂道何須圖富貴，讀書元不爲功名。", "白雲滿榻便高卧，欹枕詩成夢不成。"]'),
('d0bd50ec-3d72-4908-bce0-8322d0772d91','挽衛山齋  其一','黄庚','宋','宋诗','song-poetry','','[]','楹夢驚殘忽告終，儒林多士失宗工。',64,'全唐诗/poet.song.242000.json','["楹夢驚殘忽告終，儒林多士失宗工。", "雲間便覺無清氣，江上誰能繼古風。", "蕙帳夜闌孤鶴怨，茅齋人去九山空。", "我來豈爲私情哭，痛哭君亡吾道窮。"]'),
('fba2de63-7cb2-4255-939b-f2a0c561cf5f','挽衛山齋  其二','黄庚','宋','宋诗','song-poetry','','[]','武公後裔有仍孫，德望才名世所尊。',64,'全唐诗/poet.song.242000.json','["武公後裔有仍孫，德望才名世所尊。", "擬向山中專註易，忽傳地下趣修文。", "月樓不復賡詩句，春閣猶思共酒樽。", "痛恨死生千古隔，西風吹淚濕秋雲。"]'),
('73d56c1d-09f0-44d7-9f53-92eb6301388e','送任子敏司丞赴北','黄庚','宋','宋诗','song-poetry','','[]','鞭影拖雲入帝京，少年正好作功名。',64,'全唐诗/poet.song.242000.json','["鞭影拖雲入帝京，少年正好作功名。", "不辭驛騎三千里，欲奮鵬摶九萬程。", "白玉樓中揮翰墨，黄金臺上被恩榮。", "何須折柳送行色，只寫詩篇話別情。"]'),
('9b9368a0-f0a9-4add-98f2-252944f8abb0','和俞教授見寄韵','黄庚','宋','宋诗','song-poetry','','[]','天邊日月似梭飛，百歲光陰難預期。',64,'全唐诗/poet.song.242000.json','["天邊日月似梭飛，百歲光陰難預期。", "有酒不妨留野客，無錢何惜典春衣。", "江山猶記登臨處，身世都非少壯時。", "晚景清閑宜學道，黄庭一卷究玄微。"]'),
('74af64a0-e961-42b7-bda8-71af2cc72111','任復齋池中有瑞蓮命予賦之','黄庚','宋','宋诗','song-poetry','','[]','芙蕖開處傍池亭，花結雙頭媚晚晴。',64,'全唐诗/poet.song.242000.json','["芙蕖開處傍池亭，花結雙頭媚晚晴。", "兩隗駢肩如欲語，二喬並首似含情。", "同心凈植真奇種，聯蒂騰芳以瑞名。", "若使濂溪當日見，愛蓮有說恐難評。"]'),
('7223320a-8690-4f23-a0b3-c19172044c37','鹽','黄庚','宋','宋诗','song-poetry','','[]','同絺入貢載遺經，分賜羣臣羨水晶。',64,'全唐诗/poet.song.242000.json','["同絺入貢載遺經，分賜羣臣羨水晶。", "潤下作醎從海産，熬波出素似天成。", "享神潔白惟形似，富貴珍奇以寶名。", "此物可方爲相事，他時商鼎用調羹。"]'),
('26e79e8e-b65f-48a0-aa95-a887e2423a63','缾笙','黄庚','宋','宋诗','song-poetry','','[]','熱中竟日自煎烹，音節都從一氣生。',64,'全唐诗/poet.song.242000.json','["熱中竟日自煎烹，音節都從一氣生。", "緩緩煮湯方蟹眼，微微聒耳忽蠅聲。", "頻驚清夢愁無寐，似訴羈情歎不平。", "却笑書生那解此，聯詩石鼎羨彌明。"]'),
('0857b398-4d03-4547-9183-81852e157c45','書懷','黄庚','宋','宋诗','song-poetry','','[]','杜門已與俗相違，苔徑荒凉轍迹稀。',64,'全唐诗/poet.song.242000.json','["杜門已與俗相違，苔徑荒凉轍迹稀。", "自愛清凉忘世慮，肯求富貴役心機。", "隠居盤谷勝金谷，耐著麻衣鄙錦衣。", "百歲光陰皆夢境，且看兔走與烏飛。"]'),
('73587a81-9a8d-413c-8c19-112cd94374b4','和杜柳溪韻','黄庚','宋','宋诗','song-poetry','','[]','安貧樂道豈卑微，肯羨黄金带十圍。',64,'全唐诗/poet.song.242000.json','["安貧樂道豈卑微，肯羨黄金带十圍。", "爵列三公今却有，齒踰七袠古來稀。", "滿頭霜雪客懷老，過眼烟雲人是非。", "皎皎白駒在空谷，好賢誰復詠緇衣。"]'),
('5db47b97-3c37-44ad-adf6-6d04c0c4c8cb','金潤玉隠廢寺閒居','黄庚','宋','宋诗','song-poetry','','[]','梵剎當年聚衆僧，叢林深處著禪扃。',64,'全唐诗/poet.song.242000.json','["梵剎當年聚衆僧，叢林深處著禪扃。", "金沙布地階無土，玉軸堆函藏有經。", "雲樹千尋張翠蓋，烟蘿一片展青屏。", "星移物換今寥落，古寺猶存柏子庭。"]'),
('2cee5ae9-840b-41eb-8187-84fee089a517','和葺廬韻','黄庚','宋','宋诗','song-poetry','','[]','地僻渾無車馬喧，禪房修飾稱居安。',64,'全唐诗/poet.song.242000.json','["地僻渾無車馬喧，禪房修飾稱居安。", "莊嚴固是由心造，丹雘多應被眼瞞。", "佛法不須身外覓，世緣只作夢中看。", "我來欲問無生話，萬頃西江一吸乾。"]'),
('5389bc45-b601-4012-96d0-d59bc941c81a','偶成簡任肅齋教諭  其一','黄庚','宋','宋诗','song-poetry','','[]','百年光景易侵尋，消遣閒愁只苦吟。',64,'全唐诗/poet.song.242000.json','["百年光景易侵尋，消遣閒愁只苦吟。", "但覺筆頭風雨濕，不知鬢底雪霜侵。", "冥鴻已負九霄志，老驥空懷千里心。", "富貴倘來應有命，何須彈鋏扣知音。"]'),
('0cab0d0b-38bb-4d14-bc5f-be51610b8813','偶成簡任肅齋教諭  其二','黄庚','宋','宋诗','song-poetry','','[]','百歲光陰一轉蓬，晚年不與少年同。',64,'全唐诗/poet.song.242000.json','["百歲光陰一轉蓬，晚年不與少年同。", "事因錯處人方省，詩到窮時句始工。", "獻賦未逢楊得意，憐才難遇杜司空。", "有時追憶昇平事，猶道繁華是夢中。"]'),
('1f226883-a6e3-461a-896b-3cba5cc92f1b','偶成簡任肅齋教諭  其三','黄庚','宋','宋诗','song-poetry','','[]','貧病交攻久廢詩，蕭然一室獨棲遲。',64,'全唐诗/poet.song.242000.json','["貧病交攻久廢詩，蕭然一室獨棲遲。", "酒錢已盡琴將典，瓶粟無儲鶴亦饑。", "豪傑不多陳仲舉，結交惟欠魏無知。", "簞瓢鐘鼎都休計，畢竟窮通各有時。"]'),
('fc20cb13-c4d8-4778-8a35-91dc597bcd1a','奉謝月山太守','黄庚','宋','宋诗','song-poetry','','[]','太守相過慶誕辰，貴能下賤見公心。',64,'全唐诗/poet.song.242000.json','["太守相過慶誕辰，貴能下賤見公心。", "行厨鼎列雙魚美，衆客咸瞻五馬臨。", "曲唱駱駝誇白雪，杯傳鸚鵡擁青衿。", "寵頒束帛尤增感，恩與滄溟一樣深。"]'),
('31c06b19-c9c4-419a-804e-a900912eef27','夜坐即事','黄庚','宋','宋诗','song-poetry','','[]','霜氣侵窗冷客氈，青燈白髮老堪憐。',64,'全唐诗/poet.song.242000.json','["霜氣侵窗冷客氈，青燈白髮老堪憐。", "光陰明日又明日，世事一年難一年。", "眼底江山元似舊，胸中風月本無邊。", "道人不作陽臺夢，紙帳梅花伴獨眠。"]'),
('1dc3b520-c7e0-4edf-8c0d-fffdd445f1f0','和茅亦山先生雜詠  其一','黄庚','宋','宋诗','song-poetry','','[]','風柳吹花糝白氈，鶑愁蝶恨有誰憐。',64,'全唐诗/poet.song.242000.json','["風柳吹花糝白氈，鶑愁蝶恨有誰憐。", "不知春事又三月，堪歎人生無百年。", "清氣長留詩卷裏，閒愁不到酒樽邊。", "山窗晝永渾無事，一榻分雲枕易眠。"]'),
('4ac34ce2-f952-483d-ac84-c109ad0a1480','和茅亦山先生雜詠  其二','黄庚','宋','宋诗','song-poetry','','[]','身世飄浮水上蓬，閒中清事有誰同。',64,'全唐诗/poet.song.242000.json','["身世飄浮水上蓬，閒中清事有誰同。", "吟窗夢草添詩料，畫筆生花奪化工。", "酒後烏烏時擊缶，愁來咄咄自書空。", "園林寂寞春何處，春在桑麻雨露中。"]'),
('125505d5-37dd-4b60-ba75-fc0a51a9772c','和茅亦山先生雜詠  其三','黄庚','宋','宋诗','song-poetry','','[]','破硯塵封懶賦詩，晚年才思覺衰遲。',64,'全唐诗/poet.song.242000.json','["破硯塵封懶賦詩，晚年才思覺衰遲。", "躭書自笑已成癖，煮字元來不療饑。", "風月滿懷詩可寫，雪霜侵鬢鏡先知。", "太公八十方榮遇，把釣溪邊更待時。"]'),
('e7a68d83-4012-48a0-9c62-f14233e7431a','端午月山主人酒邊即事  其一','黄庚','宋','宋诗','song-poetry','','[]','窗外葵榴照眼明，香蒲沁酒注銀瓶。',64,'全唐诗/poet.song.242000.json','["窗外葵榴照眼明，香蒲沁酒注銀瓶。", "自無飲量堪同醉，非慕清名傚獨醒。", "一日沈湘悲楚客，千年弔古讀騷經。", "他鄉記節聊隨俗，艾虎硃符挂戶庭。"]'),
('190a6b8d-b41c-4f97-bc0a-de698bd33dc2','端午月山主人酒邊即事  其二','黄庚','宋','宋诗','song-poetry','','[]','時序催人易白頭，端陽懷古客添愁。',64,'全唐诗/poet.song.242000.json','["時序催人易白頭，端陽懷古客添愁。", "硃符不寫湘纍恨，角黍難包楚國羞。", "記節何妨斟蟻酒，奪標無復見龍舟。", "高歌思遠樓前路，掩雨珠簾今在不。"]'),
('9d865b50-3ae2-4839-863a-429510f1e4c6','寄謝蔡松江路教','黄庚','宋','宋诗','song-poetry','','[]','一別丰標又一旬，尺書多荷寄殷勤。',64,'全唐诗/poet.song.242000.json','["一別丰標又一旬，尺書多荷寄殷勤。", "交遊滿眼誰知己，契闊關心獨憶君。", "蕙帳夢寒同夜月，松江人遠隔秋雲。", "明朝便買扁舟去，來訪貞陽舊廣文。"]'),
('484cf0ce-121b-4b05-bcb6-903fd3a984bc','和杜柳溪韻','黄庚','宋','宋诗','song-poetry','','[]','白髮垂垂一老夫，年來漸覺世情疏。',64,'全唐诗/poet.song.242000.json','["白髮垂垂一老夫，年來漸覺世情疏。", "石牀夢冷和雲卧，茅屋燈殘共月居。", "客至何妨賒魯酒，家貧不肯典唐書。", "羨君種柳清溪上，借我苔機學釣魚。"]'),
('32aaac20-d695-4ef1-aae4-60656a8f2c63','和茅亦山秋夜感懷','黄庚','宋','宋诗','song-poetry','','[]','老來吟拙自知羞，好景無詩未易酬。',64,'全唐诗/poet.song.242000.json','["老來吟拙自知羞，好景無詩未易酬。", "湖海愁看今夜月，功名虛度十年秋。", "清光偏照盧仝屋，孤影自登王粲樓。", "我欲乘風蟾窟去，安能與世共沉浮。"]'),
('a1c9cb88-2689-4cd5-9265-af52212e0db4','茅亦山相過','黄庚','宋','宋诗','song-poetry','','[]','故人過我竹邊居，談笑從容樂有餘。',64,'全唐诗/poet.song.242000.json','["故人過我竹邊居，談笑從容樂有餘。", "洗盞共嘗春甕酒，挑燈對讀夜窗書。", "歸來尚憶淵明菊，高卧誰知諸葛廬。", "醉後達觀今古事，寥寥千載只須臾。"]'),
('9af0df60-93d5-4043-a0e4-4faa18803210','上廉訪分司官','黄庚','宋','宋诗','song-poetry','','[]','行部巡荒察吏奸，皇皇使節古刑官。',64,'全唐诗/poet.song.242000.json','["行部巡荒察吏奸，皇皇使節古刑官。", "聲摇天上星辰動，清逼雲間風露寒。", "肅政嚴持三尺法，卹民特放一分寬。", "香名已覆金甌底，便作他年宰相看。"]'),
('98b83b7c-9279-4474-91e9-3d035fb51f44','和鄭樞山竹夫人韻','黄庚','宋','宋诗','song-poetry','','[]','玉環傾國起胡兵，有色終汙後世名。',64,'全唐诗/poet.song.242000.json','["玉環傾國起胡兵，有色終汙後世名。", "九夏專房何在貌，一身空洞若爲情。", "寵名本自無心得，婦節從來澈骨清。", "愁見婕妤秋後扇，共懷幽恨幾時平。"]'),
('1fe78842-0e7c-4aa5-9104-5521e8677968','斑竹夫人','黄庚','宋','宋诗','song-poetry','','[]','汗青書墨沁肌凉，李衛曾携近竹牀。',64,'全唐诗/poet.song.242000.json','["汗青書墨沁肌凉，李衛曾携近竹牀。", "眼孔盈盈看熟客，淚痕點點泣秋房。", "湘紋冷淡宜湘簟，玉體玲瓏稱玉郎。", "秦虢流封無夢到，傍人空以睡爲鄉。"]'),
('5cd9e274-ea25-4287-85c7-16950b61ce97','遊虎丘山寺','黄庚','宋','宋诗','song-poetry','','[]','浮生偷得片時閒，古寺尋僧借景看。',64,'全唐诗/poet.song.242000.json','["浮生偷得片時閒，古寺尋僧借景看。", "樓閣倚雲山氣濕，轆轤捲水澗聲寒。", "地埋吳劍痕猶在，碑刻唐詩字未漫。", "寄榻禪房不知曉，起來松日已三竿。"]'),
('5ac9cf73-a79e-46c2-b5fa-9c1457afbdca','賈秋壑圃','黄庚','宋','宋诗','song-poetry','','[]','不學蒼龍卧浙東，驚飈吟珮墮青璁。',64,'全唐诗/poet.song.242000.json','["不學蒼龍卧浙東，驚飈吟珮墮青璁。", "既無良策安江左，空有名園似洛中。", "危棧連雲晴亦雨，飛樓近海夜生風。", "人間富貴皆塵土，回首吳山落照紅。"]'),
('cbe1c56e-d069-415d-bb31-123f20c5ab3d','聞鶴','黄庚','宋','宋诗','song-poetry','','[]','寒蟾初上海雲收，何處仙禽過庾樓。',64,'全唐诗/poet.song.242000.json','["寒蟾初上海雲收，何處仙禽過庾樓。", "清夜照人千里月，碧天警露一聲秋。", "玉笙縹緲緱山去，羽袂蹁躚赤壁遊。", "回首女牆舊時事，千年華表動新愁。"]'),
('df485b16-8dc9-42a8-8539-172036fb7d62','和毛宣尉蓬萊閣韻','黄庚','宋','宋诗','song-poetry','','[]','傑閣翬飛翠靄間，蓬萊元不在人寰。',64,'全唐诗/poet.song.242000.json','["傑閣翬飛翠靄間，蓬萊元不在人寰。", "綠圍城郭千村水，青逼簾櫳四面山。", "華表鶴歸遼海遠，高臺鳳去夕陽間。", "我來倚遍闌干月，雲鎖重門夜不關。"]'),
('2ea9d4c4-c1fa-49e7-8bd3-643053a28866','送張按察移節江陵','黄庚','宋','宋诗','song-poetry','','[]','滿載琴書事宦遊，皇皇使節重咨諏。',64,'全唐诗/poet.song.242000.json','["滿載琴書事宦遊，皇皇使節重咨諏。", "蒲帆風飽三千里，繡斧霜寒十六州。", "荆渚行觀新德政，越人共憶舊風流。", "市橋衰柳難攀折，只拗梅花送去舟。"]'),
('0a3c9e66-e4df-41b1-8272-80adf6981139','次鄭朴翁國正見寄','黄庚','宋','宋诗','song-poetry','','[]','雲深紅日出林遲，晞髮簷前力未衰。',64,'全唐诗/poet.song.242000.json','["雲深紅日出林遲，晞髮簷前力未衰。", "老愛歸田追靖節，狂思入海訪安期。", "春風巷陌楊花後，故國江山杜宇時。", "一種閒愁無著處，倚窗重讀寄來詩。"]'),
('5e6d7494-5da5-473b-91b8-ced74217fe5e','漁舍觀梅寄修竹','黄庚','宋','宋诗','song-poetry','','[]','寒雲漠漠護牆陰，瀟灑梅枝出竹林。',64,'全唐诗/poet.song.242000.json','["寒雲漠漠護牆陰，瀟灑梅枝出竹林。", "影落荒磯和雪釣，香浮老瓦带春斟。", "幾憑水驛傳芳信，祇許沙鷗識素心。", "回首孤山千樹遠，扁舟乘興夢中尋。"]'),
('f8bfa7fc-0a3e-4449-919c-51b731ea8a94','清明','黄庚','宋','宋诗','song-poetry','','[]','清明時節已春深，白髮蕭疏忽滿簪。',64,'全唐诗/poet.song.242000.json','["清明時節已春深，白髮蕭疏忽滿簪。", "萍梗一生孤客恨，松楸千里故鄉心。", "浸花窗下分紅影，插柳簷前借綠陰。", "幸有故人同笑語，不妨沽酒共清吟。"]'),
('e83db4fa-de53-48cf-b1d3-2ba4e89baaa2','贈大禪寺昉上人','黄庚','宋','宋诗','song-poetry','','[]','佛屋參差傍水涯，天然富貴屬僧家。',64,'全唐诗/poet.song.242000.json','["佛屋參差傍水涯，天然富貴屬僧家。", "油幢碧立當軒竹，步障紅圍繞檻花。", "隠隠磬聲春晝永，停停塔影夕陽斜。", "白頭道者留連客，自汲山泉煮石茶。"]'),
('c7136b3e-5c30-4985-82d9-38fe772b74b3','贈通玄觀道士竹鄉','黄庚','宋','宋诗','song-poetry','','[]','通玄道士苦修行，坐見桑田幾變更。',64,'全唐诗/poet.song.242000.json','["通玄道士苦修行，坐見桑田幾變更。", "雲屋苔封燒藥竈，風林花落煮茶鐺。", "休糧賸有青松啖，却老應無白髮生。", "月滿竹鄉乘鶴去，欲邀子晉學吹笙。"]'),
('e50edd67-4a7b-474f-9f40-645369c9e6ba','夜坐','黄庚','宋','宋诗','song-poetry','','[]','醉月飛觴興未闌，蓬壺影裏漏聲殘。',64,'全唐诗/poet.song.242000.json','["醉月飛觴興未闌，蓬壺影裏漏聲殘。", "碧浮金鼎香脂暖，紅閃銀臺燭泪乾。", "艷曲喜聽催拍近，狂歌自覺入腔難。", "賞心樂事輸年少，一點閒愁了不干。"]'),
('fdf14dce-1742-468f-9a55-d10b9b9c0b62','隠居','黄庚','宋','宋诗','song-poetry','','[]','編茅卜隠讀書林，門掩蒼苔一徑深。',64,'全唐诗/poet.song.242000.json','["編茅卜隠讀書林，門掩蒼苔一徑深。", "當戶曉山長識面，臨窗夜月獨知心。", "花圍錦繡翻紅影，竹列琅玕舞翠陰。", "別是一般清富貴，何須滿塢積黄金。"]'),
('ae064f1d-3ff9-4f72-bf78-55312d96e334','見梅','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孤根偷轉一分陽，枝北枝南次第芳。',64,'全唐诗/poet.song.242000.json','["孤根偷轉一分陽，枝北枝南次第芳。", "照水曉粧冰鏡冷，橫空雪樹凍雲香。", "未成林實調金鼎，先占春魁伴玉堂。", "因憶西湖林處士，年年覓句爲伊忙。"]'),
('699194bc-9233-4e9e-be91-aee8a53eb7f1','挽任宅雲','黄庚','宋','宋诗','song-poetry','','[]','方擬榮除上玉堂，玉樓有召返仙鄉。',64,'全唐诗/poet.song.242000.json','["方擬榮除上玉堂，玉樓有召返仙鄉。", "才過賈誼同年少，齒長顔回一歲亡。", "師友交情從此絕，死生異路實堪傷。", "雲邊宅在人何在，腸斷西風淚幾行。"]'),
('69b41dec-032d-45c9-a660-e73bf255e8cb','寄王愛梅','黄庚','宋','宋诗','song-poetry','','[]','諸生歸去暮庭空，塔下遊觀倚瘦筇。',64,'全唐诗/poet.song.242000.json','["諸生歸去暮庭空，塔下遊觀倚瘦筇。", "千尺寶輪擎海月，七層金鐸語天風。", "升堂儘可同僧飯，持鉢何須聽寺鐘。", "好把新詩題舊壁，他年應有碧紗籠。"]'),
('edbfb206-6215-426a-9fc6-f6f334776d43','送人歸洛','黄庚','宋','宋诗','song-poetry','','[]','白眉公子氣昂昂，年少多才姓氏香。',64,'全唐诗/poet.song.242000.json','["白眉公子氣昂昂，年少多才姓氏香。", "腹飽儒書宗孔孟，心傳醫學祖岐黄。", "秋亭聽鶴遊吳會，春館看花憶洛陽。", "老我自憐身是客，江湖又送客還鄉。"]'),
('10b80228-ef96-4453-a037-8da2ee9c737a','上李承旨學士  其一','黄庚','宋','宋诗','song-poetry','','[]','儒林學海老宗師，每恨聞名識面遲。',64,'全唐诗/poet.song.242000.json','["儒林學海老宗師，每恨聞名識面遲。", "一部山川司馬記，百篇風月謫仙詩。", "玉堂揮翰思當日，金鼎調元定此時。", "抱負大才應大用，行看事業邁周伊。"]'),
('7fead612-bf49-471c-b4ef-f94b711eda03','上李承旨學士  其二','黄庚','宋','宋诗','song-poetry','','[]','表表聲名動縉紳，金鑾奏事舊詞臣。',64,'全唐诗/poet.song.242000.json','["表表聲名動縉紳，金鑾奏事舊詞臣。", "胸中千古淵源學，天下十分端正人。", "猶記演綸依日月，行看聽履上星辰。", "枝南枝北雲山異，何日摳衣拜後塵。"]'),
('ab789dd8-7afb-45db-9208-0615e719c292','上李承旨學士  其三','黄庚','宋','宋诗','song-poetry','','[]','中朝人物總稱賢，恬退閒居又幾年。',64,'全唐诗/poet.song.242000.json','["中朝人物總稱賢，恬退閒居又幾年。", "獨抱丹心長戀闕，因思綠野且歸田。", "未應雋軌淹東魯，行看文星照北燕。", "見說君王思國老，鶴書即下九重天。"]'),
('8985fd8f-cc77-49fd-b7c9-c7e796d7e72a','寄月山少監','黄庚','宋','宋诗','song-poetry','','[]','南北相望各一天，江湖久別思凄然。',64,'全唐诗/poet.song.242000.json','["南北相望各一天，江湖久別思凄然。", "迢遥道路三千里，倏忽光陰五六年。", "清節立朝君可羨，白頭爲客我堪憐。", "折梅難寄江南信，惟有新詩數十篇。"]'),
('25fd14f3-7270-4fd9-9b23-41ac877fdb18','哭別月邨  其一','黄庚','宋','宋诗','song-poetry','','[]','交遊惟子獨相知，此老天胡不憗遺。',64,'全唐诗/poet.song.242000.json','["交遊惟子獨相知，此老天胡不憗遺。", "行輩凋零亡益友，文風寥落失儒師。", "在生曾與傳遺像，臨死猶能寄別詩。", "月落邨空人不見，傷心千古隔幽期。"]'),
('7e680952-3615-46a2-9cf1-3c15d819fdae','哭別月邨  其二','黄庚','宋','宋诗','song-poetry','','[]','三山秀氣孕英奇，表表才名冠一時。',64,'全唐诗/poet.song.242000.json','["三山秀氣孕英奇，表表才名冠一時。", "唐殿策高蕡不第，荆州人去粲何依。", "傳家有子猶堪羨，埋骨無山亦可悲。", "留得帚金詩稿在，燈窗讀罷淚沾衣。"]'),
('4be165da-c875-4645-b0ce-6fd5ea436823','和仇山村九日吟卷','黄庚','宋','宋诗','song-poetry','','[]','暮秋景物覺荒凉，觸景凭高遡杳茫。',64,'全唐诗/poet.song.242000.json','["暮秋景物覺荒凉，觸景凭高遡杳茫。", "歸隠清如陶靖節，苦吟瘦似沈東陽。", "烟橫晚浦蒹葭碧，霜落寒林橘柚黄。", "追想漢宮當日事，賜萸宴罷謝君王。"]'),
('c5fdcb20-7dc9-4857-bc07-baff1aabbbe1','寄錢竹深','黄庚','宋','宋诗','song-poetry','','[]','夢斷膏粱記幾年，捨身事佛絕塵緣。',64,'全唐诗/poet.song.242000.json','["夢斷膏粱記幾年，捨身事佛絕塵緣。", "把茅蓋屋孤峰頂，片衲蒙頭萬竹邊。", "支遁才高交杜老，參寥詩好動蘇仙。", "何當盡棄人間事，特地來參一擊禪。"]'),
('eb79f497-a042-42c6-ae0b-fddab4eb1454','見天地心','黄庚','宋','宋诗','song-poetry','','[]','乾坤主宰妙難窺，識破端倪便可知。',64,'全唐诗/poet.song.242000.json','["乾坤主宰妙難窺，識破端倪便可知。", "陽動於陰分太極，剝窮必復露真機。", "化工自有經綸處，生意元無間斷時。", "萬象皆春從此始，細參羲畫究精微。"]'),
('e8e82497-652f-45a9-b1c8-ab575f5f7a4c','白雁','黄庚','宋','宋诗','song-poetry','','[]','征鴻素縞過南樓，衣褐同羣孰與儔。',64,'全唐诗/poet.song.242000.json','["征鴻素縞過南樓，衣褐同羣孰與儔。", "雲外排行分玉李，天邊印字带銀鈎。", "高飛遠寒疑雲鶴，低落平沙類雪鷗。", "夜月蘆花無認處，惟聞嘹唳數聲秋。"]'),
('407dfe79-2b90-4fc4-a8ea-d72d7787dd93','即席和衛山齋韻并呈顧淵白路教','黄庚','宋','宋诗','song-poetry','','[]','燭夜飛觴客在山，同看明月上雲端。',64,'全唐诗/poet.song.242000.json','["燭夜飛觴客在山，同看明月上雲端。", "粘天水闊蟾光濕，捲海風高蜃氣寒。", "會友幸逢三益在，娛情休恨四并難。", "座中喜有能詩者，便作唐詩顧况看。"]'),
('e46722c0-65f2-4863-901f-f85a852aaca3','梅魂','黄庚','宋','宋诗','song-poetry','','[]','夢覺羅浮迹已陳，至今想像事如新。',64,'全唐诗/poet.song.242000.json','["夢覺羅浮迹已陳，至今想像事如新。", "相思一樣窗前月，似見三生石上春。", "的的孤芳冰氣魄，疏疏冷蕊雪精神。", "料應楚些難招至，欲倩花光爲寫真。"]'),
('36b1dde1-7bed-4d3a-b3f7-501144803cd4','書懷','黄庚','宋','宋诗','song-poetry','','[]','湖海難□鬢易絲，平生壯志與心違。',64,'全唐诗/poet.song.242000.json','["湖海難□鬢易絲，平生壯志與心違。", "一千里外家何在，三十年前事已非。", "狐正首丘應待盡，鶴思華表尚忘歸。", "書齋兀坐懷今昔，淚落西風濕客衣。"]'),
('f64682f0-d26a-41b8-af62-7185f9a84960','甲子歲旦','黄庚','宋','宋诗','song-poetry','','[]','天開正旦宿雲收，宇宙陽回和氣浮。',64,'全唐诗/poet.song.242000.json','["天開正旦宿雲收，宇宙陽回和氣浮。", "歲換上元新甲子，時同太古舊春秋。", "朱顔不逐年華改，清思惟從造化游。", "柏酒滿斟吟興動，題詩記節自賡酬。"]'),
('01f3f8ba-b7dd-42cf-80a5-09e884b5144f','白酒歌爲巖翁賦','黄庚','宋','宋诗','song-poetry','','[]','火雲燒空日色烈，暑氣著人方鬰結。',304,'全唐诗/poet.song.242000.json','["火雲燒空日色烈，暑氣著人方鬰結。", "巖翁宴客水亭東，竹色蕖香獻清絕。", "瓜削水晶蓮剖珠，象箸犀盤盛陳列。", "銀罌捧出白玉醅，透鼻香濃風味別。", "傳來未到心已寒，灧灧瓊光瑩而潔。", "初疑炎帝行冬令，壺結冰澌洗袢熱。", "又疑仙掌流沆瀣，破□傾來和玉屑。", "誰向藍田拾瑶英，釀成奇液色澄澈。", "恐是太華井中溢，修綆銅缾汲不竭。", "又恐夜半雷破山，石髓分流乳泉裂。", "既非西貉綿羊酥，又非緱山仙鶴血。", "胡爲照眼光陸離，藥玉盤中色難別。", "令人敢嚥不敢潄，怕有飛霜寒齒頰。", "一杯一杯復一杯，肺腑盡化爲冰雪。", "憶昔曾誦坡仙詩，白酒無聲瀉油滑。", "開編自覺饞涎流，詎謂今朝得親啜。", "主人醖藉如此酒，氣味清醇韵芳冽。", "餔糟諸子醉六經，抱負長才特施設。", "君王作醴思用賢，應向商巖求麯糵。"]'),
('9974d9db-086c-470a-a3fb-e9c88793c855','侍郎亭','黄庚','宋','宋诗','song-poetry','','[]','東鄰花圃栽雙松，一朝煨燼枝葉空。',176,'全唐诗/poet.song.242000.json','["東鄰花圃栽雙松，一朝煨燼枝葉空。", "侍郎庭前有雙松，至今古色摩蒼穹。", "此木受命本千載，扶持若有神始終。", "天留真質表文獻，柯葉蕃茂根本豐。", "百年培植飽雨露，虬枝風撼鳴笙鏞。", "掀髯相視雪貿貿，擁蓋對立雲童童。", "不知天地有黄落，玄冥失柄春無功。", "雲孫峨冠立亭下，典刑如侍乾淳翁。", "昂藏自是廊廟具，夭矯亦有山林風。", "稜稜鐵面不可犯，麾去秦爵如飛蓬。", "諸孫奉酒立松下，森森頭角皆虬龍。"]'),
('eaad11fe-0e84-45e9-8d92-a4b3d68f3fc2','題東山玩月圖','黄庚','宋','宋诗','song-poetry','','[]','斜陽紅盡暮雲碧，一片天光涵水色。',384,'全唐诗/poet.song.242000.json','["斜陽紅盡暮雲碧，一片天光涵水色。", "海濤擁出爛銀盤，千里嬋娟共今夕。", "主人領客登東山，踏碎寒光看秋液。", "星河倒影浸空明，露華漙玉夜氣清。", "馮夷激水水欲立，海若辟易天吳驚。", "孤舟捲帆泊烟嶼，古木撼壑生秋聲。", "憑高人在金鰲背，閒看潮生烟渚外。", "老龍翻海雲氣寒，長鯨捲雪浪花碎。", "茫茫萬頃滄浪中，屹立孤峰鎖蒼翠。", "山巔掃石羅樽罍，賓主傳杯不放杯。", "騷客掀髯賦詩去，山童踏月携琴來。", "劇談浩飲不知醉，仰天大笑歡顔開。", "倒著接䍦欲起舞，乾坤清氣入肺腑。", "天邊風月空四時，眼底江山自千古。", "謝安躡屐遊東山，袁宏登舟宴牛渚。", "庾亮南樓今在不，坡仙赤壁知何許。", "滿眼往事轉頭空，千年人物俱塵土。", "人生光景若湍流，霜痕易點雙鬢秋。", "胸中勿著塵俗事，眉間休鎖名利愁。", "我輩適意在行樂，古人所以秉燭遊。", "月山追憶舊遊地，盡寫風烟入縑素。", "我來見畫如見景，想像高唐猶可賦。", "諸君後會應可期，雲萍合散今何之。", "安得扁舟澉川去，日與杖履相追隨。"]'),
('6192c0cb-081d-4d0f-a8f1-5f5f931d2999','醉時歌','黄庚','宋','宋诗','song-poetry','','[]','茫茫古堪輿，何日分九州。',174,'全唐诗/poet.song.242000.json','["茫茫古堪輿，何日分九州。", "封域如許大，僅能著我胸中愁。", "澆愁須是如澠酒，麯波釀盡銀河流。", "貯以倒海千頃黄金罍，酌以傾江萬斛玻璃舟。", "天爲青羅幕，月爲白玉鈎。", "月邊天孫織雲錦，製成五色蒙茸裘。", "披裘把酒踏月窟，長揖北斗相勸酬。", "一飲一千石，一醉三千秋。", "高卧五城十二樓，剛風冽冽吹酒醒，起來披髮騎赤虬。", "大呼洪崖拍浮丘，飛上崑崙山頂頭。", "下視塵寰一培塿，揮斥八極逍遥遊。"]'),
('58d70f8c-d9ad-47e1-afd4-688a6db59e6f','書懷','黄庚','宋','宋诗','song-poetry','','[]','萬卷詩書千古事，一燈窗火十年心。',32,'全唐诗/poet.song.242000.json','["萬卷詩書千古事，一燈窗火十年心。", "功名夢斷身無用，閑補離騷學楚吟。"]'),
('fb8e54e0-d07e-484f-ad3e-d596a704de36','偶成','黄庚','宋','宋诗','song-poetry','','[]','淵明覺是新愁少，伯玉知非舊恨多。',32,'全唐诗/poet.song.242000.json','["淵明覺是新愁少，伯玉知非舊恨多。", "畢竟是非皆一夢，百年夢醒事如何。"]'),
('70a6a5b0-1e2d-4f4a-b9c6-19abbd5a8e6c','暮春','黄庚','宋','宋诗','song-poetry','','[]','芳事闌珊三月時，春愁惟有落花知。',32,'全唐诗/poet.song.242000.json','["芳事闌珊三月時，春愁惟有落花知。", "柳綿飄白東風老，一樹斜陽叫子規。"]'),
('43850dea-7a82-4bd4-8df1-a68c44efabdb','書燈','黄庚','宋','宋诗','song-poetry','','[]','書幌低垂風不來，蘭膏花暖夜深開。',32,'全唐诗/poet.song.242000.json','["書幌低垂風不來，蘭膏花暖夜深開。", "剔殘猶有餘光在，一點丹心未肯灰。"]'),
('21a8ea7e-0c4f-477f-bcbc-77d3198ef782','海棠','黄庚','宋','宋诗','song-poetry','','[]','臉暈輕紅酒力微，真妃半醉夜深時。',32,'全唐诗/poet.song.242000.json','["臉暈輕紅酒力微，真妃半醉夜深時。", "杜鵑叫落花梢月，獨倚東風睡不知。"]'),
('a504c562-addb-4f1d-88cf-6308a07d22ba','春陰','黄庚','宋','宋诗','song-poetry','','[]','點滴簷聲濕徑雲，翻階紅葉带啼痕。',32,'全唐诗/poet.song.242000.json','["點滴簷聲濕徑雲，翻階紅葉带啼痕。", "可憐花片都零落，雨露雖多不是恩。"]'),
('2fa76b05-8ae8-44b8-8e90-b4140b49ffd7','芭蕉','黄庚','宋','宋诗','song-poetry','','[]','翠葉離披傍竹林，幾年雨露受恩深。',32,'全唐诗/poet.song.242000.json','["翠葉離披傍竹林，幾年雨露受恩深。", "綠章封事今無用，空對西風抱赤心。"]'),
('5fd4c19e-c113-4b99-be90-de4beb1b8b13','黄芙蓉','黄庚','宋','宋诗','song-poetry','','[]','媚色津津散朵芳，道人裝束勝紅粧。',32,'全唐诗/poet.song.242000.json','["媚色津津散朵芳，道人裝束勝紅粧。", "詩人若作桃花看，便覺西風不甚凉。"]'),
('0e2a08b3-1bb8-4dd5-9347-55e0f7136fdb','聞角','黄庚','宋','宋诗','song-poetry','','[]','誰送寒聲入夢中，遥知人在戍樓東。',32,'全唐诗/poet.song.242000.json','["誰送寒聲入夢中，遥知人在戍樓東。", "明朝梅嶺花飛雪，未必都因昨夜風。"]'),
('ccaf6eb6-e6ee-4e2d-b83f-5713a2c881ec','花柳','黄庚','宋','宋诗','song-poetry','','[]','花半睡時分蝶夢，柳三眠處足鶑聲。',32,'全唐诗/poet.song.242000.json','["花半睡時分蝶夢，柳三眠處足鶑聲。", "誰知花柳無情物，添個蝶鶑便有情。"]'),
('828c7582-d941-44d9-9e1e-c3fff7a11ac9','酒家','黄庚','宋','宋诗','song-poetry','','[]','風颭青帘出杏林，行人未醉甕頭春。',32,'全唐诗/poet.song.242000.json','["風颭青帘出杏林，行人未醉甕頭春。", "安知滌器茅簷者，不是相如行輩人。"]'),
('b4c34c4a-b5da-4616-8f28-2247d85e2839','贈醫者花道人','黄庚','宋','宋诗','song-poetry','','[]','藜杖橫肩過竹扉，半挑藥籠半挑詩。',32,'全唐诗/poet.song.242000.json','["藜杖橫肩過竹扉，半挑藥籠半挑詩。", "笑予盤礴山雲裏，泉石膏肓作麽醫。"]'),
('70ebbaf2-4588-4dfa-b74e-860142f69132','晚春','黄庚','宋','宋诗','song-poetry','','[]','老來無復事狂遊，倚杖看花動客愁。',32,'全唐诗/poet.song.242000.json','["老來無復事狂遊，倚杖看花動客愁。", "病骨却寒春不管，柳棉風裏木棉裘。"]'),
('58acb798-345e-4007-9ad7-419d3c337951','漫述  其一','黄庚','宋','宋诗','song-poetry','','[]','百拙嬾營生計事，一貧方識丈夫心。',32,'全唐诗/poet.song.242000.json','["百拙嬾營生計事，一貧方識丈夫心。", "簞瓢陋巷皆真樂，何用多藏郿塢金。"]'),
('6cf96928-5449-4be0-a89f-4dc6615f9b71','漫述  其二','黄庚','宋','宋诗','song-poetry','','[]','青春易過不多日，白晝得閒能幾人。',32,'全唐诗/poet.song.242000.json','["青春易過不多日，白晝得閒能幾人。", "有限光陰空役役，堆錢難買百年身。"]'),
('e081a29d-f235-4aa5-810e-b191d84988ba','漫述  其三','黄庚','宋','宋诗','song-poetry','','[]','對客莫談當世事，閉門且讀舊時書。',32,'全唐诗/poet.song.242000.json','["對客莫談當世事，閉門且讀舊時書。", "蓬萊獻賦心猶在，只恐無人薦子虛。"]'),
('a547f1bf-1051-4c3b-ba8b-1ab96a35084c','漫述  其四','黄庚','宋','宋诗','song-poetry','','[]','楚江何忍沉清客，周粟安能活餓夫。',32,'全唐诗/poet.song.242000.json','["楚江何忍沉清客，周粟安能活餓夫。", "慨想前修千古事，孤忠高義後來無。"]'),
('38cd0b0a-705e-4ca1-b39c-dde359d4e7a9','漫述  其五','黄庚','宋','宋诗','song-poetry','','[]','逢人休要說公卿，老去無心慕寵榮。',32,'全唐诗/poet.song.242000.json','["逢人休要說公卿，老去無心慕寵榮。", "李不封侯劉不第，千年青史亦傳名。"]'),
('a8ec465d-2eac-4b2a-af7d-9c8efcee286b','漫述  其六','黄庚','宋','宋诗','song-poetry','','[]','世事艱難如意少，功名榮耀誤人多。',32,'全唐诗/poet.song.242000.json','["世事艱難如意少，功名榮耀誤人多。", "浮雲富貴非吾願，且買扁舟理釣蓑。"]'),
('bf3c65eb-4ca1-43e3-a43a-ba7ca6e67d0c','漫述  其七','黄庚','宋','宋诗','song-poetry','','[]','脫巾漉酒心先醉，著屐登山脚便輕。',32,'全唐诗/poet.song.242000.json','["脫巾漉酒心先醉，著屐登山脚便輕。", "豪飲清遊憶陶謝，古人千載尚留名。"]'),
('b8efbadb-ef29-4fe0-b552-832c6eeda782','漫述  其八','黄庚','宋','宋诗','song-poetry','','[]','眼前萬事等一夢，世上幾人能百年。',32,'全唐诗/poet.song.242000.json','["眼前萬事等一夢，世上幾人能百年。", "千古英雄今已矣，北邙荒塚草芊芊。"]'),
('ad92e6bd-987f-473a-bfd6-e1bff799ef12','漫述  其九','黄庚','宋','宋诗','song-poetry','','[]','文盟無主江湖冷，詩社欠人風月閑。',32,'全唐诗/poet.song.242000.json','["文盟無主江湖冷，詩社欠人風月閑。", "老去盍爲歸隠計，却於何處買青山。"]'),
('47cda4b0-48e6-4de5-ad49-3552c06010ad','漫述  其一○','黄庚','宋','宋诗','song-poetry','','[]','烘柳日高花院暖，炷沉烟冷竹窗虛。',32,'全唐诗/poet.song.242000.json','["烘柳日高花院暖，炷沉烟冷竹窗虛。", "開編怕見傷懷事，不讀離騷讀四書。"]'),
('e02c3172-48e3-4556-a470-921ec0628e16','一春  其一','黄庚','宋','宋诗','song-poetry','','[]','新綠園林雨過時，黄鸝無語恨春歸。',32,'全唐诗/poet.song.242000.json','["新綠園林雨過時，黄鸝無語恨春歸。", "楊花怕逐東風去，搭住闌干不肯飛。"]'),
('82e74898-01f2-44ef-9861-3b3f97c9f88e','一春  其二','黄庚','宋','宋诗','song-poetry','','[]','花心醉日蝶先覺，柳眼窺春鶑未知。',32,'全唐诗/poet.song.242000.json','["花心醉日蝶先覺，柳眼窺春鶑未知。", "景物繁華易凋謝，一春消得幾番詩。"]'),
('67e04478-817e-44c5-850f-e1a40d090c1d','江上','黄庚','宋','宋诗','song-poetry','','[]','江上支筇眼界寬，夕陽影裏水雲寒。',32,'全唐诗/poet.song.242000.json','["江上支筇眼界寬，夕陽影裏水雲寒。", "憑誰說與閑鷗鷺，借我漁磯把釣竿。"]'),
('d9365abb-1c77-4783-b1bd-98bccee7b886','送筆與各庵和尚','黄庚','宋','宋诗','song-poetry','','[]','恨殺毛錐久不靈，特分二輩到禪扃。',32,'全唐诗/poet.song.242000.json','["恨殺毛錐久不靈，特分二輩到禪扃。", "難書八萬四千偈，只寫波羅一卷經。"]'),
('55ecab08-6ca0-48d6-94db-48fdcebdf4ae','梅菊','黄庚','宋','宋诗','song-poetry','','[]','菊清獨占風霜骨，梅白偏宜雪月天。',32,'全唐诗/poet.song.242000.json','["菊清獨占風霜骨，梅白偏宜雪月天。", "晉宋後來愛花者，豈無靖節與逋仙。"]'),
('421921e6-7120-49be-9257-19e956bf382e','江景','黄庚','宋','宋诗','song-poetry','','[]','寒生雁背天將雪，冷入魚腮水欲冰。',32,'全唐诗/poet.song.242000.json','["寒生雁背天將雪，冷入魚腮水欲冰。", "釣艇歸來江路暝，舟人分火點漁燈。"]'),
('a5cccae4-7ca1-4e6c-8e88-ed5b061ed412','聽雨','黄庚','宋','宋诗','song-poetry','','[]','老來已覺此身閑，近日唐詩亦懶看。',32,'全唐诗/poet.song.242000.json','["老來已覺此身閑，近日唐詩亦懶看。", "半榻白雲眠聽雨，一窗簾影隔春寒。"]'),
('cb8570d3-dc14-4890-a1fb-177645766599','暮春  其一','黄庚','宋','宋诗','song-poetry','','[]','東風庭院夕陽天，恨綠愁紅又一年。',32,'全唐诗/poet.song.242000.json','["東風庭院夕陽天，恨綠愁紅又一年。", "春自要歸花自落，莫將芳事怨啼鵑。"]'),
('1b9c4bf9-4180-42d1-8043-286ac5a6ca7e','暮春  其二','黄庚','宋','宋诗','song-poetry','','[]','柳老黄鸝遷別樹，花殘粉蝶繞空林。',32,'全唐诗/poet.song.242000.json','["柳老黄鸝遷別樹，花殘粉蝶繞空林。", "道人不管春光去，看了紅芳有綠陰。"]'),
('1c39aa48-401c-4477-8658-52efe4a17aa2','暮春  其三','黄庚','宋','宋诗','song-poetry','','[]','一鳥不啼春寂寂，百花都落雨濛濛。',32,'全唐诗/poet.song.242000.json','["一鳥不啼春寂寂，百花都落雨濛濛。", "十分花鳥東風恨，半在詩中半酒中。"]'),
('8c9a1429-3bb7-4379-8651-f7d2eda15f85','題漂母飯信圖  其一','黄庚','宋','宋诗','song-poetry','','[]','國士無雙未肯臣，漢皇眼力欠精神。',32,'全唐诗/poet.song.242000.json','["國士無雙未肯臣，漢皇眼力欠精神。", "築壇直待追亡後，不及溪邊一婦人。"]'),
('5daf9d14-ed9f-43b0-bc28-f74f7d91ec01','題漂母飯信圖  其二','黄庚','宋','宋诗','song-poetry','','[]','一飯豈能忘漂母，英雄未遇有誰知。',32,'全唐诗/poet.song.242000.json','["一飯豈能忘漂母，英雄未遇有誰知。", "可憐屏底丹青筆，不畫登壇拜將時。"]'),
('a9272038-49bc-4d30-aa1b-84cf528cbdc3','詩窮','黄庚','宋','宋诗','song-poetry','','[]','風愁月恨屬詩翁，終日推敲句未工。',32,'全唐诗/poet.song.242000.json','["風愁月恨屬詩翁，終日推敲句未工。", "何苦辛勤學郊島，嘔心博得一生窮。"]'),
('9849933c-ca6a-4f66-92ae-b7d6a4c670c6','雷潭爲定講師賦','黄庚','宋','宋诗','song-poetry','','[]','縛草爲庵枕碧漪，蒲團長是坐禪時。',32,'全唐诗/poet.song.242000.json','["縛草爲庵枕碧漪，蒲團長是坐禪時。", "一聲霹靂驚龍起，布衲蒙頭總不知。"]'),
('a491c092-0799-4502-b2f3-3dcee769899c','雪居爲安上人賦','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲壓西湖水欲冰，雪封樓閣玉稜層。',32,'全唐诗/poet.song.242000.json','["雲壓西湖水欲冰，雪封樓閣玉稜層。", "夜來門外深三尺，應有齊腰獨立僧。"]'),
