('b445ecfe-50d3-4d01-8f02-c1feaa416c8b','子胥廟','黄庚','宋','宋诗','song-poetry','','[]','伍相祠前雲氣昏，奔吳心事與誰論。',32,'全唐诗/poet.song.242000.json','["伍相祠前雲氣昏，奔吳心事與誰論。", "怒濤夜半翻江月，疑是忠臣一片魂。"]'),
('f275f35b-f8b9-424e-aa95-1fc6becf69e2','西湖行春','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫船無復沸笙歌，湖水年年自碧波。',32,'全唐诗/poet.song.242000.json','["畫船無復沸笙歌，湖水年年自碧波。", "回首蘇公堤上柳，綠陰不似舊時多。"]'),
('98417be9-cd54-4166-8320-fd7125a93fa0','明妃  其一','黄庚','宋','宋诗','song-poetry','','[]','和戎何惜遣蛾眉，悔恨徒然殺畫師。',32,'全唐诗/poet.song.242000.json','["和戎何惜遣蛾眉，悔恨徒然殺畫師。", "漢主深恩如可報，安身死虜亦無辭。"]'),
('081e1637-4c83-4ff3-942c-bfcfad234629','明妃  其二','黄庚','宋','宋诗','song-poetry','','[]','一函香骨埋沙漠，魂魄多應繞漢庭。',32,'全唐诗/poet.song.242000.json','["一函香骨埋沙漠，魂魄多應繞漢庭。", "惟有春風知此恨，年年吹拂草痕青。"]'),
('87cf8120-752b-4cc9-8b4b-68eecd1350ca','煬帝行宮','黄庚','宋','宋诗','song-poetry','','[]','彩鳳樓前汴水流，君王不復錦帆遊。',32,'全唐诗/poet.song.242000.json','["彩鳳樓前汴水流，君王不復錦帆遊。", "長堤舊日青青柳，曾带春風拂御舟。"]'),
('c360e62a-b994-4e09-bfbf-3007b647a150','明皇按樂圖','黄庚','宋','宋诗','song-poetry','','[]','一曲霓裳舞太真，誰知鼙鼓動胡塵。',32,'全唐诗/poet.song.242000.json','["一曲霓裳舞太真，誰知鼙鼓動胡塵。", "當時若按周姬樂，治世音中無亂人。"]'),
('f8f48a70-7322-48c0-840d-d209b6ba8d57','采蓮女','黄庚','宋','宋诗','song-poetry','','[]','越女蘭舟泛綠漪，采蓮花露濕紅衣。',32,'全唐诗/poet.song.242000.json','["越女蘭舟泛綠漪，采蓮花露濕紅衣。", "萬荷影裏歌聲過，驚起鴛鴦貼水飛。"]'),
('4736a9d4-3cb7-41e4-9dfd-d9cb84d7b938','通玄觀','黄庚','宋','宋诗','song-poetry','','[]','雲氣深深護石壇，紅塵飛不到闌干。',32,'全唐诗/poet.song.242000.json','["雲氣深深護石壇，紅塵飛不到闌干。", "清陰滿地無人迹，一徑松風鶴夢寒。"]'),
('75236b70-d455-470e-8825-e897906c86f0','林高士隠居','黄庚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家住西湖深更深，古松隠裏禮茅君。',32,'全唐诗/poet.song.242000.json','["家住西湖深更深，古松隠裏禮茅君。", "白猿攀樹藤花落，點破巖前一地雲。"]'),
