('69d2a62b-bd29-4376-8e87-9fcf088dde48','閨情效香奩體  其三','黄庚','宋','宋诗','song-poetry','','[]','黛眉愁裏斂雙蛾，別久無書事奈何。',32,'全唐诗/poet.song.242000.json','["黛眉愁裏斂雙蛾，別久無書事奈何。", "欲待怨他還又憶，怨時較少憶時多。"]'),
('31ec7561-cef7-4df7-bc44-8c293e2fcc7c','閨情效香奩體  其四','黄庚','宋','宋诗','song-poetry','','[]','懶向粧臺對鏡鸞，羅衣怯薄正春寒。',32,'全唐诗/poet.song.242000.json','["懶向粧臺對鏡鸞，羅衣怯薄正春寒。", "黄金絡索珊瑚墜，獨立春風看牡丹。"]'),
('22266ada-5d8e-4065-89d9-12740e19d56c','江村即事','黄庚','宋','宋诗','song-poetry','','[]','江村暝色漸凄迷，數點殘鴉雜雁飛。',32,'全唐诗/poet.song.242000.json','["江村暝色漸凄迷，數點殘鴉雜雁飛。", "雁宿蘆花鴉宿樹，各分一半夕陽歸。"]'),
('d4f87e3f-6408-418f-8865-d85d56d0a525','春日','黄庚','宋','宋诗','song-poetry','','[]','紫燕評春語畫梁，黄鸝攙曉囀垂楊。',32,'全唐诗/poet.song.242000.json','["紫燕評春語畫梁，黄鸝攙曉囀垂楊。", "博山烟冷書窗靜，風颭瓶花點硯香。"]'),
('fd2728ec-721b-4d93-8324-7f1c3b7b993c','舟次九山','黄庚','宋','宋诗','song-poetry','','[]','水雲盡處列奇峰，螺髻參差杳靄中。',32,'全唐诗/poet.song.242000.json','["水雲盡處列奇峰，螺髻參差杳靄中。", "江岸維舟看不了，烟嵐分碧入疏蓬。"]'),
('e31442b4-c574-452e-afc5-6450f915a669','讀秦紀','黄庚','宋','宋诗','song-poetry','','[]','并吞六國獨稱雄，經籍灰飛烈焰中。',32,'全唐诗/poet.song.242000.json','["并吞六國獨稱雄，經籍灰飛烈焰中。", "書外有書焚不盡，一篇圯上漢成功。"]'),
('6e81623f-b002-49cf-92d1-a2a246e27a7e','修竹館舍','黄庚','宋','宋诗','song-poetry','','[]','乳燕銜泥春晝長，枕書無夢到高唐。',32,'全唐诗/poet.song.242000.json','["乳燕銜泥春晝長，枕書無夢到高唐。", "桃花紅雨梨花雪，相逐東風過粉牆。"]'),
('75d6d5a1-0d58-46f3-a2c3-075cc935f9f5','夏日陪王君玉汎舟鑑湖','黄庚','宋','宋诗','song-poetry','','[]','波光萬頃接天光，畫舫歸來載夕陽。',32,'全唐诗/poet.song.242000.json','["波光萬頃接天光，畫舫歸來載夕陽。", "一棹湖心天不暑，萬荷風裏滿身香。"]'),
('2d920b01-ed16-4064-ae4c-aa51cf2a02c6','秋夜登西樓','黄庚','宋','宋诗','song-poetry','','[]','清碧金英玉露漙，姮娥深夜不禁寒。',32,'全唐诗/poet.song.242000.json','["清碧金英玉露漙，姮娥深夜不禁寒。", "桂花香裏人敲句，倚遍高樓十二闌。"]'),
('ed378f62-8acb-4305-a622-14f5df6d06c5','雜詠  其一','黄庚','宋','宋诗','song-poetry','','[]','柳嫌暮雨鶑聲澀，花怯東風蝶夢寒。',32,'全唐诗/poet.song.242000.json','["柳嫌暮雨鶑聲澀，花怯東風蝶夢寒。", "偶憶故園春色好，他鄉花柳带愁看。"]'),
('88971820-6f83-4279-a8bf-744367bda672','雜詠  其二','黄庚','宋','宋诗','song-poetry','','[]','人非陶令空看菊，詩不林逋漫詠梅。',32,'全唐诗/poet.song.242000.json','["人非陶令空看菊，詩不林逋漫詠梅。", "晉宋後來愛花者，輸他高節與高才。"]'),
('55bc9855-2d5d-49e1-999b-a9f6db2495d8','雜詠  其三','黄庚','宋','宋诗','song-poetry','','[]','天外斜陽猶在樹，林間宿鳥已歸巢。',32,'全唐诗/poet.song.242000.json','["天外斜陽猶在樹，林間宿鳥已歸巢。", "黄昏莫把柴門掩，恐有詩人带月敲。"]'),
('8fe31cce-b1b7-4c00-a854-e7bafc352df7','雜詠  其四','黄庚','宋','宋诗','song-poetry','','[]','穉柳已回春暖意，殘梅猶結歲寒心。',32,'全唐诗/poet.song.242000.json','["穉柳已回春暖意，殘梅猶結歲寒心。", "百年身世詩中老，好景難消幾度吟。"]'),
('0508b3e2-abd0-4fa8-a8ac-181765735cb2','雜詠  其五','黄庚','宋','宋诗','song-poetry','','[]','新綠園林微雨後，落紅庭院夕陽時。',32,'全唐诗/poet.song.242000.json','["新綠園林微雨後，落紅庭院夕陽時。", "一聲杜宇催春去，貪睡棠妃未必知。"]'),
('01597782-3197-4659-8d33-87d08ee565db','雜詠  其六','黄庚','宋','宋诗','song-poetry','','[]','持螯已飽團臍蟹，砟膾猶思巨口鱸。',32,'全唐诗/poet.song.242000.json','["持螯已飽團臍蟹，砟膾猶思巨口鱸。", "風物秋來多感慨，天寒酒醒客心孤。"]'),
('90e1d0aa-43d5-49c4-aaaa-2dfb5cd21756','雜詠  其七','黄庚','宋','宋诗','song-poetry','','[]','囊底詩成無賣處，牀頭金盡已多時。',32,'全唐诗/poet.song.242000.json','["囊底詩成無賣處，牀頭金盡已多時。", "元龍豪氣依然在，慣守清貧豈足悲。"]'),
('2b1155c4-46a0-43c6-a45a-42f3b11ecfc5','雜詠  其八','黄庚','宋','宋诗','song-poetry','','[]','人無氣節何足道，腹有詩書自不同。',32,'全唐诗/poet.song.242000.json','["人無氣節何足道，腹有詩書自不同。", "實學真才誰具眼，江湖難遇杜司空。"]'),
('7ebac1c4-38ff-49d6-b63e-458b95b9fee6','雜詠  其九','黄庚','宋','宋诗','song-poetry','','[]','地多種竹堪容鶴，池不栽蓮恐礙魚。',32,'全唐诗/poet.song.242000.json','["地多種竹堪容鶴，池不栽蓮恐礙魚。", "小徑荒苔人不到，閉門閒學換鵝書。"]'),
('d8ce8328-c2f0-41c4-8fd5-e4531d6242c7','竹林夏日','黄庚','宋','宋诗','song-poetry','','[]','不受炎光玉萬竿，仙林便作晉林看。',32,'全唐诗/poet.song.242000.json','["不受炎光玉萬竿，仙林便作晉林看。", "此君長带冰霜氣，醉卧綠陰詩夢寒。"]'),
('b6d2612c-421f-4882-915e-2af679cf98c6','滴翠松','黄庚','宋','宋诗','song-poetry','','[]','老翠蟠空一樣高，月分寒影落庭臯。',32,'全唐诗/poet.song.242000.json','["老翠蟠空一樣高，月分寒影落庭臯。", "哦詩猛把闌干拍，宿鶴驚飛露濕袍。"]'),
('797e1ad7-8aac-41f4-b433-b012f76cd686','夜窗','黄庚','宋','宋诗','song-poetry','','[]','香篆烟銷夜已闌，硯池冰結漏聲寒。',32,'全唐诗/poet.song.242000.json','["香篆烟銷夜已闌，硯池冰結漏聲寒。", "梅花懸影書窗上，應待詩人带月看。"]'),
('97bd2957-4985-4ab3-becf-d966fdb7c844','寄郭印齋','黄庚','宋','宋诗','song-poetry','','[]','相思何日得相逢，料想君心與我同。',32,'全唐诗/poet.song.242000.json','["相思何日得相逢，料想君心與我同。", "莫怪近來書寄少，雁飛不肯下秋空。"]'),
('e47434b7-98ac-4b04-a23b-cdc2c3bc4737','句  其一','黄庚','宋','宋诗','song-poetry','','[]','江蘺滿意馨。',6,'全唐诗/poet.song.242000.json','["江蘺滿意馨。"]'),
('1a03fc05-ed47-4d32-a596-c2516d969b04','句  其二','黄庚','宋','宋诗','song-poetry','','[]','颯颯片帆輕。',6,'全唐诗/poet.song.242000.json','["颯颯片帆輕。"]'),
('97b960bc-133f-41dd-9377-903f67b2286c','曉起','林景怡','宋','宋诗','song-poetry','','[]','天雞弄喔咿，殘星在斜漢。',60,'全唐诗/poet.song.242000.json','["天雞弄喔咿，殘星在斜漢。", "整衣出幽扉，山城漏初斷。", "微微水風生，冉冉田露散。", "此時遊葛天，淡然空百羨。", "海色上寒梢，漸識梅花面。"]'),
('4215f6eb-693c-4a6c-a07a-3bc95be54822','廢觀','林景英','宋','宋诗','song-poetry','','[]','羽衣人已化，無處問殊庭。',48,'全唐诗/poet.song.242000.json','["羽衣人已化，無處問殊庭。", "春色桃誰種，天香藥自靈。", "片霞飛絕頂，一鶴下青冥。", "荒蘚空階下，猶聞夜祭星。"]'),
('080c01ba-9de7-4f67-9f33-5b4ff589eba3','寄陳莘村','林景英','宋','宋诗','song-poetry','','[]','玄冬梅半白，光接太丘星。',48,'全唐诗/poet.song.242000.json','["玄冬梅半白，光接太丘星。", "雪月往來夢，溪山長短亭。", "利名成露草，行止付風萍。", "三十年來友，無如老典型。"]'),
('6cd4efe8-82a1-4c5f-aa74-07210b983527','秋風','林景英','宋','宋诗','song-poetry','','[]','颯然何處起，水國不成眠。',48,'全唐诗/poet.song.242000.json','["颯然何處起，水國不成眠。", "觸樹人疑雨，開門月在天。", "漁舟移絕浦，雁陣落荒田。", "曉起傷漂蕩，蘆花走屋前。"]'),
('a9b54aa4-47d3-47e1-bcab-8c5c17a312a2','言歸','林景英','宋','宋诗','song-poetry','','[]','言歸江海上，甘向石田耕。',48,'全唐诗/poet.song.242000.json','["言歸江海上，甘向石田耕。", "不愧爲斯世，能閒過此生。", "地從鄰竹占，樹聽野禽爭。", "坐咏風濤外，南山盡日行。"]'),
('b14202c2-d682-48a9-a4be-93ec2795022b','林氏庵呈周鍊師','林景英','宋','宋诗','song-poetry','','[]','遥跨青田鶴，翩翩到此來。',48,'全唐诗/poet.song.242000.json','["遥跨青田鶴，翩翩到此來。", "庭生自家草，山有主人梅。", "掃石夜朝斗，雨田秋起雷。", "誰知塵影裏，清趣似蓬萊。"]'),
('46460c2e-ad50-4c40-87a4-dee1ee3b379b','送友之石龍','林景英','宋','宋诗','song-poetry','','[]','一杯渭酒勸詩豪，楊柳西風拂去袍。',64,'全唐诗/poet.song.242000.json','["一杯渭酒勸詩豪，楊柳西風拂去袍。", "行路正當金虎壯，登雲不憚石龍高。", "水懸巖白驚殘雪，日漾溪紅認落桃。", "記取奚囊新句得，月三四幅寄東臯。"]'),
('2f4b3438-8e12-49e6-a5aa-ee1ac09e752a','日出入行','林景英','宋','宋诗','song-poetry','','[]','朝出扶桑來，莫入虞淵去。',24,'全唐诗/poet.song.242000.json','["朝出扶桑來，莫入虞淵去。", "胡不緩馳驅，百歲一朝暮。"]'),
('a82f213c-79ad-469f-bc0a-deb37dc7ad6c','句','趙與侲','宋','宋诗','song-poetry','','[]','溪月涵虛影，山雲護斷香。',12,'全唐诗/poet.song.242000.json','["溪月涵虛影，山雲護斷香。"]'),
('47ffc8fc-7cff-4d41-a488-c284ecb3a73d','句','朱煥文','宋','宋诗','song-poetry','','[]','江山千里俱頭白，骨肉十年終眼青。',16,'全唐诗/poet.song.242000.json','["江山千里俱頭白，骨肉十年終眼青。"]'),
('2785a6e7-c8f3-4c59-a434-6c715fef06c2','澹山巖','趙德綸','宋','宋诗','song-poetry','','[]','巖扃二里鎖煙霏，天下名山此本稀。',64,'全唐诗/poet.song.242000.json','["巖扃二里鎖煙霏，天下名山此本稀。", "硬石穿空誰運斧，寒泉滴雪欲添衣。", "仙遊塵外杜蘿老，僧住山間筍蕨肥。", "自歎微官猶縛我，倘容卜築定忘歸。"]');
